            return
        self.depth -= 1
        if tag.lower() == "h1" or self.depth == 0:
            self.in_h1 = False
            self.done = True

    def handle_data(self, data):
        if self.in_h1 and not self.done:
            self.text_parts.append(data)

    def get_text(self):
        return "".join(self.text_parts).strip()


