Here's a small HTTP server in Go using the standard library:

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
)

func helloHandler(w http.ResponseWriter, r *http.Request) {
	name := r.URL.Query().Get("name")
	if name == "" {
		name = "world"
	}

	response := map[string]string{
		"greeting": "Hello, " + name + "!",
	}

	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(response); err != nil {
		http.Error(w, "failed to encode response", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/hello", helloHandler)

	addr := ":8080"
	log.Printf("Server listening on %s", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatal(err)
	}
}
```

Run with `go run main.go`, then try:
- `curl "http://localhost:8080/hello?name=Alice"` → `{"greeting":"Hello, Alice!"}`
- `curl "http://localhost:8080/hello"` → `{"greeting":"Hello, world!"}`

Here's a small REST API for a todo list using FastAPI:

```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from itertools import count

app = FastAPI(title="Todo API")

class TodoIn(BaseModel):
    title: str
    description: str | None = None

class Todo(TodoIn):
    id: int
    done: bool = False

_todos: dict[int, Todo] = {}
_id_seq = count(1)

@app.post("/todos", response_model=Todo, status_code=201)
def create_todo(todo_in: TodoIn):
    todo = Todo(id=next(_id_seq), done=False, **todo_in.model_dump())
    _todos[todo.id] = todo
    return todo

@app.get("/todos", response_model=list[Todo])
def list_todos():
    return list(_todos.values())

@app.post("/todos/{todo_id}/done", response_model=Todo)
def mark_done(todo_id: int):
    todo = _todos.get(todo_id)
    if not todo:
        raise HTTPException(status_code=404, detail="Todo not found")
    todo.done = True
    return todo
```

Save as `main.py`, install dependencies with `pip install fastapi uvicorn`, then run with `uvicorn main:app --reload`. Interactive docs are available at `http://localhost:8000/docs`.

