// server.js
const express = require('express');
const crypto = require('crypto');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET = process.env.WEBHOOK_SECRET;

if (!SECRET) {
  console.error('Missing WEBHOOK_SECRET environment variable');
  process.exit(1);
}

// Capture raw body for signature verification
app.use('/webhook', express.raw({ type: '*/*' }));

function verifySignature(rawBody, signature) {
  if (!signature) return false;

  // Strip optional "sha256=" prefix
  const provided = signature.startsWith('sha256=') ? signature.slice(7) : signature;

  const expected = crypto
    .createHmac('sha256', SECRET)
    .update(rawBody)
    .digest('hex');

  const a = Buffer.from(provided, 'hex');
  const b = Buffer.from(expected, 'hex');

  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(a, b);
}

app.post('/webhook', (req, res) => {
  const signature = req.get('X-Signature');
  const rawBody = req.body; // Buffer

  if (!verifySignature(rawBody, signature)) {
    console.warn('Invalid signature from', req.ip);
    return res.status(401).json({ error: 'invalid signature' });
  }

  let parsed;
  try {
    parsed = JSON.parse(rawBody.toString('utf8'));
  } catch (err) {
    return res.status(400).json({ error: 'invalid JSON' });
  }

  console.log('Valid webhook received:', JSON.stringify(parsed, null, 2));
  res.status(200).json({ ok: true });
});

app.listen(PORT, () => {
  console.log(`Webhook listener on port ${PORT}`);
});
```

