```javascript
// server.js
const express = require('express');
const crypto = require('crypto');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET = process.env.WEBHOOK_SECRET;

if (!SECRET) {
  console.error('WEBHOOK_SECRET environment variable is required');
  process.exit(1);
}

// Capture the raw body so we can verify the signature over the exact bytes received
app.use(
  '/webhook',
  express.json({
    verify: (req, _res, buf) => {
      req.rawBody = buf;
    },
  })
);

function verifySignature(rawBody, headerSig, secret) {
  if (!headerSig || !rawBody) return false;

  // Allow either a raw hex digest or a "sha256=..." prefixed value
  const provided = headerSig.startsWith('sha256=')
    ? headerSig.slice('sha256='.length)
    : headerSig;

  const expected = crypto
    .createHmac('sha256', secret)
    .update(rawBody)
    .digest('hex');

  const a = Buffer.from(provided, 'hex');
  const b = Buffer.from(expected, 'hex');

  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(a, b);
}

app.post('/webhook', (req, res) => {
  const signature = req.get('X-Signature');

  if (!verifySignature(req.rawBody, signature, SECRET)) {
    console.warn('Invalid signature on incoming webhook');
    return res.status(401).json({ error: 'invalid signature' });
  }

  console.log('Valid webhook received:', JSON.stringify(req.body, null, 2));
  res.status(200).json({ ok: true });
});

app.listen(PORT, () => {
  console.log(`Webhook listener running on port ${PORT}`);
});
