Here's a small HTTP proxy in Go using the standard library plus a simple in-memory token-bucket-style sliding window per client IP.

```go
package main

import (
	"flag"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"sync"
	"time"
)

const (
	requestLimit = 10
	windowSize   = time.Minute
)

type rateLimiter struct {
	mu      sync.Mutex
	clients map[string][]time.Time
}

func newRateLimiter() *rateLimiter {
	rl := &rateLimiter{clients: make(map[string][]time.Time)}
	go rl.gc()
	return rl
}

func (rl *rateLimiter) allow(ip string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	cutoff := now.Add(-windowSize)

	times := rl.clients[ip]
	// drop timestamps outside the window
	i := 0
	for ; i < len(times); i++ {
		if times[i].After(cutoff) {
			break
		}
	}
	times = times[i:]

	if len(times) >= requestLimit {
		rl.clients[ip] = times
		return false
	}
	rl.clients[ip] = append(times, now)
	return true
}

func (rl *rateLimiter) gc() {
	ticker := time.NewTicker(time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		rl.mu.Lock()
		cutoff := time.Now().Add(-windowSize)
		for ip, times := range rl.clients {
			i := 0
			for ; i < len(times); i++ {
				if times[i].After(cutoff) {
					break
				}
			}
			if i == len(times) {
				delete(rl.clients, ip)
			} else {
				rl.clients[ip] = times[i:]
			}
		}
		rl.mu.Unlock()
	}
}

func clientIP(r *http.Request) string {
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

func main() {
	upstream := flag.String("upstream", "https://example.com", "Upstream base URL to forward GET requests to")
	listen := flag.String("listen", ":8080", "Address to listen on")
	flag.Parse()

	upstreamURL, err := url.Parse(*upstream)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	rl := newRateLimiter()
	client := &http.Client{Timeout: 30 * time.Second}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			http.Error(w, "only GET supported", http.StatusMethodNotAllowed)
			return
		}

		ip := clientIP(r)
		if !rl.allow(ip) {
			w.Header().Set("Retry-After", "60")
			http.Error(w, "rate limit exceeded (10 requests/minute)", http.StatusTooManyRequests)
			return
		}

		target := *upstreamURL
		target.Path = singleJoin(upstreamURL.Path, r.URL.Path)
		target.RawQuery = r.URL.RawQuery

		req, err := http.NewRequestWithContext(r.Context(), http.MethodGet, target.String(), nil)
		if err != nil {
			http.Error(w, "bad upstream request: "+err.Error(), http.StatusInternalServerError)
			return
		}
		// copy a few safe headers
		for _, h := range []string{"Accept", "Accept-Encoding", "Accept-Language", "User-Agent"} {
			if v := r.Header.Get(h); v != "" {
				req.Header.Set(h, v)
			}
		}

		resp, err := client.Do(req)
		if err != nil {
			http.Error(w, "upstream error: "+err.Error(), http.StatusBadGateway)
			return
		}
		defer resp.Body.Close()

		for k, vs := range resp.Header {
			for _, v := range vs {
				w.Header().Add(k, v)
			}
		}
		w.WriteHeader(resp.StatusCode)
		io.Copy(w, resp.Body)
	})

	log.Printf("proxy listening on %s, forwarding GETs to %s", *listen, upstreamURL.String())
