        return True
    # Try parsing target as JSON for numbers, bools, null
    try:
        parsed = json.loads(target)
        if actual == parsed:
            return True
    except json.JSONDecodeError:
        pass
    # Fallback: stringified compare
    return str(actual) == target


def main():
