#!/usr/bin/env python3
"""jgrep: filter a stream of JSON objects (one per line) by key/value."""

import json
import sys


def get_nested(obj, key):
    """Look up a possibly-dotted key like 'user.name' in obj."""
    for part in key.split("."):
        if isinstance(obj, dict) and part in obj:
            obj = obj[part]
        else:
            return None, False
    return obj, True


def matches(actual, wanted):
    """Compare values: try to coerce wanted to actual's type when sensible."""
    if isinstance(actual, bool):
        return wanted.lower() in ("true", "1") if actual else wanted.lower() in ("false", "0")
    if isinstance(actual, (int, float)):
        try:
            return actual == type(actual)(wanted)
        except (ValueError, TypeError):
            return False
    if actual is None:
        return wanted.lower() == "null"
    return str(actual) == wanted


def main():
