package main

import (
	"fmt"
	"net"
	"os"
	"sort"
	"strconv"
	"strings"
	"sync"
	"time"
)

type result struct {
	port int
	open bool
}

func parsePorts(s string) ([]int, error) {
	seen := make(map[int]struct{})
	var ports []int
	for _, part := range strings.Split(s, ",") {
		part = strings.TrimSpace(part)
		if part == "" {
			continue
		}
		if strings.Contains(part, "-") {
			bounds := strings.SplitN(part, "-", 2)
			start, err1 := strconv.Atoi(strings.TrimSpace(bounds[0]))
			end, err2 := strconv.Atoi(strings.TrimSpace(bounds[1]))
			if err1 != nil || err2 != nil || start < 1 || end > 65535 || start > end {
				return nil, fmt.Errorf("invalid range: %q", part)
			}
			for p := start; p <= end; p++ {
				if _, ok := seen[p]; !ok {
					seen[p] = struct{}{}
					ports = append(ports, p)
				}
			}
		} else {
			p, err := strconv.Atoi(part)
			if err != nil || p < 1 || p > 65535 {
				return nil, fmt.Errorf("invalid port: %q", part)
			}
			if _, ok := seen[p]; !ok {
				seen[p] = struct{}{}
				ports = append(ports, p)
			}
		}
	}
	return ports, nil
}

func scan(host string, port int, timeout time.Duration) bool {
	addr := net.JoinHostPort(host, strconv.Itoa(port))
	conn, err := net.DialTimeout("tcp", addr, timeout)
	if err != nil {
		return false
	}
	conn.Close()
	return true
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <hostname> <ports>\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "  ports: comma-separated list, supports ranges (e.g. 22,80,8000-8100)\n")
		os.Exit(1)
	}

	host := os.Args[1]
	portsArg := strings.Join(os.Args[2:], ",")

	ports, err := parsePorts(portsArg)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	const maxConcurrent = 200
	timeout := 2 * time.Second

	sem := make(chan struct{}, maxConcurrent)
	results := make(chan result, len(ports))
	var wg sync.WaitGroup

	for _, p := range ports {
		wg.Add(1)
		sem <- struct{}{}
		go func(port int) {
			defer wg.Done()
			defer func() { <-sem }()
			results <- result{port: port, open: scan(host, port, timeout)}
		}(p)
	}

	go func() {
		wg.Wait()
		close(results)
	}()

	var open, closed []int
	for r := range results {
		if r.open {
			open = append(open, r.port)
		} else {
			closed = append(closed, r.port)
		}
	}
	sort.Ints(open)
	sort.Ints(closed)

	fmt.Printf("Scan results for %s:\n", host)
	fmt.Printf("\nOpen ports (%d):\n", len(open))
	for _, p := range open {
		fmt.Printf("  %d\tOPEN\n", p)
	}
	fmt.Printf("\nClosed ports (%d):\n", len(closed))
	for _, p := range closed {
		fmt.Printf("  %d\tCLOSED\n", p)
	}
}
