				}
				for p := start; p <= end; p++ {
					if !seen[p] {
						seen[p] = true
						ports = append(ports, p)
					}
				}
			} else {
				p, err := strconv.Atoi(part)
				if err != nil || p < 1 || p > 65535 {
					return nil, fmt.Errorf("invalid port: %s", part)
				}
				if !seen[p] {
					seen[p] = true
					ports = append(ports, p)
				}
			}
		}
	}
	return ports, nil
}

func checkPort(host string, port int, timeout time.Duration) bool {
	addr := net.JoinHostPort(host, strconv.Itoa(port))
	conn, err := net.DialTimeout("tcp", addr, timeout)
	if err != nil {
		return false
	}
	conn.Close()
	return true
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <port|range|list>...\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "Examples:\n")
		fmt.Fprintf(os.Stderr, "  %s example.com 80 443 8080\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "  %s example.com 20-25,80,443\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	ports, err := parsePorts(os.Args[2:])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Scanning %s (%d ports)...\n\n", host, len(ports))

	results := make(map[int]bool)
	var mu sync.Mutex
	var wg sync.WaitGroup

	// Limit concurrency to avoid exhausting file descriptors
	sem := make(chan struct{}, 256)
	timeout := 2 * time.Second

	for _, port := range ports {
		wg.Add(1)
		go func(p int) {
			defer wg.Done()
			sem <- struct{}{}
			defer func() { <-sem }()
			open := checkPort(host, p, timeout)
			mu.Lock()
			results[p] = open
			mu.Unlock()
		}(port)
	}

	wg.Wait()

	var open, closed []int
	for p, isOpen := range results {
		if isOpen {
			open = append(open, p)
		} else {
			closed = append(closed, p)
		}
	}
	sort.Ints(open)
	sort.Ints(closed)

	fmt.Println("OPEN:")
	if len(open) == 0 {
		fmt.Println("  (none)")
	}
	for _, p := range open {
		fmt.Printf("  %d\n", p)
	}

	fmt.Println("\nCLOSED:")
	if len(closed) == 0 {
		fmt.Println("  (none)")
	}
	for _, p := range closed {
		fmt.Printf("  %d\n", p)
	}
}
