			if err1 != nil || err2 != nil || start < 1 || end > 65535 || start > end {
				return nil, fmt.Errorf("invalid port range %q", part)
			}
			for p := start; p <= end; p++ {
				if _, ok := seen[p]; !ok {
					seen[p] = struct{}{}
					ports = append(ports, p)
				}
			}
		} else {
			p, err := strconv.Atoi(part)
			if err != nil || p < 1 || p > 65535 {
				return nil, fmt.Errorf("invalid port %q", part)
			}
			if _, ok := seen[p]; !ok {
				seen[p] = struct{}{}
				ports = append(ports, p)
			}
		}
	}
	return ports, nil
}

func scan(host string, port int, timeout time.Duration) result {
	addr := net.JoinHostPort(host, strconv.Itoa(port))
	conn, err := net.DialTimeout("tcp", addr, timeout)
	if err != nil {
		return result{port: port, open: false, err: err}
	}
	conn.Close()
	return result{port: port, open: true}
}

func main() {
	timeout := flag.Duration("timeout", 2*time.Second, "connection timeout per port")
	concurrency := flag.Int("c", 200, "max concurrent connections")
	flag.Usage = func() {
		fmt.Fprintf(os.Stderr, "Usage: %s [options] <host> <ports>\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "Ports: comma-separated list and/or ranges, e.g. 22,80,443,8000-8010\n")
		flag.PrintDefaults()
	}
	flag.Parse()

	if flag.NArg() < 2 {
		flag.Usage()
		os.Exit(1)
	}

	host := flag.Arg(0)
	ports, err := parsePorts(flag.Arg(1))
	if err != nil {
		fmt.Fprintln(os.Stderr, "error:", err)
		os.Exit(1)
	}

	results := make([]result, len(ports))
	sem := make(chan struct{}, *concurrency)
	var wg sync.WaitGroup

	for i, p := range ports {
		wg.Add(1)
		sem <- struct{}{}
		go func(idx, port int) {
			defer wg.Done()
			defer func() { <-sem }()
			results[idx] = scan(host, port, *timeout)
		}(i, p)
	}
	wg.Wait()

	sort.Slice(results, func(i, j int) bool { return results[i].port < results[j].port })

	var open, closed []int
	for _, r := range results {
		if r.open {
			open = append(open, r.port)
		} else {
			closed = append(closed, r.port)
		}
	}

	fmt.Printf("Scan results for %s:\n", host)
	fmt.Printf("  Open   (%d): %s\n", len(open), formatPorts(open))
	fmt.Printf("  Closed (%d): %s\n", len(closed), formatPorts(closed))
}

func formatPorts(ps []int) string {
	if len(ps) == 0 {
		return "(none)"
	}
	s := make([]string, len(ps))
	for i, p := range ps {
		s[i] = strconv.Itoa(p)
	}
	return strings.Join(s, ", ")
}
