def human_readable(size: float) -> str:
    for unit in ("B", "KB", "MB", "GB", "TB", "PB"):
        if size < 1024 or unit == "PB":
            return f"{size:.2f} {unit}"
        size /= 1024


def total_size(path: str) -> int:
    total = 0
    for root, _, files in os.walk(path, followlinks=False):
        for name in files:
            fp = os.path.join(root, name)
            try:
                # lstat avoids following symlinks
                total += os.lstat(fp).st_size
            except (OSError, FileNotFoundError) as e:
                print(f"Warning: cannot access {fp}: {e}", file=sys.stderr)
    return total


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Print the total size of all files in a directory (recursive)."
    )
    parser.add_argument("path", help="Directory path to scan")
    args = parser.parse_args()

    if not os.path.isdir(args.path):
        print(f"Error: '{args.path}' is not a directory", file=sys.stderr)
        return 1

    size = total_size(args.path)
    print(f"{human_readable(size)} ({size} bytes)")
    return 0


if __name__ == "__main__":
    sys.exit(main())
```

