Here's a Python CLI tool that recursively calculates directory size:

```python
#!/usr/bin/env python3
"""Recursively compute total size of files in a directory."""

import argparse
import os
import sys


def human_readable(size: float) -> str:
    for unit in ("B", "KB", "MB", "GB", "TB", "PB"):
        if size < 1024 or unit == "PB":
            return f"{size:.2f} {unit}"
        size /= 1024


def directory_size(path: str) -> int:
    total = 0
    for dirpath, _, filenames in os.walk(path, followlinks=False):
        for name in filenames:
            full = os.path.join(dirpath, name)
            try:
                # lstat avoids following symlinks (don't double-count targets)
                total += os.lstat(full).st_size
            except (OSError, FileNotFoundError) as e:
                print(f"Warning: could not stat {full}: {e}", file=sys.stderr)
    return total


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Print the total size of all files in a directory (recursive)."
    )
    parser.add_argument("path", help="Directory to measure")
    parser.add_argument(
        "-b", "--bytes", action="store_true", help="Also show raw byte count"
    )
    args = parser.parse_args()

    if not os.path.isdir(args.path):
        print(f"Error: {args.path!r} is not a directory", file=sys.stderr)
        return 1

    total = directory_size(args.path)
    print(human_readable(total))
    if args.bytes:
        print(f"({total} bytes)")
    return 0


if __name__ == "__main__":
    sys.exit(main())
```

Usage:

```
python3 dirsize.py /path/to/dir
python3 dirsize.py -b /path/to/dir   # also prints raw byte count
```

