Here's a simple counter app using Node.js with Express that persists the count to a file and broadcasts updates to all viewers via Server-Sent Events.

**`server.js`**
```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = 3000;
const DATA_FILE = path.join(__dirname, 'counter.json');

// Load or initialize counter
let count = 0;
try {
  count = JSON.parse(fs.readFileSync(DATA_FILE, 'utf8')).count || 0;
} catch {
  fs.writeFileSync(DATA_FILE, JSON.stringify({ count: 0 }));
}

const save = () => fs.writeFileSync(DATA_FILE, JSON.stringify({ count }));

// SSE clients
const clients = new Set();
const broadcast = () => {
  const data = `data: ${JSON.stringify({ count })}\n\n`;
  clients.forEach(res => res.write(data));
};

app.use(express.static('public'));
app.use(express.json());

app.get('/count', (req, res) => res.json({ count }));

app.post('/increment', (req, res) => {
  count++;
  save();
  broadcast();
  res.json({ count });
});

app.post('/decrement', (req, res) => {
  count--;
  save();
  broadcast();
  res.json({ count });
});

app.get('/events', (req, res) => {
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    'Connection': 'keep-alive',
  });
  res.write(`data: ${JSON.stringify({ count })}\n\n`);
  clients.add(res);
  req.on('close', () => clients.delete(res));
});

app.listen(PORT, () => console.log(`Running at http://localhost:${PORT}`));
```

