      text: String(msg.text).slice(0, 500),
      time: Date.now(),
    };
    history.push(entry);
    if (history.length > 100) history.shift();
    const payload = JSON.stringify({ type: 'message', message: entry });
    wss.clients.forEach((c) => c.readyState === 1 && c.send(payload));
  });
});

