    const time = new Date(m.time).toLocaleTimeString();
    div.innerHTML = '<span class="u"></span><span class="b"></span><span class="t"></span>';
    div.querySelector('.u').textContent = m.user + ':';
    div.querySelector('.b').textContent = ' ' + m.text;
    div.querySelector('.t').textContent = ' ' + time;
    messagesEl.appendChild(div);
    messagesEl.scrollTop = messagesEl.scrollHeight;
  }

  ws.onmessage = (e) => {
    const data = JSON.parse(e.data);
    if (data.type === 'history') data.messages.forEach(render);
    else if (data.type === 'message') render(data.message);
  };

  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const text = textEl.value.trim();
    if (!text || ws.readyState !== 1) return;
    ws.send(JSON.stringify({ user, text }));
    textEl.value = '';
  });
</script>
</body>
</html>`);
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => console.log('Chat running on http://localhost:' + PORT));
```

