Here's a minimal Express service that does exactly that:

```javascript
// webhook-service.js
import express from "express";
import crypto from "crypto";

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET = process.env.WEBHOOK_SECRET;

if (!SECRET) {
  console.error("Fatal: WEBHOOK_SECRET environment variable is not set.");
  process.exit(1);
}

// Capture the raw body so we can verify the signature against the exact bytes received.
app.use(
  express.json({
    verify: (req, _res, buf) => {
      req.rawBody = buf;
    },
  })
);

function verifySignature(rawBody, signatureHeader) {
  if (!signatureHeader) return false;

  // Accept both bare hex digests and "sha256=<hex>" prefixed values.
  const receivedSig = signatureHeader.startsWith("sha256=")
    ? signatureHeader.slice(7)
    : signatureHeader;

  const expectedSig = crypto
    .createHmac("sha256", SECRET)
    .update(rawBody)
    .digest("hex");

  // Constant-time comparison prevents timing attacks.
  try {
    return crypto.timingSafeEqual(
      Buffer.from(receivedSig, "hex"),
      Buffer.from(expectedSig, "hex")
    );
  } catch {
    // Buffers of different lengths (malformed hex, etc.) throw — treat as invalid.
    return false;
  }
}

app.post("/webhook", (req, res) => {
  const signatureHeader = req.headers["x-signature"];

  if (!verifySignature(req.rawBody, signatureHeader)) {
    console.warn(`[${new Date().toISOString()}] Rejected webhook — invalid signature.`);
    return res.status(401).json({ error: "Invalid signature" });
  }

  console.log(`[${new Date().toISOString()}] Valid webhook received:`);
  console.log(JSON.stringify(req.body, null, 2));

  res.status(200).json({ status: "ok" });
});

// Reject every other route.
app.use((_req, res) => res.status(404).json({ error: "Not found" }));

app.listen(PORT, () => {
  console.log(`Webhook service listening on port ${PORT}`);
});
```

