  -H "Content-Type: application/json" \
  -H "X-Signature: sha256=$SIG" \
  -d "$PAYLOAD"
```

---

### Key design decisions

| Decision | Reason |
|---|---|
| Raw body captured via `verify` callback | Ensures the signature is checked against the exact bytes sent, not a re-serialised JSON object |
| `crypto.timingSafeEqual` | Prevents timing-based signature oracle attacks |
| Accepts `sha256=<hex>` **or** bare hex | Compatible with GitHub-style webhooks and simpler senders |
| `WEBHOOK_SECRET` missing → immediate exit | Fails loudly at startup rather than silently accepting all requests |

Here's a minimal Express service with HMAC-SHA256 signature verification:

```javascript
// webhook-service.js
import express from "express";
import crypto from "crypto";

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET = process.env.WEBHOOK_SECRET;

if (!SECRET) {
  console.error("FATAL: WEBHOOK_SECRET environment variable is not set.");
  process.exit(1);
}

// Parse raw body so we can verify the exact bytes that were signed
app.use(
  "/webhook",
  express.raw({ type: "application/json" })
);

app.post("/webhook", (req, res) => {
  const signature = req.headers["x-signature"];

  if (!signature) {
    console.warn("Rejected request: missing X-Signature header");
    return res.status(401).json({ error: "Missing signature" });
  }

  // Compute expected HMAC-SHA256 over the raw body
  const hmac = crypto.createHmac("sha256", SECRET);
  hmac.update(req.body); // req.body is a Buffer here
  const expected = hmac.digest("hex");

  // Timing-safe comparison to prevent timing attacks
  const sigBuffer      = Buffer.from(signature, "hex");
  const expectedBuffer = Buffer.from(expected,  "hex");

  const isValid =
    sigBuffer.length === expectedBuffer.length &&
    crypto.timingSafeEqual(sigBuffer, expectedBuffer);

  if (!isValid) {
    console.warn("Rejected request: invalid signature");
    return res.status(403).json({ error: "Invalid signature" });
  }

  // Signature is valid — parse and log the JSON body
  let payload;
  try {
    payload = JSON.parse(req.body.toString("utf8"));
  } catch {
    console.warn("Rejected request: body is not valid JSON");
    return res.status(400).json({ error: "Invalid JSON body" });
  }

  console.log("Verified webhook payload:", JSON.stringify(payload, null, 2));
  return res.status(200).json({ received: true });
});

app.listen(PORT, () => {
  console.log(`Webhook service listening on port ${PORT}`);
});
```

