  -H "Content-Type: application/json" \
  -H "X-Signature: $SIG" \
  -d "$BODY"
```

---

### Key design decisions

| Decision | Reason |
|---|---|
| `express.raw()` instead of `express.json()` | Must verify the exact bytes that were signed *before* parsing |
| `crypto.timingSafeEqual()` | Prevents timing-based signature-oracle attacks |
| `Buffer.length` check before `timingSafeEqual` | The function throws if buffers differ in length |
| Parse JSON only after signature is confirmed valid | Avoids wasting CPU on untrusted, potentially malicious payloads |

Here's `wcx` in Go — straightforward, matches `wc`-style output, and handles multiple files with a total line.

**`wcx.go`**

```go
package main

import (
	"bufio"
	"fmt"
	"os"
	"text/tabwriter"
)

type counts struct {
	lines, words, bytes int
}

func countFile(path string) (counts, error) {
	f, err := os.Open(path)
	if err != nil {
		return counts{}, err
	}
	defer f.Close()

	var c counts
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		line := scanner.Bytes()
		c.lines++
		c.bytes += len(line) + 1 // +1 for the newline
		// count words
		inWord := false
		for _, b := range line {
			if b == ' ' || b == '\t' || b == '\r' {
				inWord = false
			} else {
				if !inWord {
					c.words++
					inWord = true
				}
			}
		}
	}
	if err := scanner.Err(); err != nil {
		return counts{}, err
	}

	// Use actual file size for byte count (handles files not ending in newline,
	// binary content, etc.)
	info, err := f.Stat()
	if err == nil {
		c.bytes = int(info.Size())
	}

	return c, nil
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: wcx <file> [file ...]\n")
		os.Exit(1)
	}

	paths := os.Args[1:]

	w := tabwriter.NewWriter(os.Stdout, 8, 8, 2, ' ', 0)
	fmt.Fprintln(w, "lines\twords\tbytes\tfile")
	fmt.Fprintln(w, "-----\t-----\t-----\t----")

	var total counts
	var hadError bool

	for _, path := range paths {
		c, err := countFile(path)
		if err != nil {
			fmt.Fprintf(os.Stderr, "wcx: %s: %v\n", path, err)
			hadError = true
			continue
		}
		fmt.Fprintf(w, "%d\t%d\t%d\t%s\n", c.lines, c.words, c.bytes, path)
		total.lines += c.lines
		total.words += c.words
		total.bytes += c.bytes
	}

	if len(paths) > 1 {
		fmt.Fprintf(w, "%d\t%d\t%d\t%s\n", total.lines, total.words, total.bytes, "total")
	}

	w.Flush()

	if hadError {
		os.Exit(1)
	}
}
```

