```go
// wcx.go
// Build: go build -o wcx wcx.go
// Usage: ./wcx file1.txt file2.txt ...

package main

import (
	"bufio"
	"fmt"
	"os"
	"strings"
	"unicode/utf8"
)

type counts struct {
	lines int
	words int
	bytes int
}

func countFile(path string) (counts, error) {
	f, err := os.Open(path)
	if err != nil {
		return counts{}, err
	}
	defer f.Close()

	var c counts
	scanner := bufio.NewScanner(f)

	for scanner.Scan() {
		line := scanner.Text()

		c.lines++

		// bytes: the raw bytes of the line plus the newline character
		c.bytes += len(line) + 1 // +1 for the '\n' stripped by Scanner

		// words: split on whitespace, ignoring empty tokens
		words := strings.Fields(line)
		c.words += len(words)

		_ = utf8.RuneCountInString(line) // validate UTF-8 (unused here, words/bytes are byte-based)
	}

	if err := scanner.Err(); err != nil {
		return c, err
	}

	return c, nil
}

func printRow(label string, c counts) {
	fmt.Printf("%8d %8d %8d  %s\n", c.lines, c.words, c.bytes, label)
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "Usage: wcx <file> [file ...]")
		os.Exit(1)
	}

	paths := os.Args[1:]
	var total counts
	exitCode := 0

	for _, path := range paths {
		c, err := countFile(path)
		if err != nil {
			fmt.Fprintf(os.Stderr, "wcx: %s: %v\n", path, err)
			exitCode = 1
			continue
		}
		total.lines += c.lines
		total.words += c.words
		total.bytes += c.bytes
		printRow(path, c)
	}

	if len(paths) > 1 {
		printRow("total", total)
	}

	os.Exit(exitCode)
}
