Here's `wcx` in Go — a clean reimplementation of the classic `wc` utility:

```go
// wcx.go
package main

import (
	"bufio"
	"fmt"
	"os"
	"text/tabwriter"
)

type counts struct {
	lines, words, bytes int64
}

func countFile(path string) (counts, error) {
	f, err := os.Open(path)
	if err != nil {
		return counts{}, err
	}
	defer f.Close()

	var c counts
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		line := scanner.Bytes()
		c.lines++
		c.bytes += int64(len(line)) + 1 // +1 for the newline
		// count words manually
		inWord := false
		for _, b := range line {
			isSpace := b == ' ' || b == '\t' || b == '\r'
			if isSpace {
				inWord = false
			} else {
				if !inWord {
					c.words++
					inWord = true
				}
			}
		}
	}
	if err := scanner.Err(); err != nil {
		return c, err
	}
	return c, nil
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "usage: wcx <file> [file ...]")
		os.Exit(1)
	}

	paths := os.Args[1:]

	w := tabwriter.NewWriter(os.Stdout, 8, 8, 2, ' ', 0)
	fmt.Fprintln(w, "lines\twords\tbytes\tfile")
	fmt.Fprintln(w, "-----\t-----\t-----\t----")

	var total counts
	exitCode := 0

	for _, path := range paths {
		c, err := countFile(path)
		if err != nil {
			fmt.Fprintf(os.Stderr, "wcx: %s: %v\n", path, err)
			exitCode = 1
			continue
		}
		fmt.Fprintf(w, "%d\t%d\t%d\t%s\n", c.lines, c.words, c.bytes, path)
		total.lines += c.lines
		total.words += c.words
		total.bytes += c.bytes
	}

	if len(paths) > 1 {
		fmt.Fprintf(w, "%d\t%d\t%d\t%s\n", total.lines, total.words, total.bytes, "(total)")
	}

	w.Flush()
	os.Exit(exitCode)
}
```

