Here's `jgrep` in Python — no dependencies beyond the standard library:

```python
#!/usr/bin/env python3
"""
jgrep - filter a stream of newline-delimited JSON objects by key/value.

Usage: jgrep <key> <value>
"""

import json
import sys


def coerce(value_str: str, reference):
    """Try to coerce value_str to the same type as reference for comparison."""
    if isinstance(reference, bool):
        if value_str.lower() == "true":
            return True
        if value_str.lower() == "false":
            return False
    if isinstance(reference, int):
        try:
            return int(value_str)
        except ValueError:
            pass
    if isinstance(reference, float):
        try:
            return float(value_str)
        except ValueError:
            pass
    if reference is None and value_str.lower() == "null":
        return None
    return value_str  # fall back to plain string comparison


def nested_get(obj: dict, key: str):
    """
    Support dot-notation for nested keys, e.g. "user.name".
    Returns (found, value).
    """
    parts = key.split(".")
    current = obj
    for part in parts:
        if not isinstance(current, dict) or part not in current:
            return False, None
        current = current[part]
    return True, current


def main():
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} <key> <value>", file=sys.stderr)
        sys.exit(1)

    key = sys.argv[1]
    raw_value = sys.argv[2]

    for lineno, line in enumerate(sys.stdin, start=1):
        line = line.strip()
        if not line:
            continue

        try:
            obj = json.loads(line)
        except json.JSONDecodeError as exc:
            print(f"[jgrep] Warning: line {lineno} is not valid JSON ({exc})", file=sys.stderr)
            continue

        if not isinstance(obj, dict):
            continue

        found, field_value = nested_get(obj, key)
        if not found:
            continue

        # Coerce the CLI string to match the field's actual type, then compare
        target = coerce(raw_value, field_value)

        if field_value == target:
            print(line)


if __name__ == "__main__":
    main()
```

