{"id":2,"ok":false}' | jgrep id 1
# → {"id":1,"ok":true}

# Boolean match
echo '{"id":1,"ok":true}
{"id":2,"ok":false}' | jgrep ok true
# → {"id":1,"ok":true}

# Dot-notation for nested keys
echo '{"user":{"name":"alice","age":30}}
{"user":{"name":"bob","age":25}}' | jgrep user.name alice
# → {"user":{"name":"alice","age":30}}

# Works great piped from other tools
cat logs.jsonl | jgrep level error
kubectl logs my-pod | jgrep severity CRITICAL
```

### Key features

| Feature | Details |
|---|---|
| **Type coercion** | CLI values are matched as strings, numbers, or booleans based on the field's actual JSON type |
| **Dot notation** | `user.address.city` navigates nested objects |
| **Bad lines** | Invalid JSON lines emit a warning to stderr and are skipped |
| **Streaming** | Reads stdin line by line — works on infinite/live streams |

Here's `jgrep` in Python:

```python
#!/usr/bin/env python3
"""
jgrep - filter JSON objects from stdin by key=value match.
Usage: jgrep <key> <value>
"""

import sys
import json


def matches(obj, key, value):
    """Check if obj[key] == value, with type coercion attempts."""
    if not isinstance(obj, dict):
        return False

    # Support nested keys with dot notation (e.g. "user.name")
    parts = key.split(".")
    current = obj
    for part in parts:
        if not isinstance(current, dict) or part not in current:
            return False
        current = current[part]

    actual = current

    # Try to match as the native JSON type first
    if str(actual) == value:
        return True

    # Try coercing value to the actual type
    if isinstance(actual, bool):
        return value.lower() in ("true", "1") and actual or value.lower() in ("false", "0") and not actual
    if isinstance(actual, int):
        try:
            return actual == int(value)
        except ValueError:
            pass
    if isinstance(actual, float):
        try:
            return actual == float(value)
        except ValueError:
            pass
    if actual is None:
        return value.lower() == "null"

    return False


def main():
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} <key> <value>", file=sys.stderr)
        sys.exit(1)

    key = sys.argv[1]
    value = sys.argv[2]

    for line_number, line in enumerate(sys.stdin, start=1):
        line = line.strip()
        if not line:
            continue

        try:
            obj = json.loads(line)
        except json.JSONDecodeError as e:
            print(f"Warning: line {line_number} is not valid JSON ({e})", file=sys.stderr)
            continue

        if matches(obj, key, value):
            print(json.dumps(obj))


if __name__ == "__main__":
    main()
```

