Here's a concurrent port scanner in Go:

```go
package main

import (
	"fmt"
	"net"
	"os"
	"sort"
	"strconv"
	"strings"
	"sync"
	"time"
)

const (
	timeout     = 2 * time.Second
	maxParallel = 100
)

type result struct {
	port   int
	open   bool
	err    string
}

func checkPort(host string, port int, wg *sync.WaitGroup, results chan<- result, sem chan struct{}) {
	defer wg.Done()
	sem <- struct{}{}
	defer func() { <-sem }()

	address := net.JoinHostPort(host, strconv.Itoa(port))
	conn, err := net.DialTimeout("tcp", address, timeout)
	if err != nil {
		results <- result{port: port, open: false, err: err.Error()}
		return
	}
	conn.Close()
	results <- result{port: port, open: true}
}

func parsePorts(args []string) ([]int, error) {
	var ports []int
	seen := make(map[int]bool)

	for _, arg := range args {
		// Handle ranges like "80-90"
		if strings.Contains(arg, "-") {
			parts := strings.SplitN(arg, "-", 2)
			if len(parts) != 2 {
				return nil, fmt.Errorf("invalid range: %s", arg)
			}
			start, err := strconv.Atoi(parts[0])
			if err != nil {
				return nil, fmt.Errorf("invalid port in range %s: %v", arg, err)
			}
			end, err := strconv.Atoi(parts[1])
			if err != nil {
				return nil, fmt.Errorf("invalid port in range %s: %v", arg, err)
			}
			if start > end {
				return nil, fmt.Errorf("invalid range (start > end): %s", arg)
			}
			for p := start; p <= end; p++ {
				if err := validatePort(p); err != nil {
					return nil, err
				}
				if !seen[p] {
					ports = append(ports, p)
					seen[p] = true
				}
			}
		} else {
			// Handle comma-separated values like "80,443,8080"
			for _, part := range strings.Split(arg, ",") {
				part = strings.TrimSpace(part)
				if part == "" {
					continue
				}
				p, err := strconv.Atoi(part)
				if err != nil {
					return nil, fmt.Errorf("invalid port %q: %v", part, err)
				}
				if err := validatePort(p); err != nil {
					return nil, err
				}
				if !seen[p] {
					ports = append(ports, p)
					seen[p] = true
				}
			}
		}
	}

	return ports, nil
}

func validatePort(p int) error {
	if p < 1 || p > 65535 {
		return fmt.Errorf("port %d out of range (1-65535)", p)
	}
	return nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <hostname> <port|port-range|port,port,...> ...\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "Examples:\n")
		fmt.Fprintf(os.Stderr, "  %s example.com 80 443\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "  %s example.com 80-90\n", os.Args[0])
		fmt.Fprintf(os.Stderr, "  %s example.com 22,80,443 8000-8010\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	ports, err := parsePorts(os.Args[2:])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error parsing ports: %v\n", err)
		os.Exit(1)
	}

	if len(ports) == 0 {
		fmt.Fprintf(os.Stderr, "No ports specified.\n")
		os.Exit(1)
	}

	fmt.Printf("Scanning %d port(s) on %s ...\n\n", len(ports), host)

	var wg sync.WaitGroup
	results := make(chan result, len(ports))
	sem := make(chan struct{}, maxParallel)

	for _, port := range ports {
		wg.Add(1)
		go checkPort(host, port, &wg, results, sem)
	}

	// Close results channel once all goroutines finish
	go func() {
		wg.Wait()
		close(results)
	}()

	// Collect results
	allResults := make([]result, 0, len(ports))
	for r := range results {
		allResults = append(allResults, r)
	}

	// Sort by port number for clean output
	sort.Slice(allResults, func(i, j int) bool {
		return allResults[i].port < allResults[j].port
	})

	// Print results
	openCount, closedCount := 0, 0
	for _, r := range allResults {
		if r.open {
			fmt.Printf("  %-6d OPEN\n", r.port)
			openCount++
		} else {
			fmt.Printf("  %-6d CLOSED\n", r.port)
			closedCount++
		}
	}

	fmt.Printf("\nSummary: %d open, %d closed\n", openCount, closedCount)
}
```

**Build and run:**

```bash
# Build
go build -o portscan main.go

# Scan individual ports
./portscan example.com 80 443 22

# Scan a range
./portscan example.com 8000-8010

# Mix of both, including comma-separated
