Here's a simple full-stack app using Python (Flask) with a JSON file for persistence.

**`app.py`**
```python
from flask import Flask, jsonify, request, send_from_directory
import json, os, threading

app = Flask(__name__, static_folder="static")
DATA_FILE = "counter.json"
lock = threading.Lock()

def read_count():
    if not os.path.exists(DATA_FILE):
        return 0
    with open(DATA_FILE) as f:
        return json.load(f).get("count", 0)

def write_count(n):
    with open(DATA_FILE, "w") as f:
        json.dump({"count": n}, f)

@app.route("/")
def index():
    return send_from_directory("static", "index.html")

@app.route("/count", methods=["GET"])
def get_count():
    with lock:
        return jsonify(count=read_count())

@app.route("/count", methods=["POST"])
def update_count():
    delta = request.json.get("delta", 0)
    with lock:
        new_count = read_count() + delta
        write_count(new_count)
    return jsonify(count=new_count)

if __name__ == "__main__":
    app.run(debug=True)
```

