**`server.js`**
```js
const express = require("express");
const http = require("http");
const { Server } = require("socket.io");

const app = express();
const server = http.createServer(app);
const io = new Server(server);

const PORT = process.env.PORT || 3000;
const MAX_HISTORY = 100;
const history = [];

app.get("/", (req, res) => {
  res.sendFile(__dirname + "/index.html");
});

io.on("connection", (socket) => {
  // Send recent history to the newly connected client
  socket.emit("history", history);

  socket.on("set name", (name) => {
    socket.username = String(name).trim().slice(0, 32) || "Anonymous";
    io.emit("system", `${socket.username} joined`);
  });

  socket.on("chat message", (msg) => {
    const text = String(msg).trim().slice(0, 500);
    if (!text) return;

    const entry = {
      user: socket.username || "Anonymous",
      text,
      time: new Date().toISOString(),
    };

    history.push(entry);
    if (history.length > MAX_HISTORY) history.shift();

    io.emit("chat message", entry);
  });

  socket.on("disconnect", () => {
    if (socket.username) {
      io.emit("system", `${socket.username} left`);
    }
  });
});

server.listen(PORT, () => {
  console.log(`Chat running at http://localhost:${PORT}`);
});
```

