```js
const express = require("express");
const http = require("http");
const { Server } = require("socket.io");

const app = express();
const server = http.createServer(app);
const io = new Server(server);

const PORT = process.env.PORT || 3000;
const MAX_HISTORY = 100;
const history = [];

app.get("/", (req, res) => {
  res.sendFile(__dirname + "/index.html");
});

io.on("connection", (socket) => {
  const address = socket.handshake.address;
  console.log(`User connected [${socket.id}] from ${address}`);

  // Send recent history to the newly connected user
  socket.emit("history", history);

  socket.on("message", (data) => {
    const msg = {
      name: String(data.name || "Anonymous").slice(0, 32),
      text: String(data.text || "").slice(0, 500),
      time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }),
    };

    if (!msg.text.trim()) return;

    history.push(msg);
    if (history.length > MAX_HISTORY) history.shift();

    io.emit("message", msg); // broadcast to everyone
  });

  socket.on("disconnect", () => {
    console.log(`User disconnected [${socket.id}]`);
  });
});

server.listen(PORT, () => {
  console.log(`Chat running at http://localhost:${PORT}`);
});
