  <script>
    const socket = io();
    const messagesEl = document.getElementById("messages");
    const form = document.getElementById("form");
    const input = document.getElementById("input");
    const status = document.getElementById("status");

    let myId = null;

    function escapeHtml(str) {
      return str.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
    }

    function addMessage(entry, mine) {
      const div = document.createElement("div");
      div.className = `msg ${mine ? "mine" : "theirs"}`;
      div.innerHTML = `
        <div class="bubble">${escapeHtml(entry.text)}</div>
        <div class="meta">${mine ? "you" : "#" + entry.id} · ${entry.time}</div>
      `;
      messagesEl.appendChild(div);
      messagesEl.scrollTop = messagesEl.scrollHeight;
    }

    socket.on("connect", () => {
      myId = socket.id.slice(0, 5);
      status.textContent = `connected as #${myId}`;
    });

    socket.on("disconnect", () => {
      status.textContent = "disconnected — reconnecting…";
    });

    socket.on("history", (msgs) => {
      messagesEl.innerHTML = "";
      msgs.forEach(m => addMessage(m, m.id === myId));
    });

    socket.on("message", (entry) => {
      addMessage(entry, entry.id === myId);
    });

    form.addEventListener("submit", (e) => {
      e.preventDefault();
      const text = input.value.trim();
      if (!text) return;
      socket.emit("message", text);
      input.value = "";
    });
  </script>
