      name: (data.name || 'Anonymous').trim().slice(0, 32) || 'Anonymous',
      text: (data.text || '').trim().slice(0, 500),
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    };

    if (!msg.text) return;

    history.push(msg);
    if (history.length > MAX_HISTORY) history.shift();

    io.emit('message', msg);
  });
});

