Here's a simple URL shortener using Python/Flask with SQLite for storage.

**Install dependencies:**
```bash
pip install flask
```

**`app.py`:**
```python
import sqlite3
import string
import random
from flask import Flask, request, redirect, render_template_string, url_for, abort

app = Flask(__name__)
DB = "urls.db"

# ── Database ──────────────────────────────────────────────────────────────────

def get_db():
    conn = sqlite3.connect(DB)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as db:
        db.execute("""
            CREATE TABLE IF NOT EXISTS urls (
                id      INTEGER PRIMARY KEY AUTOINCREMENT,
                code    TEXT UNIQUE NOT NULL,
                long_url TEXT NOT NULL,
                hits    INTEGER DEFAULT 0
            )
        """)

def generate_code(length=6):
    chars = string.ascii_letters + string.digits
    return "".join(random.choices(chars, k=length))

def create_short(long_url):
    with get_db() as db:
        # Return existing code if URL already shortened
        row = db.execute("SELECT code FROM urls WHERE long_url = ?", (long_url,)).fetchone()
        if row:
            return row["code"]
        for _ in range(10):          # retry on collision
            code = generate_code()
            try:
                db.execute("INSERT INTO urls (code, long_url) VALUES (?, ?)", (code, long_url))
                return code
            except sqlite3.IntegrityError:
                continue
    raise RuntimeError("Could not generate a unique code")

def resolve(code):
    with get_db() as db:
        row = db.execute("SELECT long_url FROM urls WHERE code = ?", (code,)).fetchone()
        if row:
            db.execute("UPDATE urls SET hits = hits + 1 WHERE code = ?", (code,))
            return row["long_url"]
    return None

