@app.route("/", methods=["GET", "POST"])
def index():
    short_url = error = original_url = None
    if request.method == "POST":
        original_url = request.form.get("url", "").strip()
        if not original_url.startswith(("http://", "https://")):
            error = "Please enter a valid URL starting with http:// or https://"
        else:
            try:
                code = create_short(original_url)
                short_url = url_for("redirect_to", code=code, _external=True)
            except Exception as e:
                error = f"Something went wrong: {e}"
    return render_template_string(HOME, short_url=short_url, error=error, url=original_url)

@app.route("/<code>")
def redirect_to(code):
    long_url = resolve(code)
    if not long_url:
        abort(404)
    return redirect(long_url, code=301)

@app.errorhandler(404)
def not_found(_):
    return "<h2>404 – Short link not found.</h2><p><a href='/'>Go home</a></p>", 404

# ── Entry point ───────────────────────────────────────────────────────────────

if __name__ == "__main__":
    init_db()
    app.run(debug=True)
