I'll create a Node.js Express service that verifies HMAC-SHA256 signatures and logs valid webhook payloads.

```javascript
const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

const SECRET = process.env.WEBHOOK_SECRET || 'your-secret-key';

app.post('/webhook', (req, res) => {
  const signature = req.headers['x-signature'];

  if (!signature) {
    return res.status(401).json({ error: 'Missing X-Signature header' });
  }

  // Calculate expected signature
  const body = JSON.stringify(req.body);
  const expectedSignature = crypto
    .createHmac('sha256', SECRET)
    .update(body)
    .digest('hex');

  // Compare signatures (timing-safe comparison)
  if (!crypto.timingSafeEqual(signature, expectedSignature)) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Signature is valid, log the body
  console.log('✓ Valid webhook received:', req.body);

  res.json({ success: true, message: 'Webhook processed' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Webhook service listening on port ${PORT}`);
});
```

**Usage:**

1. Install dependencies: `npm install express`
2. Set your secret: `export WEBHOOK_SECRET="your-shared-secret"`
3. Run the service: `node server.js`
4. Test with curl:
```bash
