I'll build a simple web app with a counter that persists on the server and syncs across all viewers.

```python
from flask import Flask, render_template, jsonify, request
from flask_cors import CORS

app = Flask(__name__)
CORS(app)

# In-memory counter (in production, use a database)
counter = {"value": 0}

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/api/counter', methods=['GET'])
def get_counter():
    return jsonify(counter)

@app.route('/api/counter', methods=['POST'])
def update_counter():
    data = request.json
    counter['value'] = data.get('value', counter['value'])
    return jsonify(counter)

@app.route('/api/increment', methods=['POST'])
def increment():
    counter['value'] += 1
    return jsonify(counter)

@app.route('/api/decrement', methods=['POST'])
def decrement():
    counter['value'] -= 1
    return jsonify(counter)

if __name__ == '__main__':
    app.run(debug=True)
```

