        <div class="message-time">${data.timestamp}</div>
      `;
      messagesDiv.appendChild(messageDiv);
      messagesDiv.scrollTop = messagesDiv.scrollHeight;
    });

    socket.on('connect', () => {
      console.log('Connected to chat server');
    });
  </script>
