class URLMapping(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    short_code = db.Column(db.String(10), unique=True, nullable=False)
    long_url = db.Column(db.String(2048), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    clicks = db.Column(db.Integer, default=0)

def generate_short_code(length=6):
    characters = string.ascii_letters + string.digits
    return ''.join(random.choice(characters) for _ in range(length))

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/api/shorten', methods=['POST'])
def shorten():
    data = request.json
    long_url = data.get('url', '').strip()

    if not long_url:
        return jsonify({'error': 'URL is required'}), 400

    # Add http:// if no protocol specified
    if not long_url.startswith(('http://', 'https://')):
        long_url = 'http://' + long_url

    # Check if URL already shortened
    existing = URLMapping.query.filter_by(long_url=long_url).first()
    if existing:
        return jsonify({
            'short_code': existing.short_code,
            'short_url': f"{request.host_url}{existing.short_code}"
        })

    # Generate unique short code
    short_code = generate_short_code()
    while URLMapping.query.filter_by(short_code=short_code).first():
        short_code = generate_short_code()

    # Save to database
    mapping = URLMapping(short_code=short_code, long_url=long_url)
    db.session.add(mapping)
    db.session.commit()

    return jsonify({
        'short_code': short_code,
        'short_url': f"{request.host_url}{short_code}"
    })

@app.route('/<short_code>')
def redirect_url(short_code):
    mapping = URLMapping.query.filter_by(short_code=short_code).first_or_404()
    mapping.clicks += 1
    db.session.commit()
    return redirect(mapping.long_url)

@app.route('/api/stats/<short_code>')
