    mapping = URLMapping.query.filter_by(short_code=short_code).first_or_404()
    return jsonify({
        'short_code': mapping.short_code,
        'long_url': mapping.long_url,
        'clicks': mapping.clicks,
        'created_at': mapping.created_at.isoformat()
    })

