I'll build a simple URL shortener using Python with Flask and SQLite.

```python
from flask import Flask, render_template, request, redirect, jsonify
from flask_sqlalchemy import SQLAlchemy
import string
import random
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///urls.db'
db = SQLAlchemy(app)

class URL(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    original_url = db.Column(db.String(2048), nullable=False)
    short_code = db.Column(db.String(10), unique=True, nullable=False)

def generate_short_code(length=6):
    characters = string.ascii_letters + string.digits
    return ''.join(random.choice(characters) for _ in range(length))

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/shorten', methods=['POST'])
def shorten():
    data = request.get_json()
    original_url = data.get('url')

    if not original_url:
        return jsonify({'error': 'No URL provided'}), 400

    # Add scheme if missing
    if not original_url.startswith(('http://', 'https://')):
        original_url = 'https://' + original_url

    # Check if URL already shortened
    existing = URL.query.filter_by(original_url=original_url).first()
    if existing:
        return jsonify({'short_url': f"/{existing.short_code}"})

    # Generate unique short code
    while True:
        short_code = generate_short_code()
        if not URL.query.filter_by(short_code=short_code).first():
            break

    url_entry = URL(original_url=original_url, short_code=short_code)
    db.session.add(url_entry)
    db.session.commit()

    return jsonify({'short_url': f"/{short_code}"})

@app.route('/<short_code>')
def redirect_url(short_code):
    url_entry = URL.query.filter_by(short_code=short_code).first()
    if url_entry:
        return redirect(url_entry.original_url)
    return 'URL not found', 404

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)
