Here’s a small REST API for a todo list using Node.js and Express.

```javascript
// index.js
const express = require('express');

const app = express();
const PORT = process.env.PORT || 3000;

// Parse JSON bodies
app.use(express.json());

// Handle invalid JSON
app.use((err, req, res, next) => {
  if (err instanceof SyntaxError && 'body' in err) {
    return res.status(400).json({ error: 'Invalid JSON body' });
  }
  next();
});

// In-memory storage
let todos = [];
let nextId = 1;

// Create a todo: POST /todos  { "title": "Buy milk" }
app.post('/todos', (req, res) => {
  const { title } = req.body || {};
  if (!title || typeof title !== 'string') {
    return res.status(400).json({ error: 'Field "title" (string) is required' });
  }
  const now = new Date().toISOString();
  const todo = { id: nextId++, title, done: false, createdAt: now, completedAt: null };
  todos.push(todo);
  res.status(201).json(todo);
});

// List todos: GET /todos
app.get('/todos', (req, res) => {
  res.json(todos);
});

// Mark done: POST /todos/:id/done
app.post('/todos/:id/done', (req, res) => {
  const id = Number(req.params.id);
  if (!Number.isInteger(id)) {
    return res.status(400).json({ error: 'Invalid id' });
  }
  const todo = todos.find(t => t.id === id);
  if (!todo) {
    return res.status(404).json({ error: 'Todo not found' });
  }
  if (!todo.done) {
    todo.done = true;
    todo.completedAt = new Date().toISOString();
  }
  res.json(todo);
});

// Start server
app.listen(PORT, () => {
  console.log(`Todo API listening on http://localhost:${PORT}`);
});
```

