Here's a simple Python command-line tool that filters JSON Lines by key/value.

```python
#!/usr/bin/env python3
import sys
import json

USAGE = "Usage: jgrep <key> <value>\nReads JSON objects (one per line) from stdin and prints those where obj[key] == value."

def parse_cli_value(s: str):
    # Try to interpret the value as JSON (number, true/false, null, string, etc.)
    try:
        return json.loads(s)
    except Exception:
        # Fallback to plain string if not valid JSON literal
        return s

def main():
    argv = sys.argv
    if len(argv) != 3 or argv[1] in ("-h", "--help"):
        print(USAGE, file=sys.stderr)
        sys.exit(2 if len(argv) != 3 else 0)

    key = argv[1]
    want = parse_cli_value(argv[2])

    for line in sys.stdin:
        if not line.strip():
            continue
        try:
            obj = json.loads(line)
        except Exception:
            # Skip lines that are not valid JSON
            continue
        if isinstance(obj, dict) and key in obj and obj.get(key) == want:
            # Print the original line to preserve formatting
            if line.endswith("\n"):
                sys.stdout.write(line)
            else:
                sys.stdout.write(line + "\n")

if __name__ == "__main__":
    main()
```

Usage:
- Save as jgrep (make it executable: chmod +x jgrep) and place on PATH.
- Example: cat data.jsonl | jgrep status true
- The value argument is parsed as JSON if possible (e.g., true/false/null/numbers); otherwise treated as a string.

Here’s a small Python 3 program that fetches a URL and prints the text inside the first <h1> tag using only the standard library.

```python
#!/usr/bin/env python3
import sys
import re
import urllib.request
import urllib.error
from html.parser import HTMLParser

class H1Parser(HTMLParser):
    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.in_h1 = False
        self.done = False
        self.chunks = []

    def handle_starttag(self, tag, attrs):
        if not self.done and tag.lower() == 'h1':
            self.in_h1 = True

    def handle_endtag(self, tag):
        if self.in_h1 and tag.lower() == 'h1':
            self.in_h1 = False
            self.done = True

    def handle_data(self, data):
        if self.in_h1 and not self.done:
            self.chunks.append(data)

def fetch_html(url, timeout=15):
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "h1-fetcher/1.0 (+https://example.com)",
            "Accept": "text/html,application/xhtml+xml;q=0.9,*/*;q=0.8",
        },
    )
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        data = resp.read()
        charset = resp.headers.get_content_charset()
    if charset:
        return data.decode(charset, errors="replace")
    # Fallbacks if charset not provided
    try:
        return data.decode("utf-8")
    except UnicodeDecodeError:
        return data.decode("latin-1", errors="replace")

def extract_first_h1(html_text):
    parser = H1Parser()
    parser.feed(html_text)
    parser.close()
    if not parser.chunks:
        return None
    # Collapse whitespace to a single space
    text = re.sub(r"\s+", " ", "".join(parser.chunks)).strip()
    return text or None

def main():
    if len(sys.argv) != 2:
        print("Usage: python h1_fetch.py <URL>", file=sys.stderr)
        sys.exit(1)
    url = sys.argv[1]
    try:
        html_text = fetch_html(url)
    except urllib.error.URLError as e:
        print(f"Error fetching URL: {e}", file=sys.stderr)
        sys.exit(2)
    h1 = extract_first_h1(html_text)
    if h1 is None:
        print("No <h1> found", file=sys.stderr)
        sys.exit(3)
    print(h1)

if __name__ == "__main__":
    main()
```

Usage:
- Save as h1_fetch.py
- Run: python3 h1_fetch.py https://example.com
- Prints the text content of the first <h1> tag, or exits with an error if not found.

