```python
#!/usr/bin/env python3
import os
import sys
import uuid

def main():
    dirpath = sys.argv[1] if len(sys.argv) > 1 else "."
    dirpath = os.path.abspath(dirpath)

    try:
        entries = os.listdir(dirpath)
    except FileNotFoundError:
        print(f"Directory not found: {dirpath}", file=sys.stderr)
        sys.exit(1)

    # Pick only regular files ending in .jpg (case-insensitive)
    sources = [
        e for e in entries
        if os.path.isfile(os.path.join(dirpath, e)) and e.lower().endswith(".jpg")
    ]

    if not sources:
        print("No .jpg files found in the directory.", file=sys.stderr)
        sys.exit(1)

    # Sort by current filename (case-insensitive for predictability)
    sources.sort(key=str.lower)

    width = 4  # fixed width: 0001, 0002, ...
    mappings = []
    for idx, name in enumerate(sources, start=1):
        final_name = f"photo-{idx:0{width}d}.jpg"
        mappings.append((os.path.join(dirpath, name), os.path.join(dirpath, final_name)))

    source_set = set(src for src, _ in mappings)
    final_set = set(dst for _, dst in mappings)
    if len(final_set) != len(mappings):
        print("Computed duplicate target names; aborting.", file=sys.stderr)
        sys.exit(1)

    # Prevent overwriting files that are not part of the rename set
    for _, dst in mappings:
        if os.path.exists(dst) and dst not in source_set:
            print(f"Target already exists and is not being renamed: {os.path.basename(dst)}", file=sys.stderr)
            sys.exit(1)

    # Two-phase rename to avoid collisions: src -> temp -> final
    temps = []
    for src, _ in mappings:
        base = os.path.basename(src)
        temp = os.path.join(dirpath, base + f".renametmp-{uuid.uuid4().hex}")
        while os.path.exists(temp):
            temp = os.path.join(dirpath, base + f".renametmp-{uuid.uuid4().hex}")
        temps.append((src, temp))

    try:
        # Phase 1: move all sources to unique temp names
        for src, temp in temps:
            os.replace(src, temp)
        # Phase 2: move temps to their final target names
        for (src, dst), (_, temp) in zip(mappings, temps):
            os.replace(temp, dst)
    except Exception as e:
        print(f"Error during renaming: {e}", file=sys.stderr)
        # Best-effort rollback for any temps still present
        for (orig_src, _), (_, temp) in zip(mappings, temps):
            if os.path.exists(temp) and not os.path.exists(orig_src):
                try:
                    os.replace(temp, orig_src)
                except Exception:
                    pass
        sys.exit(1)

    print(f"Renamed {len(mappings)} files to photo-0001.jpg ... photo-{len(mappings):04d}.jpg")

if __name__ == "__main__":
    main()
```

Usage:
- Save as rename_photos.py
- Run: python3 rename_photos.py /path/to/folder
- If no folder is given, it uses the current directory. It processes .jpg files (case-insensitive) and outputs photo-0001.jpg, photo-0002.jpg, ... in sorted order by existing filename. The script uses a safe two-phase rename to avoid collisions.

