#!/usr/bin/env python3
import sys
import re
import urllib.request
import urllib.error
from html.parser import HTMLParser

class H1Parser(HTMLParser):
    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.in_h1 = False
        self.done = False
        self.parts = []

    def handle_starttag(self, tag, attrs):
        if not self.done and tag.lower() == 'h1':
            self.in_h1 = True

    def handle_endtag(self, tag):
        if self.in_h1 and tag.lower() == 'h1':
            self.in_h1 = False
            self.done = True

    def handle_data(self, data):
        if self.in_h1 and not self.done:
            self.parts.append(data)

    def get_text(self):
        text = ''.join(self.parts)
        return ' '.join(text.split()).strip()

def guess_encoding_from_meta(html_bytes):
    head = html_bytes[:8192]
    m = re.search(br'<meta[^>]+charset=["\']?\s*([a-zA-Z0-9_\-]+)', head, re.IGNORECASE)
    if m:
        try:
            return m.group(1).decode('ascii', 'ignore')
        except Exception:
            return None
    m = re.search(
        br'<meta[^>]+http-equiv=["\']?content-type["\']?[^>]*content=["\'][^"\']*;\s*charset=([a-zA-Z0-9_\-]+)',
        head, re.IGNORECASE
    )
    if m:
        try:
            return m.group(1).decode('ascii', 'ignore')
        except Exception:
            return None
    return None

def fetch(url):
    if '://' not in url:
        url = 'http://' + url
    req = urllib.request.Request(url, headers={
        'User-Agent': 'Mozilla/5.0 (compatible; h1-fetch/1.0)'
    })
    with urllib.request.urlopen(req, timeout=15) as resp:
        content_type = resp.headers.get('Content-Type', '')
        encoding = None
        try:
            encoding = resp.headers.get_content_charset()
        except Exception:
            m = re.search(r'charset=([\w\-]+)', content_type, re.IGNORECASE)
            if m:
                encoding = m.group(1)
        data = resp.read()
    if not encoding:
        enc2 = guess_encoding_from_meta(data)
        if enc2:
            encoding = enc2
    if not encoding:
        encoding = 'utf-8'
    try:
        text = data.decode(encoding, errors='replace')
    except LookupError:
        text = data.decode('utf-8', errors='replace')
    return text

def main():
    if len(sys.argv) != 2:
        print(f'Usage: {sys.argv[0]} URL', file=sys.stderr)
        sys.exit(2)
    url = sys.argv[1]
    try:
        html = fetch(url)
    except urllib.error.URLError as e:
        print(f'Error fetching URL: {e}', file=sys.stderr)
        sys.exit(1)
    parser = H1Parser()
    try:
        parser.feed(html)
    except Exception:
        pass
    h1_text = parser.get_text()
    if h1_text:
        print(h1_text)
        sys.exit(0)
    else:
        print('No <h1> found', file=sys.stderr)
        sys.exit(1)

if __name__ == '__main__':
    main()

