Here's a simple Python program that reads a file (or stdin), counts line frequencies, and prints only the lines that occur more than once with their counts, sorted from most frequent to least.

```python
#!/usr/bin/env python3
import sys
import argparse

def iter_lines(paths):
    if not paths:
        for line in sys.stdin:
            yield line
    else:
        for p in paths:
            with open(p, 'r', encoding='utf-8', errors='replace', newline='') as f:
                for line in f:
                    yield line

def main():
    parser = argparse.ArgumentParser(
        description="Print lines appearing more than once, with counts, sorted by frequency descending."
    )
    parser.add_argument('files', nargs='*', help="Input files (reads stdin if omitted).")
    args = parser.parse_args()

    counts = {}
    for line in iter_lines(args.files):
        counts[line] = counts.get(line, 0) + 1

    dup_items = [(line, c) for line, c in counts.items() if c > 1]
    dup_items.sort(key=lambda t: (-t[1], t[0]))

    write = sys.stdout.write
    for line, c in dup_items:
        # Print "count<TAB>line", preserving the line's original newline (if any)
        write(f"{c}\t")
        write(line)

if __name__ == "__main__":
    sys.exit(main())
```

Usage:
- From a file: python dupfreq.py yourfile.txt
- From stdin: cat yourfile.txt | python dupfreq.py

Output format: count<TAB>line (line is printed as-is, including its original newline if present).

Here’s a minimal Go HTTP server that serves GET /hello?name=<name> and returns the requested JSON.

```go
// main.go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
)

type greetingResponse struct {
	Greeting string `json:"greeting"`
}

func helloHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	name := r.URL.Query().Get("name")
	if name == "" {
		name = "world"
	}

	resp := greetingResponse{Greeting: fmt.Sprintf("Hello, %s!", name)}
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	if err := json.NewEncoder(w).Encode(resp); err != nil {
		http.Error(w, "Failed to encode JSON", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/hello", helloHandler)

	addr := ":8080"
	log.Printf("Listening on http://localhost%s", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatal(err)
	}
}
