Here's a small Node.js service using Express that verifies an HMAC-SHA256 signature from the X-Signature header and logs the JSON body if valid.

Code (server.js):
```js
const express = require('express');
const crypto = require('crypto');

const PORT = process.env.PORT || 3000;
const SECRET = process.env.WEBHOOK_SECRET || process.env.SHARED_SECRET; // use either if set

if (!SECRET) {
  console.error('Error: Set WEBHOOK_SECRET (or SHARED_SECRET) environment variable.');
  process.exit(1);
}

const app = express();

// Use raw body for signature verification (expects application/json)
app.post(
  '/webhook',
  express.raw({ type: 'application/json', limit: '1mb' }),
  (req, res) => {
    try {
      const sigHeader = req.get('X-Signature');
      if (!sigHeader) {
        return res.status(400).send('Missing X-Signature header');
      }

      // Accept either "sha256=<hex>" or plain "<hex>"
      const providedHex = sigHeader.startsWith('sha256=')
        ? sigHeader.slice(7)
        : sigHeader;

      // Compute expected HMAC over the raw request body
      const expectedHex = crypto
        .createHmac('sha256', SECRET)
        .update(req.body)
        .digest('hex');

      const providedBuf = Buffer.from(providedHex, 'hex');
      const expectedBuf = Buffer.from(expectedHex, 'hex');

      if (
        providedBuf.length !== expectedBuf.length ||
        !crypto.timingSafeEqual(providedBuf, expectedBuf)
      ) {
        return res.status(401).send('Invalid signature');
      }

      // Signature valid: parse and log JSON
      let json;
      try {
        json = JSON.parse(req.body.toString('utf8'));
      } catch {
        return res.status(400).send('Invalid JSON');
      }

      console.log('Webhook payload:', JSON.stringify(json));
      return res.status(200).send('ok');
    } catch (err) {
      console.error('Error handling webhook:', err);
      return res.status(500).send('Internal Server Error');
    }
  }
);

app.listen(PORT, () => {
  console.log(`Webhook listener running on http://localhost:${PORT}`);
});
```

Usage:
- Set the secret: export WEBHOOK_SECRET='your-shared-secret'
- Install and run:
  - npm install express
  - node server.js
- Test with curl (example):
  - Save JSON to data.json, then:
    - SIG=$(openssl dgst -sha256 -hmac "$WEBHOOK_SECRET" -binary data.json | xxd -p -c 256)
    - curl -X POST -H "Content-Type: application/json" -H "X-Signature: $SIG" --data @data.json http://localhost:3000/webhook

Here’s a small Go service that verifies an HMAC-SHA256 signature from the X-Signature header against a shared secret in WEBHOOK_SECRET and logs the JSON body if valid.

```go
// main.go
package main

import (
	"crypto/hmac"
	"crypto/sha256"
	"crypto/subtle"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"io"
	"log"
	"net/http"
	"os"
	"strings"
)

const (
	envSecret = "WEBHOOK_SECRET"
)

func main() {
	secret := os.Getenv(envSecret)
	if secret == "" {
		log.Fatalf("%s is not set", envSecret)
	}

	mux := http.NewServeMux()
	mux.Handle("/webhook", webhookHandler([]byte(secret)))

	addr := ":" + firstNonEmpty(os.Getenv("PORT"), "8080")
	log.Printf("Listening on %s", addr)
	if err := http.ListenAndServe(addr, mux); err != nil {
		log.Fatal(err)
	}
}

func webhookHandler(secret []byte) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		// Read raw body for signature check
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "failed to read body", http.StatusBadRequest)
			return
		}
		defer r.Body.Close()

		sigHeader := r.Header.Get("X-Signature")
		if sigHeader == "" {
			http.Error(w, "missing X-Signature", http.StatusUnauthorized)
			return
		}

		sig, err := parseSignature(sigHeader)
		if err != nil || len(sig) != sha256.Size {
			http.Error(w, "invalid signature format", http.StatusUnauthorized)
			return
		}

		mac := hmac.New(sha256.New, secret)
		mac.Write(body)
		expected := mac.Sum(nil)

		if subtle.ConstantTimeCompare(expected, sig) != 1 {
			http.Error(w, "signature verification failed", http.StatusUnauthorized)
			return
		}

		// Parse and log JSON body
		var payload any
		if err := json.Unmarshal(body, &payload); err != nil {
			http.Error(w, "invalid JSON body", http.StatusBadRequest)
			return
		}
		pretty, _ := json.MarshalIndent(payload, "", "  ")
		log.Printf("Webhook received and verified:\n%s", pretty)

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(`{"status":"ok"}`))
	})
}

// parseSignature accepts any of the following header formats:
// - "sha256=<hex>"
// - "<hex>"
// - base64 (standard or raw) of 32-byte HMAC
func parseSignature(h string) ([]byte, error) {
	s := strings.TrimSpace(h)
	// Handle optional "sha256=" prefix (commonly used)
	if i := strings.IndexByte(s, '='); i != -1 {
		// If it looks like "sha256=<digest>", take the part after '='
		if i+1 < len(s) && strings.HasPrefix(strings.ToLower(s[:i]), "sha256") {
			s = s[i+1:]
		}
	}
	s = strings.TrimSpace(s)

	// Try hex
	if b, err := hex.DecodeString(s); err == nil {
		return b, nil
	}
	// Try base64 (raw then padded)
	if b, err := base64.RawStdEncoding.DecodeString(s); err == nil {
		return b, nil
	}
	if b, err := base64.StdEncoding.DecodeString(s); err == nil {
		return b, nil
	}
	return nil, io.ErrUnexpectedEOF
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if v != "" {
			return v
		}
	}
	return ""
}
```

Usage:
- Set WEBHOOK_SECRET to your shared secret. Optionally set PORT (default 8080).
- Build and run:
  - go run main.go
- Send a POST to /webhook with:
  - Body: JSON
  - Header X-Signature: HMAC-SHA256 of the raw body using the shared secret (as hex, base64, or "sha256=<hex>").

Here’s a small Go HTTP proxy that forwards GET requests to an upstream URL and rate-limits each client IP to 10 requests per minute, returning 429 when over the limit.

```go
// main.go
package main

import (
	"flag"
	"log"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"
)

type bucket struct {
	count int
	reset time.Time
}

type RateLimiter struct {
	mu      sync.Mutex
	clients map[string]*bucket
	limit   int
	window  time.Duration
}

func NewRateLimiter(limit int, window time.Duration) *RateLimiter {
	rl := &RateLimiter{
		clients: make(map[string]*bucket),
		limit:   limit,
		window:  window,
	}
	// Simple cleanup goroutine to prevent unbounded map growth
	go func() {
		t := time.NewTicker(window)
		defer t.Stop()
		for range t.C {
			now := time.Now()
			rl.mu.Lock()
			for ip, b := range rl.clients {
				if now.After(b.reset.Add(window)) {
					delete(rl.clients, ip)
				}
			}
			rl.mu.Unlock()
		}
	}()
	return rl
}

func (rl *RateLimiter) Allow(id string) bool {
	now := time.Now()
	rl.mu.Lock()
	defer rl.mu.Unlock()

	b, ok := rl.clients[id]
	if !ok || now.After(b.reset) {
		rl.clients[id] = &bucket{count: 1, reset: now.Add(rl.window)}
		return true
	}
	if b.count >= rl.limit {
		return false
	}
	b.count++
	return true
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For if present (first IP), else use RemoteAddr
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			return strings.TrimSpace(parts[0])
		}
	}
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

func main() {
	upstreamStr := flag.String("upstream", "", "Upstream base URL to proxy to (e.g. http://localhost:9000 or https://api.example.com/base)")
	addr := flag.String("addr", ":8080", "Listen address")
	flag.Parse()

	if *upstreamStr == "" {
		log.Fatal("missing required -upstream URL")
	}

	target, err := url.Parse(*upstreamStr)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	proxy := httputil.NewSingleHostReverseProxy(target)
	// Improve error messages from upstream failures
	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, e error) {
		http.Error(w, "Bad Gateway: "+e.Error(), http.StatusBadGateway)
	}

	limiter := NewRateLimiter(10, time.Minute)

	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}

		ip := clientIP(r)
		if !limiter.Allow(ip) {
			w.Header().Set("Retry-After", "60")
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		// Proxy the GET request to the upstream
		proxy.ServeHTTP(w, r)
	})

	srv := &http.Server{
		Addr:         *addr,
		Handler:      handler,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 60 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Printf("Proxy listening on %s -> %s (GET only, 10 req/min per IP)", *addr, target.String())
	if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatalf("server error: %v", err)
	}
}
```

