  - Optional: -addr :8080 to change listen address.
- Send GET requests to the proxy (e.g., http://localhost:8080/path?query=1). They’ll be forwarded to the upstream base URL (preserving path and query). Each client IP is limited to 10 requests per 60 seconds; excess requests receive HTTP 429 with Retry-After: 60.

Here's a small Go HTTP proxy server that forwards GET requests to an upstream URL and rate-limits each client IP to 10 requests per minute, returning 429 when over the limit.

```go
// proxy.go
package main

import (
	"log"
	"math"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

type clientLimiter struct {
	limiter  *rate.Limiter
	lastSeen time.Time
}

type ipRateLimiter struct {
	mu      sync.Mutex
	clients map[string]*clientLimiter
	r       rate.Limit
	burst   int
}

func newIPRateLimiter(r rate.Limit, burst int) *ipRateLimiter {
	rl := &ipRateLimiter{
		clients: make(map[string]*clientLimiter),
		r:       r,
		burst:   burst,
	}
	// Periodic cleanup of stale clients to avoid unbounded memory growth
	go func() {
		ticker := time.NewTicker(2 * time.Minute)
		defer ticker.Stop()
		for range ticker.C {
			rl.cleanup(5 * time.Minute)
		}
	}()
	return rl
}

func (l *ipRateLimiter) get(ip string) *rate.Limiter {
	l.mu.Lock()
	defer l.mu.Unlock()
	cl, ok := l.clients[ip]
	if !ok {
		cl = &clientLimiter{
			limiter:  rate.NewLimiter(l.r, l.burst),
			lastSeen: time.Now(),
		}
		l.clients[ip] = cl
	} else {
		cl.lastSeen = time.Now()
	}
	return cl.limiter
}

func (l *ipRateLimiter) cleanup(stale time.Duration) {
	now := time.Now()
	l.mu.Lock()
	defer l.mu.Unlock()
	for ip, cl := range l.clients {
		if now.Sub(cl.lastSeen) > stale {
			delete(l.clients, ip)
		}
	}
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For, then X-Real-IP, then RemoteAddr
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	if xr := r.Header.Get("X-Real-IP"); xr != "" {
		return xr
	}
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err == nil && host != "" {
		return host
	}
	return r.RemoteAddr
}

func main() {
	upstreamStr := os.Getenv("UPSTREAM_URL")
	if upstreamStr == "" {
		log.Fatal("UPSTREAM_URL environment variable is required, e.g. https://example.com")
	}
	upstream, err := url.Parse(upstreamStr)
	if err != nil {
		log.Fatalf("invalid UPSTREAM_URL: %v", err)
	}

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	// 10 requests per minute per IP (token bucket with burst of 10)
	rl := newIPRateLimiter(rate.Limit(10.0/60.0), 10)

	proxy := httputil.NewSingleHostReverseProxy(upstream)

	// Ensure Host header is set to upstream's host
	origDirector := proxy.Director
	proxy.Director = func(r *http.Request) {
		origDirector(r)
		r.Host = upstream.Host
	}

	// Reasonable transport timeouts
	proxy.Transport = &http.Transport{
		Proxy:                 http.ProxyFromEnvironment,
		MaxIdleConns:          100,
		IdleConnTimeout:       90 * time.Second,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		log.Printf("proxy error: %v", err)
		http.Error(w, "Bad Gateway", http.StatusBadGateway)
	}

	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			w.Header().Set("Allow", http.MethodGet)
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}

		ip := clientIP(r)
		lim := rl.get(ip)
		if !lim.Allow() {
			// Optionally provide Retry-After hint
			if res := lim.Reserve(); res.OK() {
				delay := res.Delay()
				res.Cancel() // do not actually reserve a token
				seconds := int(math.Ceil(delay.Seconds()))
				if seconds < 1 {
					seconds = 1
				}
				w.Header().Set("Retry-After", strconv.Itoa(seconds))
			}
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		proxy.ServeHTTP(w, r)
	})

	srv := &http.Server{
		Addr:         ":" + port,
		Handler:      handler,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 60 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Printf("Proxy listening on :%s -> %s (GET only, 10 req/min/IP)", port, upstream)
	if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatal(err)
	}
}
```

Usage:
- Requires Go 1.20+.
- Set UPSTREAM_URL to the base URL to proxy to (e.g., https://httpbin.org).
- Optional: set PORT (default 8080).
- Run:
