Here’s a simple, fast Python command-line tool that checks ports in parallel and reports which are open or closed.

```python
#!/usr/bin/env python3
import argparse
import asyncio
from typing import List, Set

def parse_ports(port_args: List[str]) -> List[int]:
    """
    Parse ports from arguments.
    Supports:
      - space-separated numbers: 80 443
      - comma lists: 80,443,8080
      - ranges: 20-25
      - combinations: 20-25,80 443
    """
    ports: Set[int] = set()
    for arg in port_args:
        for chunk in arg.split(","):
            chunk = chunk.strip()
            if not chunk:
                continue
            if "-" in chunk:
                try:
                    start_s, end_s = chunk.split("-", 1)
                    start = int(start_s)
                    end = int(end_s)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port range: {chunk}")
                if start < 1 or end > 65535 or start > end:
                    raise argparse.ArgumentTypeError(f"Invalid port range: {chunk}")
                ports.update(range(start, end + 1))
            else:
                try:
                    p = int(chunk)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port: {chunk}")
                if p < 1 or p > 65535:
                    raise argparse.ArgumentTypeError(f"Invalid port: {chunk}")
                ports.add(p)
    if not ports:
        raise argparse.ArgumentTypeError("No valid ports provided")
    return sorted(ports)

async def check_port(host: str, port: int, timeout: float, sem: asyncio.Semaphore) -> tuple[int, bool]:
    """
    Try to open a TCP connection to host:port.
    Returns (port, True) if open, (port, False) otherwise.
    """
    async with sem:
        try:
            conn = asyncio.open_connection(host=host, port=port)
            reader, writer = await asyncio.wait_for(conn, timeout=timeout)
            try:
                writer.close()
                # Not all Python versions require/offer wait_closed; guard it.
                if hasattr(writer, "wait_closed"):
                    await writer.wait_closed()
            except Exception:
                pass
            return port, True
        except Exception:
            return port, False

async def run_scan(host: str, ports: List[int], timeout: float, concurrency: int) -> List[tuple[int, bool]]:
    sem = asyncio.Semaphore(concurrency)
    tasks = [asyncio.create_task(check_port(host, p, timeout, sem)) for p in ports]
    results = await asyncio.gather(*tasks)
    # Sort results by port number
    return sorted(results, key=lambda x: x[0])

def main():
    ap = argparse.ArgumentParser(description="Parallel TCP port checker")
    ap.add_argument("host", help="Hostname or IP to scan")
    ap.add_argument("ports", nargs="+", help="Ports to check (e.g., 80 443 or 20-25,80,443)")
    ap.add_argument("-t", "--timeout", type=float, default=1.5, help="Per-port timeout in seconds (default: 1.5)")
    ap.add_argument("-c", "--concurrency", type=int, default=200, help="Max concurrent checks (default: 200)")
    args = ap.parse_args()

    try:
        ports = parse_ports(args.ports)
    except argparse.ArgumentTypeError as e:
        ap.error(str(e))
        return

    try:
        results = asyncio.run(run_scan(args.host, ports, args.timeout, args.concurrency))
    except KeyboardInterrupt:
        print("Interrupted.")
        return

    # Print results
    open_ports = [p for p, is_open in results if is_open]
    closed_ports = [p for p, is_open in results if not is_open]

    for p in results:
        port, is_open = p
        print(f"{port}: {'open' if is_open else 'closed'}")

    # Optional summary lines
    if open_ports:
        print(f"Open ports: {', '.join(map(str, open_ports))}")
    if closed_ports:
        print(f"Closed ports: {', '.join(map(str, closed_ports))}")

if __name__ == "__main__":
    main()
```

