                if start < MIN_PORT or end > MAX_PORT:
                    raise ValueError(f"Port out of range (1-65535): {part}")
                for p in range(start, end + 1):
                    ports.add(p)
            else:
                try:
                    p = int(part)
                except ValueError:
                    raise ValueError(f"Invalid port: {part}")
                if p < MIN_PORT or p > MAX_PORT:
                    raise ValueError(f"Port out of range (1-65535): {p}")
                ports.add(p)
    if not ports:
        raise ValueError("No valid ports provided.")
    return sorted(ports)

async def check_port(host, port, timeout, sem):
    async with sem:
        try:
            reader, writer = await asyncio.wait_for(
                asyncio.open_connection(host, port),
                timeout=timeout,
            )
            writer.close()
            try:
                await writer.wait_closed()
            except Exception:
                pass
            return port, True
        except Exception:
            return port, False

async def run_scan(host, ports, timeout, concurrency):
    sem = asyncio.Semaphore(concurrency)
    tasks = [asyncio.create_task(check_port(host, p, timeout, sem)) for p in ports]
    results = await asyncio.gather(*tasks)
    return dict(results)

def main():
    parser = argparse.ArgumentParser(
        description="Check which TCP ports are open on a host (in parallel)."
    )
    parser.add_argument("host", help="Hostname or IP address to scan")
    parser.add_argument(
        "ports",
        nargs="+",
        help="Ports to scan (e.g. 80 443 22-25 53,110,8080-8082)",
    )
    parser.add_argument(
        "-t", "--timeout",
        type=float,
        default=1.5,
        help="Connection timeout in seconds (default: 1.5)",
    )
    parser.add_argument(
        "-c", "--concurrency",
        type=int,
        default=None,
        help="Max parallel connections (default: min(512, number of ports))",
    )

    args = parser.parse_args()

    try:
        ports = parse_ports(args.ports)
    except ValueError as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(2)

    concurrency = args.concurrency or min(512, len(ports))
    if concurrency < 1:
        concurrency = 1

    try:
        results = asyncio.run(run_scan(args.host, ports, args.timeout, concurrency))
    except Exception as e:
        print(f"Scan error: {e}", file=sys.stderr)
        sys.exit(2)

    for p in ports:
        status = "OPEN" if results.get(p) else "CLOSED"
        print(f"{args.host}:{p} {status}")

if __name__ == "__main__":
    main()
