Here’s a simple Python command-line tool that scans a hostname’s TCP ports in parallel and reports which are open or closed.

```python
#!/usr/bin/env python3
import argparse
import asyncio
import socket
import sys
from typing import Tuple, Optional, List

async def check_port(host: str, port: int, timeout: float) -> Tuple[int, bool]:
    try:
        conn = asyncio.open_connection(host=host, port=port)
        reader, writer = await asyncio.wait_for(conn, timeout=timeout)
        writer.close()
        try:
            await writer.wait_closed()
        except Exception:
            pass
        return port, True
    except (asyncio.TimeoutError, ConnectionRefusedError, OSError):
        # Treat timeouts and connection errors as "closed" for this tool
        return port, False

async def run_scans(host: str, ports: List[int], timeout: float, concurrency: int) -> List[Tuple[int, bool]]:
    sem = asyncio.Semaphore(concurrency)

    async def bounded(port: int):
        async with sem:
            return await check_port(host, port, timeout)

    tasks = [asyncio.create_task(bounded(p)) for p in ports]
    try:
        results = await asyncio.gather(*tasks)
        return results
    except asyncio.CancelledError:
        for t in tasks:
            t.cancel()
        raise

def parse_args():
    parser = argparse.ArgumentParser(
        description="Parallel TCP port scanner: prints which ports are open or closed."
    )
    parser.add_argument("host", help="Hostname or IP to scan")
    parser.add_argument("ports", nargs="+", help="List of TCP ports to scan (e.g., 22 80 443)")
    parser.add_argument("-t", "--timeout", type=float, default=2.0, help="Per-port timeout in seconds (default: 2.0)")
    parser.add_argument("-j", "--jobs", type=int, default=200, help="Max concurrent connections (default: 200)")
    return parser.parse_args()

def validate_ports(ports_raw: List[str]) -> List[int]:
    ports = []
    for p in ports_raw:
        try:
            val = int(p)
        except ValueError:
            print(f"Invalid port: {p}", file=sys.stderr)
            sys.exit(2)
        if not (1 <= val <= 65535):
            print(f"Port out of range (1-65535): {val}", file=sys.stderr)
            sys.exit(2)
        ports.append(val)
    return ports

def main():
    args = parse_args()
    ports = validate_ports(args.ports)

    # Resolve hostname early to provide fast feedback on bad hostnames
    try:
        socket.getaddrinfo(args.host, None, proto=socket.IPPROTO_TCP)
    except socket.gaierror as e:
        print(f"Error: cannot resolve hostname '{args.host}': {e}", file=sys.stderr)
        sys.exit(2)

    concurrency = max(1, min(args.jobs, len(ports)))

    try:
        results = asyncio.run(run_scans(args.host, ports, args.timeout, concurrency))
    except KeyboardInterrupt:
        print("\nScan interrupted.", file=sys.stderr)
        sys.exit(130)

    open_ports = [p for p, is_open in results if is_open]
    closed_ports = [p for p, is_open in results if not is_open]

    # Print results
    if open_ports:
        print("Open ports:")
        for p in sorted(open_ports):
            print(f"- {p}")
    else:
        print("Open ports: none")

    if closed_ports:
        print("Closed ports:")
        for p in sorted(closed_ports):
            print(f"- {p}")
    else:
        print("Closed ports: none")

if __name__ == "__main__":
    main()
```

