- Optional flags: --timeout 1.5 and --jobs 500 to control per-port timeout and concurrency.

Here is a simple Python command-line tool that computes the total size of all files in a directory (recursively) and prints it in human-readable form.

```python
#!/usr/bin/env python3
import os
import sys
import argparse

def human_readable_size(size_bytes: int) -> str:
    if size_bytes < 1024:
        return f"{size_bytes} B"
    units = ["KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB"]
    val = float(size_bytes)
    for unit in units:
        val /= 1024.0
        if val < 1024.0:
            return f"{val:.2f} {unit}"
    return f"{val:.2f} YB"  # Fallback, extremely large values

def total_size_bytes(root: str) -> int:
    total = 0
    stack = [root]

    while stack:
        current = stack.pop()
        try:
            with os.scandir(current) as it:
                for entry in it:
                    try:
                        if entry.is_file(follow_symlinks=False):
                            try:
                                total += entry.stat(follow_symlinks=False).st_size
                            except OSError as e:
                                print(f"Warning: cannot stat file: {entry.path}: {e}", file=sys.stderr)
                        elif entry.is_dir(follow_symlinks=False):
                            stack.append(entry.path)
                        # Ignore other types (symlinks, sockets, etc.)
                    except OSError as e:
                        print(f"Warning: cannot access entry: {entry.path}: {e}", file=sys.stderr)
        except OSError as e:
            print(f"Warning: cannot access directory: {current}: {e}", file=sys.stderr)

    return total

def main():
    parser = argparse.ArgumentParser(
        description="Print total size of all files in a directory (recursively), in human-readable form."
    )
    parser.add_argument("directory", help="Path to the directory to scan")
    args = parser.parse_args()

    dir_path = os.path.abspath(args.directory)

    if not os.path.exists(dir_path):
        print(f"Error: path does not exist: {dir_path}", file=sys.stderr)
        sys.exit(1)
    if not os.path.isdir(dir_path):
        print(f"Error: not a directory: {dir_path}", file=sys.stderr)
        sys.exit(1)

    total = total_size_bytes(dir_path)
    print(human_readable_size(total))

if __name__ == "__main__":
    main()
