Here’s a simple Python command-line tool that sums the sizes of all files in a directory (recursively) and prints the total in human-readable form.

```python
#!/usr/bin/env python3
import argparse
import os
import sys
from typing import Tuple, Set

def format_size(num_bytes: int) -> str:
    # Binary (IEC) units
    units = ["B", "KiB", "MiB", "GiB", "TiB", "PiB", "EiB"]
    size = float(num_bytes)
    for i, unit in enumerate(units):
        if size < 1024.0 or i == len(units) - 1:
            if unit == "B":
                return f"{int(size)} {unit}"
            # Show up to 2 decimals, strip trailing zeros
            s = f"{size:.2f}".rstrip("0").rstrip(".")
            return f"{s} {unit}"
        size /= 1024.0
    return f"{int(num_bytes)} B"  # Fallback (shouldn't hit)

def total_size_bytes(root: str) -> int:
    total = 0
    seen: Set[Tuple[int, int]] = set()  # (st_dev, st_ino) to avoid double-counting hard links
    stack = [root]

    while stack:
        current = stack.pop()
        try:
            with os.scandir(current) as it:
                for entry in it:
                    try:
                        if entry.is_dir(follow_symlinks=False):
                            stack.append(entry.path)
                        else:
                            # Use lstat (follow_symlinks=False) to avoid following symlinks
                            try:
                                st = entry.stat(follow_symlinks=False)
                            except FileNotFoundError:
                                # The file may have disappeared between listing and stat
                                continue
                            key = (getattr(st, "st_dev", 0), getattr(st, "st_ino", 0))
                            if key not in seen:
                                seen.add(key)
                                total += st.st_size
                    except PermissionError:
                        # Skip entries we cannot access
                        continue
                    except OSError:
                        # Skip problematic entries (e.g., broken reparse points)
                        continue
        except PermissionError:
            continue
        except FileNotFoundError:
            continue
        except NotADirectoryError:
            # In case the root changes under us (rare), skip
            continue
        except OSError:
            continue

    return total

def main() -> None:
    parser = argparse.ArgumentParser(
        description="Print total size of all files in a directory (recursively) in human-readable form."
    )
    parser.add_argument("directory", help="Path to the directory to scan")
    args = parser.parse_args()

    dir_path = args.directory
    if not os.path.isdir(dir_path):
        print(f"Error: '{dir_path}' is not a directory or cannot be accessed.", file=sys.stderr)
        sys.exit(1)

    total = total_size_bytes(dir_path)
    print(format_size(total))

if __name__ == "__main__":
    main()
```

