Here’s a simple Python command-line tool that prints the total size of all files inside a directory (recursively) in human-readable form.

```python
#!/usr/bin/env python3
import argparse
import os
import sys

def human_readable_size(num_bytes: int, base: int = 1024) -> str:
    units = ["B", "KB", "MB", "GB", "TB", "PB", "EB"]
    size = float(num_bytes)
    for unit in units:
        if size < base or unit == units[-1]:
            if unit == "B":
                return f"{int(size)} {unit}"
            else:
                return f"{size:.1f} {unit}"
        size /= base

def total_size_bytes(root: str) -> int:
    # Sum sizes of files only, recursively. Do not follow symlinks.
    # Avoid double-counting hard-linked files by tracking (st_dev, st_ino).
    total = 0
    seen_inodes = set()

    stack = [root]
    while stack:
        current = stack.pop()
        try:
            with os.scandir(current) as it:
                for entry in it:
                    try:
                        if entry.is_symlink():
                            continue
                        if entry.is_dir(follow_symlinks=False):
                            stack.append(entry.path)
                        elif entry.is_file(follow_symlinks=False):
                            try:
                                st = entry.stat(follow_symlinks=False)
                            except (FileNotFoundError, PermissionError, OSError):
                                continue
                            key = None
                            # Deduplicate by inode where available
                            st_dev = getattr(st, "st_dev", None)
                            st_ino = getattr(st, "st_ino", None)
                            if st_dev is not None and st_ino is not None:
                                key = (st_dev, st_ino)
                            if key is not None:
                                if key in seen_inodes:
                                    continue
                                seen_inodes.add(key)
                            total += st.st_size
                        else:
                            # Non-regular, non-dir entry (e.g., sockets, FIFOs): skip
                            continue
                    except (PermissionError, FileNotFoundError, OSError):
                        # Skip entries we can't access
                        continue
        except (PermissionError, FileNotFoundError, OSError):
            # Skip directories we can't open
            continue
    return total

def main():
    parser = argparse.ArgumentParser(
        description="Print the total size of all files in a directory (recursively) in human-readable form."
    )
    parser.add_argument("directory", help="Path to the directory to scan")
    args = parser.parse_args()

    dir_path = args.directory

    if not os.path.exists(dir_path):
        print(f"Error: path does not exist: {dir_path}", file=sys.stderr)
        sys.exit(2)
    if not os.path.isdir(dir_path):
        print(f"Error: not a directory: {dir_path}", file=sys.stderr)
        sys.exit(2)

    total = total_size_bytes(dir_path)
    print(human_readable_size(total))

if __name__ == "__main__":
    main()
```

