Here’s a simple Python command-line tool that prints the total size of all files inside a directory (recursively) in human-readable form.

```python
#!/usr/bin/env python3
import argparse
import os
import sys

def format_size(nbytes: int) -> str:
    # Human-readable (binary, IEC units)
    if nbytes < 1024:
        return f"{nbytes} B"
    units = ["KiB", "MiB", "GiB", "TiB", "PiB", "EiB"]
    size = float(nbytes)
    for unit in units:
        size /= 1024.0
        if size < 1024.0:
            return f"{size:.2f} {unit}"
    return f"{size:.2f} ZiB"

def total_size_bytes(root: str) -> int:
    total = 0
    stack = [root]
    seen_inodes = set()  # avoid double-counting hard links (POSIX)
    while stack:
        current = stack.pop()
        try:
            with os.scandir(current) as it:
                for entry in it:
                    try:
                        # Skip all symlinks (both files and directories)
                        if entry.is_symlink():
                            continue
                        if entry.is_file(follow_symlinks=False):
                            try:
                                st = entry.stat(follow_symlinks=False)
                            except OSError:
                                continue
                            # Avoid double-counting hard links
                            key = getattr(st, "st_ino", None), getattr(st, "st_dev", None)
                            if key[0] is not None and key not in seen_inodes:
                                seen_inodes.add(key)
                                total += st.st_size
                            elif key[0] is None:
                                # Fallback if inode/dev not available (e.g., some Windows setups)
                                total += st.st_size
                        elif entry.is_dir(follow_symlinks=False):
                            stack.append(entry.path)
                        # Ignore other special file types (sockets, fifos, devices)
                    except OSError:
                        # Cannot access this entry; skip
                        continue
        except OSError:
            # Cannot open this directory; skip
            continue
    return total

def main():
    parser = argparse.ArgumentParser(
        description="Print the total size of all files in a directory (recursively) in human-readable form."
    )
    parser.add_argument("directory", help="Path to the directory to scan")
    args = parser.parse_args()

    dirpath = os.path.abspath(args.directory)
    if not os.path.exists(dirpath):
        print(f"Error: path does not exist: {dirpath}", file=sys.stderr)
        sys.exit(1)
    if not os.path.isdir(dirpath):
        print(f"Error: not a directory: {dirpath}", file=sys.stderr)
        sys.exit(1)

    total = total_size_bytes(dirpath)
    print(format_size(total))

if __name__ == "__main__":
    main()
```

