```js
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'counter.json');

// Load persisted value (or default to 0)
function loadCounter() {
  try {
    if (fs.existsSync(DATA_FILE)) {
      const raw = fs.readFileSync(DATA_FILE, 'utf8');
      const parsed = JSON.parse(raw);
      if (typeof parsed.value === 'number' && Number.isFinite(parsed.value)) {
        return parsed.value;
      }
    }
  } catch (e) {
    console.error('Failed to read counter.json:', e);
  }
  return 0;
}

// Save value to disk
function saveCounter(value) {
  try {
    fs.writeFileSync(
      DATA_FILE,
      JSON.stringify({ value, updatedAt: new Date().toISOString() }, null, 2),
      'utf8'
    );
  } catch (e) {
    console.error('Failed to write counter.json:', e);
  }
}

let counter = loadCounter();

app.use(express.static(path.join(__dirname, 'public')));

app.get('/api/counter', (req, res) => {
  res.json({ value: counter });
});

app.post('/api/increment', (req, res) => {
  counter += 1;
  saveCounter(counter);
  res.json({ value: counter });
});

app.post('/api/decrement', (req, res) => {
  counter -= 1;
  saveCounter(counter);
  res.json({ value: counter });
});

app.listen(PORT, () => {
  console.log(`Shared counter running at http://localhost:${PORT}`);
});
```

