const TMP_FILE = path.join(DATA_DIR, 'counter.json.tmp');

fs.mkdirSync(DATA_DIR, { recursive: true });

let state = { value: 0 };

function persist() {
  const json = JSON.stringify(state);
  fs.writeFileSync(TMP_FILE, json);
  fs.renameSync(TMP_FILE, COUNTER_FILE);
}

function load() {
  try {
    const raw = fs.readFileSync(COUNTER_FILE, 'utf8');
    const data = JSON.parse(raw);
    if (typeof data.value === 'number' && isFinite(data.value)) {
      state.value = Math.floor(data.value);
      return;
