Here’s a minimal self-contained web app (no dependencies) that serves a shared counter with +/− and persists it to disk.

```javascript
// server.js
// Simple shared counter web app with persistence (no external dependencies)

const http = require('http');
const fs = require('fs');
const path = require('path');
const url = require('url');

const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'counter.json');

function loadCounter() {
  try {
    const raw = fs.readFileSync(DATA_FILE, 'utf8');
    const parsed = JSON.parse(raw);
    const n = Number(parsed && parsed.value);
    return Number.isSafeInteger(n) ? n : 0;
  } catch {
    return 0;
  }
}

function saveCounterSync(value) {
  const payload = JSON.stringify({ value }, null, 2);
  fs.writeFileSync(DATA_FILE, payload, 'utf8');
}

let counter = loadCounter();
saveCounterSync(counter); // ensure file exists

function sendJSON(res, status, obj) {
  const body = JSON.stringify(obj);
  res.writeHead(status, {
    'Content-Type': 'application/json; charset=utf-8',
    'Content-Length': Buffer.byteLength(body),
    'Cache-Control': 'no-store',
  });
  res.end(body);
}

function sendHTML(res, html) {
  res.writeHead(200, {
    'Content-Type': 'text/html; charset=utf-8',
    'Content-Length': Buffer.byteLength(html),
    'Cache-Control': 'no-store',
  });
  res.end(html);
}

function notFound(res) {
  res.writeHead(404, { 'Content-Type': 'text/plain; charset=utf-8' });
  res.end('Not found');
}

function methodNotAllowed(res) {
  res.writeHead(405, { 'Content-Type': 'text/plain; charset=utf-8' });
  res.end('Method not allowed');
}

const INDEX_HTML = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Shared Counter</title>
<style>
