  body { font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; margin: 0; display: grid; place-items: center; min-height: 100vh; background: #f7f7f8; }
  .card { background: white; color: #111; border-radius: 12px; padding: 24px; box-shadow: 0 6px 24px rgba(0,0,0,.08); min-width: 280px; }
  @media (prefers-color-scheme: dark) { body { background: #0b0c0e; } .card { background: #15171a; color: #eaeaea; box-shadow: 0 6px 24px rgba(0,0,0,.35); } .muted { color: #9aa3af; } button { color: inherit; } }
  h1 { font-size: 20px; margin: 0 0 12px 0; }
  .value { font-size: 64px; font-weight: 700; text-align: center; margin: 12px 0 20px; font-variant-numeric: tabular-nums; }
  .row { display: flex; gap: 12px; justify-content: center; }
  button { font-size: 20px; padding: 10px 16px; border-radius: 10px; border: 1px solid #d0d7de; background: #fff; cursor: pointer; min-width: 56px; }
  button:hover { background: #f1f5f9; }
  button:disabled { opacity: 0.6; cursor: not-allowed; }
  .muted { font-size: 12px; text-align: center; margin-top: 10px; color: #6b7280; }
</style>
</head>
<body>
  <div class="card">
    <h1>Shared Counter</h1>
    <div id="value" class="value">…</div>
    <div class="row">
      <button id="dec" aria-label="Decrement">−</button>
      <button id="inc" aria-label="Increment">+</button>
    </div>
    <div class="muted">Updates are persisted on the server and shared across viewers.</div>
  </div>
<script>
  const valueEl = document.getElementById('value');
  const incBtn = document.getElementById('inc');
  const decBtn = document.getElementById('dec');

  async function fetchValue(signal) {
    const r = await fetch('/api/counter', { cache: 'no-store', signal });
    if (!r.ok) throw new Error('Failed to fetch value');
    const j = await r.json();
    return j.value;
  }

  function setBusy(b) {
    incBtn.disabled = b;
    decBtn.disabled = b;
  }

  async function refresh() {
    try {
      const v = await fetchValue();
      valueEl.textContent = v;
    } catch (e) {
      console.error(e);
    }
  }

  async function post(path) {
    setBusy(true);
    try {
      const r = await fetch(path, { method: 'POST' });
      if (!r.ok) throw new Error('Request failed');
      const j = await r.json();
      valueEl.textContent = j.value;
    } catch (e) {
      console.error(e);
      // fall back to full refresh
      await refresh();
    } finally {
      setBusy(false);
    }
  }

  incBtn.addEventListener('click', () => post('/api/increment'));
  decBtn.addEventListener('click', () => post('/api/decrement'));

  // Initial load
  refresh();

  // Poll periodically to pick up changes from other viewers
  setInterval(refresh, 2000);
</script>
