const server = http.createServer((req, res) => {
  const { pathname } = url.parse(req.url, true);

  // Basic routing
  if (req.method === 'GET' && (pathname === '/' || pathname === '/index.html')) {
    return sendHTML(res, INDEX_HTML);
  }

  if (req.method === 'GET' && pathname === '/api/counter') {
    return sendJSON(res, 200, { value: counter });
  }

  if (req.method === 'POST' && pathname === '/api/increment') {
    counter += 1;
    try { saveCounterSync(counter); } catch (e) { console.error('Save failed:', e); }
    return sendJSON(res, 200, { value: counter });
  }

  if (req.method === 'POST' && pathname === '/api/decrement') {
    counter -= 1;
    try { saveCounterSync(counter); } catch (e) { console.error('Save failed:', e); }
    return sendJSON(res, 200, { value: counter });
  }

  if (req.method === 'GET' && pathname === '/favicon.ico') {
    res.writeHead(204); // no content
    return res.end();
  }

  // Method not allowed for known endpoints
  if (pathname === '/api/counter' || pathname === '/api/increment' || pathname === '/api/decrement') {
    return methodNotAllowed(res);
  }

  return notFound(res);
});

server.listen(PORT, () => {
  console.log(`Shared counter running at http://localhost:${PORT}`);
});
```

