```js
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'counter.json');

// Load persisted value (default 0)
let value = 0;
try {
  const raw = fs.readFileSync(DATA_FILE, 'utf8');
  const parsed = JSON.parse(raw);
  if (typeof parsed.value === 'number' && Number.isFinite(parsed.value)) {
    value = parsed.value;
  }
} catch (_) {
  // no file yet or parse error; start at 0
}

function save() {
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify({ value }), 'utf8');
  } catch (e) {
    console.error('Failed to save counter:', e);
  }
}

app.use(express.static(path.join(__dirname, 'public')));

// API: get current value
app.get('/api/value', (req, res) => {
  res.set('Cache-Control', 'no-store');
  res.json({ value });
});

// API: increment
app.post('/api/inc', (req, res) => {
  value += 1;
  save();
  res.set('Cache-Control', 'no-store');
  res.json({ value });
});

// API: decrement
app.post('/api/dec', (req, res) => {
  value -= 1;
  save();
  res.set('Cache-Control', 'no-store');
  res.json({ value });
});

app.listen(PORT, () => {
  console.log(`Shared counter running at http://localhost:${PORT}`);
});
