// server.js
const express = require('express');
const fs = require('fs').promises;
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'counter.json');
let counter = 0;

// Disable caching so clients always see fresh values
app.use((req, res, next) => {
  res.set('Cache-Control', 'no-store');
  next();
});

// Load counter from disk on startup
async function loadCounter() {
  try {
    const data = await fs.readFile(DATA_FILE, 'utf8');
    const obj = JSON.parse(data);
    if (typeof obj.value === 'number') counter = obj.value;
  } catch (err) {
    if (err.code !== 'ENOENT') {
      console.error('Error reading counter.json:', err);
    }
  }
}

// Save counter to disk (atomic write)
async function saveCounter() {
  const tmp = DATA_FILE + '.tmp';
  const data = JSON.stringify({ value: counter });
  await fs.writeFile(tmp, data, 'utf8');
  await fs.rename(tmp, DATA_FILE);
}

