  <strong>Minimal Chat</strong>
  <span id="room">/room</span>
</header>
<div id="log" aria-live="polite"></div>
<form id="form" autocomplete="off">
  <input id="input" type="text" placeholder="Type a message and press Enter…" maxlength="1000" required />
  <button id="send" type="submit">Send</button>
</form>
<script>
(() => {
  const log = document.getElementById('log');
  const form = document.getElementById('form');
  const input = document.getElementById('input');
  const sendBtn = document.getElementById('send');
  const statusDot = document.getElementById('status');

  function setStatus(ok) {
    statusDot.style.background = ok ? '#1cc66e' : '#f55';
    sendBtn.disabled = !ok;
  }

  function line(text, cls) {
    const div = document.createElement('div');
    div.className = cls || 'msg';
    div.textContent = text;
    log.appendChild(div);
    if (log.scrollHeight - log.scrollTop - log.clientHeight < 40) {
      log.scrollTop = log.scrollHeight;
    }
  }

  function renderMessage(obj) {
    const row = document.createElement('div');
    row.className = 'msg';
    const t = document.createElement('span');
    t.className = 'time';
    t.textContent = new Date(obj.t).toLocaleTimeString();
    const m = document.createElement('span');
    m.textContent = obj.m; // safe: textContent escapes HTML
    row.appendChild(t);
    row.appendChild(m);
    log.appendChild(row);
    log.scrollTop = log.scrollHeight;
  }

  const proto = location.protocol === 'https:' ? 'wss' : 'ws';
  const ws = new WebSocket(proto + '://' + location.host);
  let open = false;

  ws.addEventListener('open', () => { open = true; setStatus(true); line('Connected', 'sys'); });
  ws.addEventListener('close', () => { open = false; setStatus(false); line('Disconnected', 'sys'); });
  ws.addEventListener('error', () => { open = false; setStatus(false); line('Connection error', 'sys'); });
  ws.addEventListener('message', (ev) => {
    try {
      const obj = JSON.parse(ev.data);
      if (obj && typeof obj.m === 'string' && typeof obj.t === 'number') {
        renderMessage(obj);
      }
    } catch {}
  });

  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const text = (input.value || '').trim();
    if (!text || !open) return;
    ws.send(text);
    input.value = '';
    input.focus();
  });

  // focus input on load
  setTimeout(() => input.focus(), 50);
})();
</script>
`;

const server = http.createServer((req, res) => {
  if (req.method === 'GET' && (req.url === '/' || req.url.startsWith('/?'))) {
    res.writeHead(200, { 'content-type': 'text/html; charset=utf-8' });
    res.end(html);
  } else if (req.method === 'GET' && req.url === '/favicon.ico') {
    res.writeHead(204).end();
  } else {
    res.writeHead(404).end('Not found');
  }
});

const wss = new WebSocketServer({ server });
wss.on('connection', (ws) => {
  ws.on('message', (data) => {
    let msg = '';
    try {
      msg = data.toString('utf8').trim();
    } catch {}
    if (!msg) return;
    if (msg.length > 1000) msg = msg.slice(0, 1000);
    const payload = JSON.stringify({ m: msg, t: Date.now() });
    for (const client of wss.clients) {
      if (client.readyState === 1) client.send(payload);
    }
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log('Chat running on http://localhost:' + PORT);
});
