    <input id="text" placeholder="Type a message and press Enter" required maxlength="500">
    <button type="submit">Send</button>
  </form>
</div>
<script>
  // Simple unique client id persisted locally
  const cid = localStorage.getItem('cid') || (crypto.randomUUID ? crypto.randomUUID() : String(Math.random()).slice(2));
  localStorage.setItem('cid', cid);

  const qs = sel => document.querySelector(sel);
  const msgs = qs('#msgs');
  const form = qs('#chat');
  const inputText = qs('#text');
  const inputName = qs('#name');

  // Load stored name if any
  inputName.value = localStorage.getItem('name') || '';
  inputName.addEventListener('change', () => localStorage.setItem('name', inputName.value.trim()));

  function atBottom() {
    return msgs.scrollTop + msgs.clientHeight >= msgs.scrollHeight - 10;
  }
  function scrollToBottom() {
    msgs.scrollTop = msgs.scrollHeight;
  }
  function timeStr(ts) {
    const d = new Date(ts);
    return d.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
  }
  function addSystem(text) {
    const div = document.createElement('div');
    div.className = 'sys';
    div.textContent = text;
    msgs.appendChild(div);
    scrollToBottom();
  }
  function addMessage(m) {
    const mine = m.cid === cid;
    const row = document.createElement('div');
    row.className = 'msg' + (mine ? ' me' : '');
    const meta = document.createElement('div');
    meta.className = 'meta';
    meta.textContent = (m.name || 'Anon') + ' • ' + timeStr(m.ts);
    const bubble = document.createElement('div');
    bubble.className = 'bubble';
    bubble.textContent = m.text; // safe via textContent
    row.append(meta, bubble);
    const shouldStick = atBottom();
    msgs.appendChild(row);
    if (shouldStick) scrollToBottom();
  }

  // Live stream via SSE
  const es = new EventSource('/events');
  es.onmessage = (e) => {
    try {
      const data = JSON.parse(e.data);
      if (data.type === 'msg') addMessage(data);
      else if (data.type === 'sys') addSystem(data.text);
    } catch {}
  };
  es.onerror = () => {
    addSystem('Disconnected… attempting to reconnect.');
  };

  // Send messages
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const text = inputText.value.trim();
    if (!text) return;
    const name = inputName.value.trim();
    try {
      await fetch('/send', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ text, name, cid })
      });
      inputText.value = '';
      inputText.focus();
    } catch (err) {
      addSystem('Failed to send: ' + (err && err.message ? err.message : err));
    }
  });

  // Focus message field on load
  inputText.focus();
</script>
`;

function sendEvent(res, evt) {
  // evt is a JS object; we send as one SSE message
  res.write(`data: ${JSON.stringify(evt)}\n\n`);
}

function broadcast(evt) {
  for (const res of clients) {
    try {
      sendEvent(res, evt);
    } catch {
      // ignore broken pipe; cleanup happens on 'close'
    }
  }
}

function handleEvents(req, res) {
  // SSE headers
  res.writeHead(200, {
    'Content-Type': 'text/event-stream; charset=utf-8',
    'Cache-Control': 'no-cache, no-transform',
    'Connection': 'keep-alive',
    'X-Accel-Buffering': 'no', // for nginx
  });
  res.write(': connected\n\n'); // initial comment
  clients.add(res);
  broadcast({ type: 'sys', text: 'A user joined.' });

  req.on('close', () => {
    clients.delete(res);
    broadcast({ type: 'sys', text: 'A user left.' });
  });
}

function readJson(req, limit = 1024 * 8) {
  return new Promise((resolve, reject) => {
    let size = 0;
    const chunks = [];
    req.on('data', (c) => {
      size += c.length;
      if (size > limit) {
        reject(Object.assign(new Error('Payload too large'), { code: 413 }));
        req.destroy();
        return;
      }
      chunks.push(c);
    });
    req.on('end', () => {
      try {
        const raw = Buffer.concat(chunks).toString('utf8');
        const obj = JSON.parse(raw || '{}');
        resolve(obj);
      } catch (e) {
        reject(Object.assign(new Error('Bad JSON'), { code: 400 }));
      }
    });
    req.on('error', reject);
  });
}

const server = http.createServer(async (req, res) => {
  const { pathname } = parse(req.url, true);

  // Serve the single page
  if (req.method === 'GET' && (pathname === '/' || pathname === '/index.html')) {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(html);
    return;
  }

  // Favicon noise
  if (req.method === 'GET' && pathname === '/favicon.ico') {
    res.writeHead(204).end();
    return;
  }

  // SSE endpoint
  if (req.method === 'GET' && pathname === '/events') {
    handleEvents(req, res);
    return;
  }

  // Send message
  if (req.method === 'POST' && pathname === '/send') {
    try {
      const { text, name, cid } = await readJson(req);
      const cleanText = typeof text === 'string' ? text.trim().slice(0, 500) : '';
      const cleanName = typeof name === 'string' ? name.trim().slice(0, 30) : '';
      const cleanCid = typeof cid === 'string' ? cid.slice(0, 100) : '';
      if (!cleanText) {
        res.writeHead(400, { 'Content-Type': 'text/plain' }).end('Message required');
        return;
      }
      const msg = { type: 'msg', text: cleanText, name: cleanName || 'Anon', cid: cleanCid, ts: Date.now() };
      broadcast(msg);
      res.writeHead(204).end();
    } catch (e) {
      const code = e && e.code ? e.code : 500;
      res.writeHead(code, { 'Content-Type': 'text/plain' }).end(e.message || 'Error');
    }
    return;
  }

  // 404
  res.writeHead(404, { 'Content-Type': 'text/plain' }).end('Not found');
});

// Heartbeat to keep connections alive through proxies
setInterval(() => {
  for (const res of clients) {
    try { res.write(': ping\\n\\n'); } catch {}
  }
}, 20000);

server.listen(PORT, () => {
  console.log('Chat running at http://localhost:' + PORT);
});
