      if (refill > 0) {
        tokens = Math.min(RATE_LIMIT.max, tokens + refill);
        lastRefill = now;
      }
    }
    if (tokens <= 0) return;
    tokens--;

    let text = '';
    try {
      const data = JSON.parse(msg.toString());
      if (data && data.type === 'chat' && typeof data.text === 'string') {
        text = data.text;
      } else {
        return;
      }
    } catch {
      // Fallback: accept plain text
      text = msg.toString();
    }
    text = text.slice(0, 2000).trim();
    if (!text) return;

    const payload = JSON.stringify({ type: 'chat', text, time: Date.now() });
    for (const client of wss.clients) {
      if (client.readyState === WebSocket.OPEN) client.send(payload);
    }
  });
});

server.listen(PORT, () => {
  console.log('Chat running on http://localhost:' + PORT);
});
```

Usage:
- Save as server.js
- Run: npm init -y && npm install ws
- Start: node server.js
- Open http://localhost:3000 in multiple tabs or devices to chat in real time.

