  <script src="https://cdn.jsdelivr.net/npm/dompurify@3/dist/purify.min.js"></script>
  <script>
    // Configure marked
    const renderer = new marked.Renderer();
    renderer.link = (href, title, text) => {
      const t = title ? ` title="${title.replace(/"/g, '&quot;')}"` : '';
      const safeHref = href || '';
      return `<a href="${safeHref}"${t} target="_blank" rel="noopener noreferrer">${text}</a>`;
    };

    marked.setOptions({
      gfm: true,
      breaks: true,
      headerIds: true,
      mangle: false,
      renderer
    });

    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const status = document.getElementById('status');

    function render() {
      const src = editor.value;
      const html = marked.parse(src);
      const clean = DOMPurify.sanitize(html, { USE_PROFILES: { html: true } });
      preview.innerHTML = clean;
      status.textContent = `${src.length} characters`;
    }

    // Render on input and on load
    editor.addEventListener('input', render, { passive: true });
    window.addEventListener('DOMContentLoaded', render);

    // Basic Ctrl/Cmd+Enter to focus preview
    editor.addEventListener('keydown', (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
        e.preventDefault();
        preview.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });
  </script>
</body>
</html>
```

Usage: Save this as index.html and open it in a browser. Type Markdown in the left pane; the right pane updates live. Note: it uses CDNs for marked and DOMPurify, so you need an internet connection for those libraries.

