Here’s a minimal, single-file Flask app that shortens URLs and redirects short links to their original targets.

```python
# app.py
import os
import sqlite3
from urllib.parse import urlparse, urljoin

from flask import (
    Flask, request, redirect, g, render_template_string, abort
)

app = Flask(__name__)
DB_PATH = os.path.join(os.path.dirname(__file__), "urls.db")

BASE62_ALPHABET = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"


def get_db():
    if "db" not in g:
        g.db = sqlite3.connect(DB_PATH)
        g.db.row_factory = sqlite3.Row
    return g.db


@app.teardown_appcontext
def close_db(exc):
    db = g.pop("db", None)
    if db is not None:
        db.close()


def init_db():
    db = get_db()
    db.execute(
        """
        CREATE TABLE IF NOT EXISTS urls (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            code TEXT UNIQUE,
            long_url TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            hits INTEGER DEFAULT 0
        )
        """
    )
    db.execute("CREATE INDEX IF NOT EXISTS idx_urls_long_url ON urls(long_url)")
    db.commit()


def base62_encode(n: int) -> str:
    if n == 0:
        return "0"
    out = []
    b = len(BASE62_ALPHABET)
    while n > 0:
        n, rem = divmod(n, b)
        out.append(BASE62_ALPHABET[rem])
    return "".join(reversed(out))


def normalize_url(u: str) -> str:
    u = (u or "").strip()
    if not u:
        return ""
    parsed = urlparse(u)
    if not parsed.scheme:
        # Default to https if no scheme provided
        u = "https://" + u
        parsed = urlparse(u)
    # Basic sanity: only allow http/https and a netloc present
    if parsed.scheme not in ("http", "https") or not parsed.netloc:
        return ""
    return u


INDEX_TEMPLATE = """
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Simple URL Shortener</title>
  <style>
    body { font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; margin: 2rem; }
    form { display: flex; gap: 0.5rem; max-width: 720px; }
    input[type="url"] { flex: 1; padding: 0.6rem; font-size: 1rem; }
    button { padding: 0.6rem 1rem; font-size: 1rem; cursor: pointer; }
    .result { margin-top: 1rem; padding: 0.8rem; background: #f4f7fb; border-radius: 6px; display: inline-block; }
    .error { color: #b00020; margin-top: 0.5rem; }
    .help { color: #666; margin-top: 1rem; }
  </style>
</head>
<body>
  <h1>Simple URL Shortener</h1>
  <form method="post" action="/">
    <input type="url" name="url" placeholder="https://example.com/very/long/url" required />
    <button type="submit">Shorten</button>
  </form>

  {% if error %}
    <div class="error">{{ error }}</div>
  {% endif %}

  {% if short_url %}
    <div class="result">
      Short link: <a href="{{ short_url }}" target="_blank" rel="noopener">{{ short_url }}</a>
    </div>
  {% endif %}

  <div class="help">
    Paste a long URL above, get a short link back. Visiting the short link redirects to the original URL.
  </div>
</body>
</html>
"""


@app.route("/", methods=["GET", "POST"])
def index():
    init_db()  # Safe to call repeatedly; creates tables if missing
    short_url = None
    error = None

    if request.method == "POST":
        raw = request.form.get("url", "")
        long_url = normalize_url(raw)
        if not long_url:
            error = "Please enter a valid http(s) URL."
        else:
            db = get_db()
            # Reuse existing code for the same long URL if present
            row = db.execute(
                "SELECT code FROM urls WHERE long_url = ? LIMIT 1", (long_url,)
            ).fetchone()
            if row:
                code = row["code"]
            else:
                # Create a new record to get an autoincrement ID
                cur = db.execute("INSERT INTO urls (long_url) VALUES (?)", (long_url,))
                new_id = cur.lastrowid
                code = base62_encode(new_id)
                db.execute("UPDATE urls SET code = ? WHERE id = ?", (code, new_id))
                db.commit()
            short_url = urljoin(request.url_root, code)

    return render_template_string(INDEX_TEMPLATE, short_url=short_url, error=error)


@app.route("/<string:code>")
def follow(code):
    init_db()
    db = get_db()
    row = db.execute("SELECT long_url FROM urls WHERE code = ? LIMIT 1", (code,)).fetchone()
    if not row:
        abort(404, description="Short link not found.")
    # Increment hit counter (best-effort)
    db.execute("UPDATE urls SET hits = hits + 1 WHERE code = ?", (code,))
    db.commit()
    return redirect(row["long_url"], code=302)


@app.errorhandler(404)
def not_found(e):
    return (
        "<h1>404 Not Found</h1><p>The requested short link does not exist.</p>",
        404,
        {"Content-Type": "text/html; charset=utf-8"},
    )


if __name__ == "__main__":
    # Run the development server
    app.run(host="0.0.0.0", port=8000, debug=True)
```

Usage:
- Requirements: Python 3.9+; install Flask with: pip install Flask
- Run: python app.py
- Open http://localhost:8000 in your browser, paste a long URL, and get a short link. Visiting that short link will redirect to the original URL.

