```python
# app.py
import os
import json
import string
import secrets
import threading
from urllib.parse import urlparse
from tempfile import NamedTemporaryFile

from flask import Flask, request, redirect, abort, render_template_string

app = Flask(__name__)

DATA_FILE = "urls.json"
DATA_LOCK = threading.Lock()

HTML_INDEX = """
<!doctype html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>Simple URL Shortener</title>
    <style>
      body { font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif; margin: 40px; }
      form { max-width: 600px; }
      input[type=text] { width: 100%; padding: 10px; font-size: 16px; }
      button { margin-top: 12px; padding: 10px 16px; font-size: 16px; }
      .msg { margin-top: 20px; font-size: 16px; }
      code { background: #f5f5f5; padding: 2px 4px; }
    </style>
  </head>
  <body>
    <h1>Simple URL Shortener</h1>
    <form action="/shorten" method="post">
      <label for="url">Long URL:</label><br/>
      <input id="url" name="url" type="text" placeholder="https://example.com/very/long/link" required />
      <br/>
      <button type="submit">Shorten</button>
    </form>
    {% if short_url %}
      <div class="msg">
        Short link: <a href="{{ short_url }}"><code>{{ short_url }}</code></a>
      </div>
    {% elif error %}
      <div class="msg" style="color:#b00020;">{{ error }}</div>
    {% endif %}
  </body>
</html>
"""

def load_data():
    if not os.path.exists(DATA_FILE):
        return {}
    with open(DATA_FILE, "r", encoding="utf-8") as f:
        try:
            return json.load(f)
        except json.JSONDecodeError:
            return {}

def save_data(data):
    tmp = NamedTemporaryFile("w", delete=False, encoding="utf-8", dir=".")
    try:
        json.dump(data, tmp, ensure_ascii=False, indent=2)
        tmp.flush()
        os.fsync(tmp.fileno())
        tmp.close()
        os.replace(tmp.name, DATA_FILE)
    finally:
        try:
            os.unlink(tmp.name)
        except FileNotFoundError:
            pass

ALPHABET = string.ascii_letters + string.digits

def generate_code(length=6):
    return "".join(secrets.choice(ALPHABET) for _ in range(length))

def normalize_url(raw):
    raw = raw.strip()
    if not raw:
        return None
    parsed = urlparse(raw)
    if not parsed.scheme:
        # Default to http if scheme missing
        raw = "http://" + raw
        parsed = urlparse(raw)
    if parsed.scheme not in ("http", "https"):
        return None
    if not parsed.netloc:
        return None
    return raw

@app.route("/", methods=["GET"])
def index():
    return render_template_string(HTML_INDEX)

@app.route("/shorten", methods=["POST"])
def shorten():
    raw_url = request.form.get("url", "")
    long_url = normalize_url(raw_url)
    if not long_url:
        return render_template_string(HTML_INDEX, error="Please enter a valid http or https URL."), 400

    with DATA_LOCK:
        data = load_data()

        # Reuse existing code if URL already shortened
        for code, url in data.items():
            if url == long_url:
                short_url = request.host_url + code
                return render_template_string(HTML_INDEX, short_url=short_url)

        # Generate unique code
        code = generate_code()
        # Avoid collisions
        while code in data:
            code = generate_code()

        data[code] = long_url
        save_data(data)

    short_url = request.host_url + code
    return render_template_string(HTML_INDEX, short_url=short_url)

@app.route("/<code>", methods=["GET"])
def follow(code):
    if not code:
        abort(404)
    with DATA_LOCK:
        data = load_data()
        long_url = data.get(code)
    if not long_url:
        abort(404)
    return redirect(long_url, code=302)

@app.errorhandler(404)
def not_found(e):
    return "Short link not found.", 404

if __name__ == "__main__":
    # Run the development server
    app.run(host="0.0.0.0", port=5000, debug=False)
```

