#!/usr/bin/env python3
import sys
import urllib.request
from html.parser import HTMLParser

class FirstH1Parser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_h1 = False
        self.found = False
        self.parts = []

    def handle_starttag(self, tag, attrs):
        if not self.found and tag.lower() == 'h1':
            self.in_h1 = True

    def handle_endtag(self, tag):
        if self.in_h1 and tag.lower() == 'h1':
            self.in_h1 = False
            self.found = True  # stop after first h1

    def handle_data(self, data):
        if self.in_h1 and not self.found:
            self.parts.append(data)

    def get_text(self):
        text = ''.join(self.parts)
        # Collapse whitespace
        return ' '.join(text.split()).strip()

def fetch_url(url):
    req = urllib.request.Request(url, headers={'User-Agent': 'python-urllib/3'})
    with urllib.request.urlopen(req) as resp:
        raw = resp.read()
        # Try to get charset from headers, default to utf-8
        charset = resp.headers.get_content_charset() or 'utf-8'
        return raw.decode(charset, errors='replace')

def main():
    if len(sys.argv) != 2:
        print("Usage: python get_h1.py <url>", file=sys.stderr)
        sys.exit(2)
    url = sys.argv[1]
    try:
        html = fetch_url(url)
    except Exception as e:
        print(f"Error fetching URL: {e}", file=sys.stderr)
        sys.exit(1)

    parser = FirstH1Parser()
    parser.feed(html)
    h1_text = parser.get_text()
    if h1_text:
        print(h1_text)
    else:
        # No H1 found: print nothing and exit with code 0, or optionally print a message
        print("", end="")

if __name__ == "__main__":
    main()
```

