Here's a small Python script that fetches a URL and prints the text inside the first <h1> tag.

```python
#!/usr/bin/env python3
import sys
import urllib.request
import urllib.error
from html.parser import HTMLParser
import html

class FirstH1Parser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.collecting = False
        self.depth = 0
        self.buffer = []
        self.found = False

    def handle_starttag(self, tag, attrs):
        if self.found:
            return
        if tag.lower() == 'h1':
            # start collecting; initial depth = 1 (the <h1> itself)
            self.collecting = True
            self.depth = 1
            self.found = True
        elif self.collecting:
            # nested tag inside h1
            self.depth += 1

    def handle_endtag(self, tag):
        if not self.collecting:
            return
        # decrement depth for any end tag inside h1
        self.depth -= 1
        if self.depth <= 0:
            # finished collecting the h1 content
            self.collecting = False

    def handle_data(self, data):
        if self.collecting:
            self.buffer.append(data)

    def handle_entityref(self, name):
        if self.collecting:
            self.buffer.append('&' + name + ';')

    def handle_charref(self, name):
        if self.collecting:
            self.buffer.append('&#' + name + ';')

    def get_text(self):
        if not self.buffer:
            return ''
        raw = ''.join(self.buffer)
        return html.unescape(raw).strip()

def fetch_url(url, timeout=10):
    # Add scheme if missing
    if not url.startswith(('http://', 'https://')):
        url = 'http://' + url
    req = urllib.request.Request(url, headers={'User-Agent': 'python-urllib/3'})
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        # try to determine encoding
        charset = None
        # Python 3.9+: resp.headers.get_content_charset()
        try:
            charset = resp.headers.get_content_charset()
        except Exception:
            try:
                charset = resp.info().get_content_charset()
            except Exception:
                charset = None
        raw = resp.read()
        if charset:
            text = raw.decode(charset, errors='replace')
        else:
            # fallback to utf-8, replace errors
            try:
                text = raw.decode('utf-8', errors='replace')
            except Exception:
                text = raw.decode('latin-1', errors='replace')
        return text

def main():
    if len(sys.argv) != 2:
        print("Usage: {} <url>".format(sys.argv[0]), file=sys.stderr)
        sys.exit(2)
    url = sys.argv[1]
    try:
        html_text = fetch_url(url)
    except urllib.error.HTTPError as e:
        print(f"HTTP error: {e.code} {e.reason}", file=sys.stderr)
        sys.exit(1)
    except urllib.error.URLError as e:
        print(f"URL error: {e.reason}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Error fetching URL: {e}", file=sys.stderr)
        sys.exit(1)

    parser = FirstH1Parser()
    parser.feed(html_text)
    h1_text = parser.get_text()
    if h1_text:
        print(h1_text)
    else:
        print("No <h1> found", file=sys.stderr)
        sys.exit(3)

if __name__ == '__main__':
    main()
```

