Here's a single-file Go program that implements the requested in-memory REST API for todos.

Save as main.go, build and run (go 1.20+ recommended).

```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"strings"
	"sync"
	"time"
)

type Todo struct {
	ID        int       `json:"id"`
	Title     string    `json:"title"`
	Done      bool      `json:"done"`
	CreatedAt time.Time `json:"created_at"`
}

type store struct {
	sync.Mutex
	nextID int
	items  map[int]*Todo
}

var s = &store{
	nextID: 1,
	items:  make(map[int]*Todo),
}

func main() {
	http.HandleFunc("/todos", todosHandler)            // GET /todos, POST /todos
	http.HandleFunc("/todos/", todoSubHandler)         // POST /todos/{id}/done
	addr := ":8080"
	log.Printf("Starting server on %s\n", addr)
	log.Fatal(http.ListenAndServe(addr, nil))
}

func todosHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodGet:
		handleListTodos(w, r)
	case http.MethodPost:
		handleCreateTodo(w, r)
	default:
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
	}
}

func todoSubHandler(w http.ResponseWriter, r *http.Request) {
	// Expect pattern /todos/{id}/done
	// Trim leading "/todos/"
	trim := strings.TrimPrefix(r.URL.Path, "/todos/")
	parts := strings.Split(strings.Trim(trim, "/"), "/")
	if len(parts) == 2 && parts[1] == "done" && r.Method == http.MethodPost {
		idStr := parts[0]
		handleMarkDone(w, r, idStr)
		return
	}
	http.NotFound(w, r)
}

type createRequest struct {
	Title string `json:"title"`
}

func handleCreateTodo(w http.ResponseWriter, r *http.Request) {
	var req createRequest
	dec := json.NewDecoder(r.Body)
	dec.DisallowUnknownFields()
	if err := dec.Decode(&req); err != nil {
		http.Error(w, "invalid JSON body", http.StatusBadRequest)
		return
	}
	req.Title = strings.TrimSpace(req.Title)
	if req.Title == "" {
		http.Error(w, "title is required", http.StatusBadRequest)
		return
	}

	s.Lock()
	id := s.nextID
	t := &Todo{
		ID:        id,
		Title:     req.Title,
		Done:      false,
		CreatedAt: time.Now().UTC(),
	}
	s.items[id] = t
	s.nextID++
	s.Unlock()

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", fmt.Sprintf("/todos/%d", id))
	w.WriteHeader(http.StatusCreated)
	_ = json.NewEncoder(w).Encode(t)
}

func handleListTodos(w http.ResponseWriter, r *http.Request) {
	s.Lock()
	list := make([]*Todo, 0, len(s.items))
	for _, t := range s.items {
		list = append(list, t)
	}
	s.Unlock()

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(list)
}

func handleMarkDone(w http.ResponseWriter, r *http.Request, idStr string) {
	id, err := strconv.Atoi(idStr)
	if err != nil || id <= 0 {
		http.Error(w, "invalid id", http.StatusBadRequest)
		return
	}

	s.Lock()
	t, ok := s.items[id]
	if !ok {
		s.Unlock()
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if t.Done {
		// already done; idempotent
		s.Unlock()
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(t)
		return
	}
	t.Done = true
	s.Unlock()

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(t)
}
```

Usage notes:
- Build and run:
  - go build -o todos && ./todos
- Examples:
  - Create: curl -s -X POST -H "Content-Type: application/json" -d '{"title":"Buy milk"}' http://localhost:8080/todos
  - List: curl -s http://localhost:8080/todos
  - Mark done (replace 1 with the id): curl -s -X POST http://localhost:8080/todos/1/done

This implementation keeps data in memory and is thread-safe.

Here's a small Node.js service using Express that verifies an HMAC-SHA256 signature from the X-Signature header against a shared secret in the WEBHOOK_SECRET environment variable, and logs the JSON body if valid.

index.js
```js
// index.js
const express = require('express');
const crypto = require('crypto');

const app = express();

// Get secret from environment
const SECRET = process.env.WEBHOOK_SECRET;
if (!SECRET) {
  console.error('Missing WEBHOOK_SECRET environment variable. Exiting.');
  process.exit(1);
}

// Use raw body parser so we compute HMAC over exact bytes
app.use('/webhook', express.raw({ type: 'application/json', limit: '1mb' }));

function safeCompareHex(aHex, bHex) {
  // Return false if lengths differ
  if (typeof aHex !== 'string' || typeof bHex !== 'string') return false;
  if (aHex.length !== bHex.length) return false;
  const a = Buffer.from(aHex, 'hex');
  const b = Buffer.from(bHex, 'hex');
  // timingSafeEqual requires same length buffers
  return crypto.timingSafeEqual(a, b);
}

app.post('/webhook', (req, res) => {
  try {
    const header = (req.get('X-Signature') || '').trim();
    if (!header) {
      return res.status(400).send('Missing X-Signature header');
    }

    // Accept either "sha256=<hex>" or just "<hex>"
    const prefix = 'sha256=';
    const incomingHex = header.startsWith(prefix) ? header.slice(prefix.length) : header;

    // Compute HMAC-SHA256 over raw request body bytes
    const hmac = crypto.createHmac('sha256', SECRET);
    hmac.update(req.body || Buffer.from(''));
    const digestHex = hmac.digest('hex');

    if (!safeCompareHex(digestHex, incomingHex)) {
      console.warn('Invalid signature. Expected:', 'sha256=' + digestHex, 'Got:', header);
      return res.status(401).send('Invalid signature');
    }

    // Signature valid — parse JSON and log
    let json;
    try {
      const text = req.body.toString('utf8');
      json = text ? JSON.parse(text) : {};
    } catch (err) {
      console.warn('Signature valid but JSON parse failed:', err.message);
      return res.status(400).send('Invalid JSON');
    }

    console.log('Verified webhook payload:', JSON.stringify(json, null, 2));
    return res.status(200).send('OK');
  } catch (err) {
    console.error('Server error handling webhook:', err);
    return res.status(500).send('Server error');
  }
});

const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Webhook listener running on port ${PORT}`);
});
```

Usage:
1. Install dependencies:
   - npm init -y
   - npm install express
2. Run:
   - export WEBHOOK_SECRET="your_shared_secret"
   - node index.js
3. Example curl (Linux/macOS) — compute HMAC hex and send:
   - BODY='{"hello":"world"}'
   - SIG=$(printf '%s' "$BODY" | openssl dgst -sha256 -hmac "$WEBHOOK_SECRET" | awk '{print $2}')
   - curl -X POST -H "Content-Type: application/json" -H "X-Signature: sha256=$SIG" --data "$BODY" http://localhost:3000/webhook

The service returns 200 when verified, 401 for invalid signature, and 400 for missing header or invalid JSON.

Here's a small Go HTTP proxy that forwards GET requests to an upstream URL and rate-limits each client IP to 10 requests per minute (returns 429 when exceeded).

```go
// Save as proxy.go
package main

import (
	"flag"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"
)

type clientBucket struct {
	tokens   float64
	last     time.Time
	lastSeen time.Time
}

type Proxy struct {
	upstream    *url.URL
	clientMu    sync.Mutex
	clients     map[string]*clientBucket
	rate        float64 // tokens per second
	capacity    float64 // max tokens
	cleanupTick time.Duration
}

func NewProxy(upstream *url.URL, maxRequests int, perSeconds int) *Proxy {
	return &Proxy{
		upstream:    upstream,
		clients:     make(map[string]*clientBucket),
		rate:        float64(maxRequests) / float64(perSeconds),
		capacity:    float64(maxRequests),
		cleanupTick: 5 * time.Minute,
	}
}

func (p *Proxy) getClientBucket(ip string) *clientBucket {
	p.clientMu.Lock()
	defer p.clientMu.Unlock()
	b, ok := p.clients[ip]
	now := time.Now()
	if !ok {
		b = &clientBucket{
			tokens:   p.capacity,
			last:     now,
			lastSeen: now,
		}
		p.clients[ip] = b
		return b
	}
	// refill tokens
	elapsed := now.Sub(b.last).Seconds()
	b.tokens += elapsed * p.rate
	if b.tokens > p.capacity {
		b.tokens = p.capacity
	}
	b.last = now
	b.lastSeen = now
	return b
}

func (p *Proxy) cleanupLoop() {
	ticker := time.NewTicker(p.cleanupTick)
	defer ticker.Stop()
	for range ticker.C {
		threshold := time.Now().Add(-10 * time.Minute)
		p.clientMu.Lock()
		for ip, b := range p.clients {
			if b.lastSeen.Before(threshold) {
				delete(p.clients, ip)
			}
		}
		p.clientMu.Unlock()
	}
}

func clientIP(r *http.Request) string {
	// Prefer X-Forwarded-For's first entry if present, otherwise use RemoteAddr.
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		// Could be comma separated list
		parts := strings.Split(xff, ",")
		ip := strings.TrimSpace(parts[0])
		if ip != "" {
			return ip
		}
	}
	// Fallback to RemoteAddr
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		// If can't parse, return whole RemoteAddr
		return r.RemoteAddr
	}
	return host
}

func copyHopByHopHeaders(dst, src http.Header) {
	// Per RFC 2616 section 13.5.1 hop-by-hop headers should be removed/handled by proxy.
	hopByHop := []string{
		"Connection", "Proxy-Connection", "Keep-Alive", "Proxy-Authenticate",
		"Proxy-Authorization", "TE", "Trailers", "Transfer-Encoding", "Upgrade",
	}
	for k, vv := range src {
		skip := false
		for _, h := range hopByHop {
			if strings.EqualFold(k, h) {
				skip = true
				break
			}
		}
		if skip {
			continue
		}
		for _, v := range vv {
			dst.Add(k, v)
		}
	}
}

func (p *Proxy) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Allow only GET
	if r.Method != http.MethodGet {
		w.Header().Set("Allow", http.MethodGet)
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	ip := clientIP(r)
	b := p.getClientBucket(ip)

	// Rate limiting decision
	if b.tokens < 1.0 {
		// compute retry-after seconds (how long until at least 1 token)
		needed := 1.0 - b.tokens
		retrySecs := int((needed / p.rate) + 0.999) // ceil
		w.Header().Set("Retry-After", fmt.Sprintf("%d", retrySecs))
		http.Error(w, "too many requests", http.StatusTooManyRequests)
		return
	}
	// consume token
	b.tokens -= 1.0

	// Build upstream URL (preserve path and raw query)
	upstreamURL := p.upstream.ResolveReference(r.URL)

	// Create new GET request
	req, err := http.NewRequest(http.MethodGet, upstreamURL.String(), nil)
	if err != nil {
		http.Error(w, "bad gateway", http.StatusBadGateway)
		return
	}

	// Copy selected headers (excluding hop-by-hop)
	copyHopByHopHeaders(req.Header, r.Header)

	// Set/append X-Forwarded-For
	if prior := req.Header.Get("X-Forwarded-For"); prior != "" {
		req.Header.Set("X-Forwarded-For", prior+", "+ip)
	} else {
		req.Header.Set("X-Forwarded-For", ip)
	}

	// Set Host header for upstream
	req.Host = p.upstream.Host

	transport := http.DefaultTransport
	resp, err := transport.RoundTrip(req)
	if err != nil {
		http.Error(w, "bad gateway", http.StatusBadGateway)
		return
	}
	defer resp.Body.Close()

	// Copy status
	w.WriteHeader(resp.StatusCode)
	// Copy headers
	copyHopByHopHeaders(w.Header(), resp.Header)

	// Copy body
	if _, err := io.Copy(w, resp.Body); err != nil {
		// can't write to client; just log
		log.Printf("error copying response body: %v", err)
	}
}

func main() {
	var listenAddr string
	var upstreamStr string
	var maxRequests int
	var perSeconds int

	flag.StringVar(&listenAddr, "listen", ":8080", "listen address")
	flag.StringVar(&upstreamStr, "upstream", "", "upstream base URL (e.g. https://example.com)")
	flag.IntVar(&maxRequests, "max", 10, "max requests per client in window")
	flag.IntVar(&perSeconds, "per", 60, "window duration in seconds")
	flag.Parse()

	if upstreamStr == "" {
		log.Fatal("upstream flag is required")
	}
	upstream, err := url.Parse(upstreamStr)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}
	if upstream.Scheme != "http" && upstream.Scheme != "https" {
		log.Fatalf("upstream must be http or https")
	}

	proxy := NewProxy(upstream, maxRequests, perSeconds)
	go proxy.cleanupLoop()

	server := &http.Server{
		Addr:    listenAddr,
		Handler: proxy,
	}

	log.Printf("Starting GET proxy on %s -> %s (limit: %d req per %d seconds)", listenAddr, upstream.String(), maxRequests, perSeconds)
	// For debug: print requests
	dump := func(r *http.Request) {
		if b, err := httputil.DumpRequest(r, false); err == nil {
			log.Printf("%s", b)
		}
	}
	_ = dump

	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("server error: %v", err)
	}
}
```

Usage:
- Build and run:
  - go run proxy.go -upstream=https://httpbin.org -listen=:8080
- The proxy accepts only GET requests. Each client IP (based on X-Forwarded-For first entry or RemoteAddr) is limited to 10 requests per 60 seconds by default; you can change with -max and -per flags. Requests over the limit get HTTP 429 with a Retry-After header.

Here's a small HTTP proxy in Go that forwards GET requests to an upstream server and rate-limits each client IP to 10 requests per minute (returns 429 when over the limit).

Save as proxy.go and build with "go build".

```go
package main

import (
	"flag"
	"fmt"
	"log"
	"math"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"
)

// Token-bucket limiter per client IP
type clientLimiter struct {
	mu    sync.Mutex
	tokens float64
	last   time.Time
}

type limiterStore struct {
	mu      sync.RWMutex
	clients map[string]*clientLimiter
	// parameters
	capacity float64
	rate     float64 // tokens per second
	ttl      time.Duration
}

func newLimiterStore(capacity int, per time.Duration, ttl time.Duration) *limiterStore {
	return &limiterStore{
		clients:  make(map[string]*clientLimiter),
		capacity: float64(capacity),
		rate:     float64(capacity) / per.Seconds(),
		ttl:      ttl,
	}
}

func (s *limiterStore) getClient(ip string) *clientLimiter {
	s.mu.RLock()
	c, ok := s.clients[ip]
	s.mu.RUnlock()
	if ok {
		return c
	}
	// create
	s.mu.Lock()
	defer s.mu.Unlock()
	// double-check
	if c, ok = s.clients[ip]; ok {
		return c
	}
	c = &clientLimiter{
		tokens: s.capacity,
		last:   time.Now(),
	}
	s.clients[ip] = c
	return c
}

func (s *limiterStore) allow(ip string) (bool, float64) {
	// returns (allowed, secondsUntilNextToken)
	c := s.getClient(ip)
	c.mu.Lock()
	defer c.mu.Unlock()
	now := time.Now()
	elapsed := now.Sub(c.last).Seconds()
	if elapsed > 0 {
		c.tokens = math.Min(s.capacity, c.tokens+elapsed*s.rate)
		c.last = now
	}
	if c.tokens >= 1.0 {
		c.tokens -= 1.0
		// remaining tokens
		return true, 0
	}
	// compute wait time until one token available
	needed := 1.0 - c.tokens
	sec := needed / s.rate
	if sec < 0 {
		sec = 0
	}
	return false, sec
}

// Cleanup old clients not touched for ttl
func (s *limiterStore) cleanupLoop() {
	ticker := time.NewTicker(s.ttl / 2)
	defer ticker.Stop()
	for range ticker.C {
		cutoff := time.Now().Add(-s.ttl)
		s.mu.Lock()
		for ip, cl := range s.clients {
			cl.mu.Lock()
			last := cl.last
			cl.mu.Unlock()
			if last.Before(cutoff) {
				delete(s.clients, ip)
			}
		}
		s.mu.Unlock()
	}
}

func getClientIP(r *http.Request) string {
	// prefer X-Forwarded-For if present (first value)
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		// header can be "client, proxy1, proxy2"
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			return strings.TrimSpace(parts[0])
		}
	}
	// fallback to remote address
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

func main() {
	var upstreamStr string
	var listenAddr string
	var limit int
	var perSeconds int
	flag.StringVar(&upstreamStr, "upstream", "", "Upstream base URL (required), e.g. http://example.com/")
	flag.StringVar(&listenAddr, "listen", ":8080", "Address to listen on")
	flag.IntVar(&limit, "limit", 10, "Max requests per client per time window")
	flag.IntVar(&perSeconds, "per", 60, "Time window in seconds")
	flag.Parse()

	if upstreamStr == "" {
		log.Fatalf("upstream flag is required")
	}

	upstreamURL, err := url.Parse(upstreamStr)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	// reverse proxy
	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	// keep original Host header? We'll set it to upstream host.
	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		// We want to forward the incoming path and query onto the upstream host.
		// SingleHostReverseProxy's Director will set scheme and host; call it then adjust path to preserve original
		originalDirector(req)
		// The originalDirector already replaced req.URL.Path with single host's path + incoming path,
		// but it's safe to leave as-is. Ensure Host header is upstream host.
		req.Host = upstreamURL.Host
	}

	// limiter store: capacity limit per perSeconds
	store := newLimiterStore(limit, time.Duration(perSeconds)*time.Second, 5*time.Minute)
	go store.cleanupLoop()

	handler := func(w http.ResponseWriter, r *http.Request) {
		// Only forward GET requests as requested
		if r.Method != http.MethodGet {
			w.Header().Set("Allow", http.MethodGet)
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}
		ip := getClientIP(r)
		allowed, wait := store.allow(ip)
		if !allowed {
			retryAfter := int(math.Ceil(wait))
			if retryAfter < 1 {
				retryAfter = 1
			}
			w.Header().Set("Retry-After", fmt.Sprintf("%d", retryAfter))
			http.Error(w, "rate limit exceeded", http.StatusTooManyRequests)
			return
		}
		// Forward request to upstream
		proxy.ServeHTTP(w, r)
	}

	http.HandleFunc("/", handler)
	log.Printf("Starting proxy on %s forwarding to %s (limit %d req per %ds)", listenAddr, upstreamURL.String(), limit, perSeconds)
	if err := http.ListenAndServe(listenAddr, nil); err != nil {
		log.Fatalf("server error: %v", err)
	}
}
