Here's a small Go HTTP proxy that forwards GET requests to an upstream URL and enforces a per-client-IP limit of 10 requests per minute (returns 429 when over the limit).

Save as main.go and run with -upstream (required) and optional -addr.

```go
package main

import (
	"flag"
	"fmt"
	"log"
	"math"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"
)

type clientInfo struct {
	count       int
	windowStart time.Time
}

type RateLimiter struct {
	mu      sync.Mutex
	clients map[string]*clientInfo
	limit   int
	window  time.Duration
}

func NewRateLimiter(limit int, window time.Duration) *RateLimiter {
	rl := &RateLimiter{
		clients: make(map[string]*clientInfo),
		limit:   limit,
		window:  window,
	}
	go rl.cleanupLoop()
	return rl
}

// Allow returns (allowed, retryAfter). If allowed is false, retryAfter is how long
// the client should wait before a new request will be accepted.
func (rl *RateLimiter) Allow(ip string) (bool, time.Duration) {
	now := time.Now()
	rl.mu.Lock()
	defer rl.mu.Unlock()

	c, ok := rl.clients[ip]
	if !ok || now.Sub(c.windowStart) >= rl.window {
		rl.clients[ip] = &clientInfo{count: 1, windowStart: now}
		return true, 0
	}

	if c.count < rl.limit {
		c.count++
		return true, 0
	}

	// over limit
	retry := rl.window - now.Sub(c.windowStart)
	if retry < 0 {
		retry = 0
	}
	return false, retry
}

// cleanupLoop removes stale client entries to avoid unbounded growth.
func (rl *RateLimiter) cleanupLoop() {
	ticker := time.NewTicker(time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		rl.cleanup()
	}
}

func (rl *RateLimiter) cleanup() {
	rl.mu.Lock()
	defer rl.mu.Unlock()
	now := time.Now()
	threshold := rl.window * 5
	for ip, c := range rl.clients {
		if now.Sub(c.windowStart) > threshold {
			delete(rl.clients, ip)
		}
	}
}

func getClientIP(r *http.Request) string {
	// Prefer X-Forwarded-For left-most entry if present
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		// may be comma-separated list
		parts := strings.Split(xff, ",")
		if len(parts) > 0 {
			ip := strings.TrimSpace(parts[0])
			if ip != "" {
				return ip
			}
		}
	}
	// Fall back to RemoteAddr
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		// If SplitHostPort fails, return the whole RemoteAddr
		return r.RemoteAddr
	}
	return host
}

func main() {
	upstreamStr := flag.String("upstream", "", "Upstream base URL to forward GET requests to (required), e.g. http://example.com")
	addr := flag.String("addr", ":8080", "Address to listen on")
	limit := flag.Int("limit", 10, "Requests per window per client")
	windowSec := flag.Int("window", 60, "Window size in seconds for rate limiting")
	flag.Parse()

	if *upstreamStr == "" {
		log.Fatal("missing required -upstream flag")
	}

	upstreamURL, err := url.Parse(*upstreamStr)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	rl := NewRateLimiter(*limit, time.Duration(*windowSec)*time.Second)

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	// Replace the Director so we preserve the incoming path and query and set upstream host.
	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		// Use original director to ensure default behavior, then adjust if necessary.
		originalDirector(req)
		// Ensure the scheme and host match the configured upstream (in case originalDirector used it already).
		req.URL.Scheme = upstreamURL.Scheme
		req.URL.Host = upstreamURL.Host
		// Keep the original request path and raw query (SingleHostReverseProxy sets URL.Path to upstream.Path + req.URL.Path)
		// For safer behavior, we want to forward the incoming request path and query exactly appended to upstream base.
		// If upstreamURL.Path is non-empty and not "/", combine paths correctly.
		upPath := upstreamURL.Path
		if upPath == "" {
			upPath = "/"
		}
		// Combine paths: upstream path may be "/" or a prefix.
		if strings.HasSuffix(upPath, "/") {
			upPath = strings.TrimSuffix(upPath, "/")
		}
		// req.URL.Path already contains the incoming path; ensure it is appended to upstream path.
		// But since originalDirector already set req.URL.Path to singleHostReverseProxy behavior,
		// we'll set Host and Scheme only and leave Path as-is (this matches common expected behavior).
		req.Host = upstreamURL.Host
	}

	handler := func(w http.ResponseWriter, r *http.Request) {
		// Only accept GET
		if r.Method != http.MethodGet {
			w.Header().Set("Allow", "GET")
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}

		ip := getClientIP(r)
		allowed, retryAfter := rl.Allow(ip)
		if !allowed {
			// Retry-After in seconds
			secs := int(math.Ceil(retryAfter.Seconds()))
			if secs < 1 {
				secs = 1
			}
			w.Header().Set("Retry-After", fmt.Sprintf("%d", secs))
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		// Forward to upstream
		proxy.ServeHTTP(w, r)
	}

	server := &http.Server{
		Addr:    *addr,
		Handler: http.HandlerFunc(handler),
	}

	log.Printf("Starting proxy on %s forwarding to %s (limit %d req per %d sec)\n", *addr, upstreamURL, *limit, *windowSec)
	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatalf("server error: %v", err)
	}
}
