Here's a simple Go HTTP proxy that forwards only GET requests to a configured upstream and enforces a per-client-IP rate limit of 10 requests per minute (returns 429 when exceeded).

Save as main.go and run with `go run main.go -upstream http://upstream.example -listen :8080`.

```go
package main

import (
	"flag"
	"fmt"
	"log"
	"math"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"
)

const (
	maxTokens     = 10.0
	refillPerMin  = 10.0
	cleanupAfter  = 10 * time.Minute
	cleanupPeriod = 5 * time.Minute
)

var refillPerSec = refillPerMin / 60.0

type clientLimiter struct {
	mu    sync.Mutex
	tokens float64
	last   time.Time
}

type limiterStore struct {
	mu      sync.Mutex
	clients map[string]*clientLimiter
}

func newLimiterStore() *limiterStore {
	ls := &limiterStore{
		clients: make(map[string]*clientLimiter),
	}
	go ls.cleanupLoop()
	return ls
}

func (ls *limiterStore) getClient(ip string) *clientLimiter {
	ls.mu.Lock()
	c, ok := ls.clients[ip]
	if !ok {
		c = &clientLimiter{
			tokens: maxTokens,
			last:   time.Now(),
		}
		ls.clients[ip] = c
	}
	ls.mu.Unlock()
	return c
}

func (ls *limiterStore) cleanupLoop() {
	t := time.NewTicker(cleanupPeriod)
	defer t.Stop()
	for range t.C {
		cutoff := time.Now().Add(-cleanupAfter)
		ls.mu.Lock()
		for ip, c := range ls.clients {
			c.mu.Lock()
			last := c.last
			c.mu.Unlock()
			if last.Before(cutoff) {
				delete(ls.clients, ip)
			}
		}
		ls.mu.Unlock()
	}
}

// allow returns (allowed, retryAfterSeconds)
func (ls *limiterStore) allow(ip string) (bool, int) {
	c := ls.getClient(ip)

	c.mu.Lock()
	defer c.mu.Unlock()

	now := time.Now()
	elapsed := now.Sub(c.last).Seconds()
	if elapsed > 0 {
		c.tokens += elapsed * refillPerSec
		if c.tokens > maxTokens {
			c.tokens = maxTokens
		}
		c.last = now
	}

	if c.tokens >= 1.0 {
		c.tokens -= 1.0
		return true, 0
	}

	need := (1.0 - c.tokens) / refillPerSec
	retry := int(math.Ceil(need))
	if retry < 1 {
		retry = 1
	}
	return false, retry
}

func getClientIP(r *http.Request) string {
	// Prefer X-Real-IP, then X-Forwarded-For (first), else RemoteAddr
	if xr := strings.TrimSpace(r.Header.Get("X-Real-Ip")); xr != "" {
		return xr
	}
	if xff := strings.TrimSpace(r.Header.Get("X-Forwarded-For")); xff != "" {
		// X-Forwarded-For can contain comma separated list. Take first.
		parts := strings.Split(xff, ",")
		return strings.TrimSpace(parts[0])
	}
	// RemoteAddr is ip:port
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

func main() {
	upstreamFlag := flag.String("upstream", "", "Upstream base URL to forward requests to (required), e.g. http://example.com")
	listenFlag := flag.String("listen", ":8080", "Address to listen on")
	flag.Parse()

	if *upstreamFlag == "" {
		log.Fatal("missing -upstream flag")
	}
	upstreamURL, err := url.Parse(*upstreamFlag)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	ls := newLimiterStore()

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	// Optional: keep original Host header of upstream
	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		// ensure we forward the original path + query exactly as received
		// NewSingleHostReverseProxy already sets req.URL.Path/RawQuery relative to upstream.
		// Nothing extra needed here unless you want to customize.
	}

	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Only allow GET
		if r.Method != http.MethodGet {
			w.Header().Set("Allow", http.MethodGet)
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}

		ip := getClientIP(r)
		allowed, retry := ls.allow(ip)
		if !allowed {
			w.Header().Set("Retry-After", fmt.Sprintf("%d", retry))
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		// Forward request to upstream
		proxy.ServeHTTP(w, r)
	})

	server := &http.Server{
		Addr:    *listenFlag,
		Handler: handler,
	}

	log.Printf("Starting proxy on %s forwarding GETs to %s (limit: %.0f req/min per IP)\n", *listenFlag, upstreamURL, refillPerMin)
	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatalf("server error: %v", err)
	}
}
