Here's a small Go HTTP proxy that forwards GET requests to an upstream URL and rate-limits each client IP to 10 requests per minute (returns 429 when over the limit).

Save as proxy.go and run with `go run proxy.go -upstream http://upstream.example -listen :8080`.

```go
package main

import (
	"flag"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

const (
	capacity       = 10.0
	windowSeconds  = 60.0
	cleanupSeconds = 300 // remove idle clients after 5 minutes
)

var refillPerSec = capacity / windowSeconds

type bucket struct {
	tokens float64
	last   time.Time
}

func (b *bucket) allowNow() (allowed bool, waitSeconds float64) {
	now := time.Now()
	elapsed := now.Sub(b.last).Seconds()
	if elapsed < 0 {
		elapsed = 0
	}
	b.tokens += elapsed * refillPerSec
	if b.tokens > capacity {
		b.tokens = capacity
	}
	b.last = now
	if b.tokens >= 1.0 {
		b.tokens -= 1.0
		return true, 0
	}
	need := 1.0 - b.tokens
	waitSeconds = need / refillPerSec
	return false, waitSeconds
}

type limiter struct {
	mu      sync.Mutex
	buckets map[string]*bucket
}

func newLimiter() *limiter {
	l := &limiter{
		buckets: make(map[string]*bucket),
	}
	go l.cleanupLoop()
	return l
}

func (l *limiter) allow(ip string) (bool, float64) {
	l.mu.Lock()
	defer l.mu.Unlock()
	b, ok := l.buckets[ip]
	if !ok {
		b = &bucket{
			tokens: capacity - 1.0, // consume one immediately on first request
			last:   time.Now(),
		}
		if b.tokens < 0 {
			b.tokens = 0
		}
		l.buckets[ip] = b
		return true, 0
	}
	allow, wait := b.allowNow()
	return allow, wait
}

func (l *limiter) cleanupLoop() {
	t := time.NewTicker(time.Minute)
	defer t.Stop()
	for range t.C {
		cutoff := time.Now().Add(-time.Duration(cleanupSeconds) * time.Second)
		l.mu.Lock()
		for ip, b := range l.buckets {
			if b.last.Before(cutoff) {
				delete(l.buckets, ip)
			}
		}
		l.mu.Unlock()
	}
}

func getClientIP(r *http.Request) string {
	// Prefer X-Real-IP, then X-Forwarded-For, then RemoteAddr
	if xr := r.Header.Get("X-Real-Ip"); xr != "" {
		return strings.TrimSpace(strings.Split(xr, ",")[0])
	}
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		parts := strings.Split(xff, ",")
		return strings.TrimSpace(parts[0])
	}
	// RemoteAddr is "ip:port"
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

var hopByHop = map[string]bool{
	"Connection":          true,
	"Keep-Alive":          true,
	"Proxy-Authenticate":  true,
	"Proxy-Authorization": true,
	"TE":                  true,
	"Trailers":            true,
	"Transfer-Encoding":   true,
	"Upgrade":             true,
}

func copyHeaders(dst, src http.Header) {
	for k, vv := range src {
		if _, ok := hopByHop[k]; ok {
			continue
		}
		for _, v := range vv {
			dst.Add(k, v)
		}
	}
}

func main() {
	var listenAddr string
	var upstream string
	flag.StringVar(&listenAddr, "listen", ":8080", "listen address")
	flag.StringVar(&upstream, "upstream", "", "upstream base URL (required), e.g. http://example.com")
	flag.Parse()

	if upstream == "" {
		log.Fatal("missing -upstream flag")
	}
	upstream = strings.TrimRight(upstream, "/")

	_, err := url.Parse(upstream)
	if err != nil {
		log.Fatalf("invalid upstream URL: %v", err)
	}

	lim := newLimiter()
	client := &http.Client{
		Timeout: 30 * time.Second,
	}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		// Only allow GET
		if r.Method != http.MethodGet {
			w.Header().Set("Allow", http.MethodGet)
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		ip := getClientIP(r)
		allowed, wait := lim.allow(ip)
		if !allowed {
			retry := int(wait + 0.999) // ceil seconds
			w.Header().Set("Retry-After", fmt.Sprintf("%d", retry))
			http.Error(w, "rate limit exceeded", http.StatusTooManyRequests)
			return
		}

		// Build target URL by appending request URI to upstream base
		target := upstream + r.URL.RequestURI()

		req, err := http.NewRequest(http.MethodGet, target, nil)
		if err != nil {
			http.Error(w, "bad upstream request", http.StatusInternalServerError)
			return
		}

		// Copy headers except hop-by-hop; set X-Forwarded-For
		copyHeaders(req.Header, r.Header)
		// Add or append X-Forwarded-For
		xff := r.Header.Get("X-Forwarded-For")
		if xff == "" {
			req.Header.Set("X-Forwarded-For", ip)
		} else {
			req.Header.Set("X-Forwarded-For", xff+", "+ip)
		}

		resp, err := client.Do(req)
		if err != nil {
			http.Error(w, "upstream error: "+err.Error(), http.StatusBadGateway)
			return
		}
		defer resp.Body.Close()

		// Copy response status, headers, body
		copyHeaders(w.Header(), resp.Header)
		w.WriteHeader(resp.StatusCode)
		_, _ = io.Copy(w, resp.Body)
	})

	log.Printf("listening on %s, proxying GETs to %s (limit %v req/min per IP)\n", listenAddr, upstream, capacity)
	if err := http.ListenAndServe(listenAddr, nil); err != nil {
		log.Fatalf("server failed: %v", err)
	}
}
