- Only GET requests are proxied.
- Each client IP is allowed 10 requests per 60 seconds (token-bucket). Excess requests get HTTP 429 and a Retry-After header.

Here's a simple Python implementation of `wcx`. Save it as "wcx" (or "wcx.py"), make it executable, and run it.

```python
#!/usr/bin/env python3
import sys
import os

WHITESPACE_BYTES = set(b' \t\n\r\v\f')

def count_file(path):
    lines = 0
    words = 0
    bytes_count = 0
    in_word = False

    try:
        with open(path, 'rb') as f:
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                bytes_count += len(chunk)
                lines += chunk.count(b'\n')
                # iterate bytes to count words, handling chunk boundaries
                for b in chunk:
                    if b in WHITESPACE_BYTES:
                        if in_word:
                            in_word = False
                    else:
                        if not in_word:
                            words += 1
                            in_word = True
        return (lines, words, bytes_count, None)
    except OSError as e:
        return (0, 0, 0, str(e))

def format_counts(lines, words, bytes_count):
    # Align similar to wc: right-aligned columns
    return f"{lines:>8}{words:>8}{bytes_count:>8}"

def main(argv):
    if len(argv) < 2:
        print("Usage: wcx FILE [FILE...]", file=sys.stderr)
        return 2

    total_lines = total_words = total_bytes = 0
    had_error = False

    results = []
    for path in argv[1:]:
        lines, words, bytes_count, err = count_file(path)
        if err is not None:
            print(f"wcx: {path}: {err}", file=sys.stderr)
            had_error = True
            # do not include in totals
            results.append((None, path))
        else:
            total_lines += lines
            total_words += words
            total_bytes += bytes_count
            results.append(((lines, words, bytes_count), path))

    # Print per-file results
    for item, path in results:
        if item is None:
            continue
        lines, words, bytes_count = item
        print(f"{format_counts(lines, words, bytes_count)} {path}")

    # Print total (for all files listed that were successfully read)
    print(f"{format_counts(total_lines, total_words, total_bytes)} total")

    return 1 if had_error else 0

if __name__ == "__main__":
    sys.exit(main(sys.argv))
```

Usage notes:
- Run as: ./wcx file1.txt file2.bin ...
- Output format mirrors classic wc: columns for lines, words, bytes, then filename; a final totals line is printed.
- If any file cannot be read, an error is written to stderr and that file is omitted from the totals; the process exits with code 1 in that case.

