#!/usr/bin/env python3
"""
jgrep <key> <value>

Reads JSON objects (one per line) from stdin and prints only the lines
whose JSON object has the given key equal to the given value.

Key supports dotted path syntax (e.g. "user.name" or "items.0.id").
Value is parsed as JSON if possible (so true, null, numbers, arrays, objects
work); otherwise it's matched as a string.
"""

import sys
import json

def parse_target(value_arg):
    try:
        # Try parsing as JSON (so numbers, true/false, null, arrays, objects work)
        return json.loads(value_arg)
    except Exception:
        # Fallback: treat as raw string
        return value_arg

def get_by_path(obj, path):
    cur = obj
    for seg in path:
        if isinstance(cur, dict):
            if seg in cur:
                cur = cur[seg]
            else:
                raise KeyError
        elif isinstance(cur, list):
            # allow numeric indices for lists
            try:
                idx = int(seg)
            except Exception:
                raise KeyError
            if -len(cur) <= idx < len(cur):
                cur = cur[idx]
            else:
                raise KeyError
        else:
            raise KeyError
    return cur

def main(argv):
    if len(argv) != 3:
        prog = argv[0] if argv else "jgrep"
        sys.stderr.write(f"Usage: {prog} <key> <value>\n")
        sys.exit(2)

    _, key_arg, value_arg = argv
    path = key_arg.split(".") if key_arg != "" else []
    target = parse_target(value_arg)

    for raw_line in sys.stdin:
        line = raw_line.rstrip("\n")
        if not line.strip():
            continue
        try:
            obj = json.loads(line)
        except Exception as e:
            # invalid JSON line -> skip (write to stderr)
            sys.stderr.write(f"Skipping invalid JSON line: {e}\n")
            continue
        try:
            if path:
                val = get_by_path(obj, path)
            else:
                # empty key refers to the whole object
                val = obj
        except KeyError:
            continue

        # Compare using Python equality
        if val == target:
            # print original line exactly (preserve formatting)
            sys.stdout.write(raw_line)

if __name__ == "__main__":
    main(sys.argv)
