Here's a single-file Python tool that implements jgrep. Save it as jgrep (or jgrep.py), make it executable, and put it on your PATH if you like.

```python
#!/usr/bin/env python3
"""
jgrep - filter newline-delimited JSON (NDJSON) objects by a key/value match.

Usage:
  jgrep <key> <value>

The tool reads JSON objects (one per line) from stdin and writes lines
whose <key> equals <value> to stdout.

Key supports dot-separated paths for nested objects/arrays, e.g. "a.b.0.c".
<value> is interpreted as JSON when possible (numbers, true/false, null,
strings with quotes). If JSON parsing of <value> fails, the value is treated
as a raw string and matched against the string form of the JSON field.
"""

import sys
import json

def parse_expected(val):
    # Try to parse as JSON (allow numbers, booleans, null, quoted strings, arrays, objects)
    try:
        return json.loads(val)
    except Exception:
        return val  # treat as raw string

def fetch_path(obj, path_parts):
    cur = obj
    for part in path_parts:
        if cur is None:
            return None
        # if part can be an integer index for lists, use int
        if isinstance(cur, list):
            try:
                idx = int(part)
            except Exception:
                return None
            if idx < 0 or idx >= len(cur):
                return None
            cur = cur[idx]
        elif isinstance(cur, dict):
            # raw key lookup (keys are strings)
            if part in cur:
                cur = cur[part]
            else:
                return None
        else:
            return None
    return cur

def matches(found, expected):
    # If expected was parsed as JSON (not a raw string), compare directly
    if not isinstance(expected, str):
        return found == expected
    # expected is a raw string (user-provided), compare by string form
    # For found values, convert to JSON string for consistent formatting for objects/arrays,
    # otherwise use Python str for primitives.
    if isinstance(found, (dict, list)):
        found_str = json.dumps(found, separators=(',', ':'), ensure_ascii=False)
    else:
        # For Python booleans and None, json.dumps gives lowercase true/false/null which may be nicer,
        # but we want to compare to raw user string so use JSON form too for booleans/null/numbers.
        try:
            found_str = json.dumps(found, ensure_ascii=False)
        except Exception:
            found_str = str(found)
    # Strip quotes if JSON produced a quoted string (user likely provided an unquoted string)
    if found_str.startswith('"') and found_str.endswith('"'):
        found_str_unq = json.loads(found_str)
    else:
        found_str_unq = found_str
    return found_str_unq == expected

def main(argv):
    if len(argv) != 3:
        sys.stderr.write("Usage: jgrep <key> <value>\n")
        sys.exit(2)
    key, value_raw = argv[1], argv[2]
    expected = parse_expected(value_raw)
    path_parts = key.split('.')

    # Process stdin line-by-line
    for raw_line in sys.stdin:
        if not raw_line.strip():
            continue
        # keep original line as-is on match
        try:
            obj = json.loads(raw_line)
        except Exception:
            # skip invalid JSON lines
            continue
        found = fetch_path(obj, path_parts)
        if found is None:
            continue
        if matches(found, expected):
            # write the original line exactly as read
            sys.stdout.write(raw_line)

if __name__ == "__main__":
    main(sys.argv)
```

