```python
#!/usr/bin/env python3
import sys
import socket
import argparse
from concurrent.futures import ThreadPoolExecutor, as_completed

def parse_port_token(token):
    token = token.strip()
    if not token:
        return []
    if '-' in token:
        parts = token.split('-', 1)
        try:
            a = int(parts[0])
            b = int(parts[1])
        except ValueError:
            raise argparse.ArgumentTypeError(f"Invalid port range: {token}")
        if a < 1 or b < 1 or a > 65535 or b > 65535:
            raise argparse.ArgumentTypeError(f"Port numbers must be 1-65535: {token}")
        if a <= b:
            return list(range(a, b+1))
        else:
            return list(range(b, a+1))
    else:
        try:
            p = int(token)
        except ValueError:
            raise argparse.ArgumentTypeError(f"Invalid port: {token}")
        if p < 1 or p > 65535:
            raise argparse.ArgumentTypeError(f"Port number must be 1-65535: {token}")
        return [p]

def parse_ports_arg(port_args):
    ports = set()
    for arg in port_args:
        # allow comma-separated tokens inside each arg too
        for token in arg.split(','):
            ports.update(parse_port_token(token))
    return sorted(ports)

def check_port(host, port, timeout):
    try:
        # socket.create_connection will attempt to resolve and connect (IPv4/IPv6)
        with socket.create_connection((host, port), timeout=timeout) as s:
            return port, True
    except (socket.timeout, ConnectionRefusedError):
        return port, False
    except socket.gaierror:
        # name resolution error - treat as closed (caller may handle separately)
        return port, False
    except OSError:
        # other OS/socket errors - treat as closed
        return port, False

def main():
    parser = argparse.ArgumentParser(description="Simple parallel port scanner")
    parser.add_argument("host", help="Hostname or IP to scan")
    parser.add_argument("ports", nargs="+", help="Ports to scan. Use single ports, ranges (e.g. 20-25), and commas. Example: 22 80 8000-8010 8080,8443")
    parser.add_argument("-t", "--timeout", type=float, default=1.0, help="Connection timeout in seconds (default 1.0)")
    parser.add_argument("-c", "--concurrency", type=int, default=100, help="Number of worker threads (default 100)")
    args = parser.parse_args()

    try:
        ports = parse_ports_arg(args.ports)
    except argparse.ArgumentTypeError as e:
        parser.error(str(e))

    if not ports:
        parser.error("No valid ports specified.")

    # limit concurrency to a reasonable bound
    max_workers = max(1, min(args.concurrency, len(ports), 1000))

    results = {}
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        futures = {ex.submit(check_port, args.host, p, args.timeout): p for p in ports}
        for fut in as_completed(futures):
            port, is_open = fut.result()
            results[port] = is_open

    # Print sorted results
    open_count = 0
    for p in sorted(results):
        status = "open" if results[p] else "closed"
        if results[p]:
            open_count += 1
        print(f"{p:5d}  {status}")

    print(f"\nScanned {len(ports)} ports on {args.host}: {open_count} open, {len(ports)-open_count} closed")

if __name__ == "__main__":
    main()
```

Usage example:
- Scan specific ports: python portscan.py example.com 22 80 443
- Scan ranges and comma lists: python portscan.py 192.0.2.1 20-25 80,443,8080
- Adjust timeout or concurrency: python portscan.py -t 0.5 -c 200 example.com 1-1024

