#!/usr/bin/env python3
"""
Parallel TCP port scanner.

Usage examples:
  python3 portscan.py example.com 22 80 443
  python3 portscan.py example.com 1-1024
  python3 portscan.py example.com 22,80,443 8000-8100
  python3 portscan.py -t 0.5 example.com 22 80 443

Checks TCP ports in parallel using a thread pool.
"""

import argparse
import socket
import sys
from concurrent.futures import ThreadPoolExecutor, as_completed

def parse_ports(port_args):
    ports = set()
    for token in port_args:
        # support comma separated groups within token, e.g. "22,80,443"
        for part in token.split(','):
            part = part.strip()
            if not part:
                continue
            if '-' in part:
                try:
                    start_s, end_s = part.split('-', 1)
                    start = int(start_s)
                    end = int(end_s)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port range: '{part}'")
                if start > end:
                    raise argparse.ArgumentTypeError(f"Invalid range (start > end): '{part}'")
                for p in range(start, end + 1):
                    ports.add(p)
            else:
                try:
                    p = int(part)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port: '{part}'")
                ports.add(p)
    # validate range
    invalid = [p for p in ports if not (1 <= p <= 65535)]
    if invalid:
        raise argparse.ArgumentTypeError(f"Ports must be in 1-65535, invalid: {invalid[:5]}")
    return sorted(ports)

def check_port(host, port, timeout):
    """Return True if TCP port is open on host, False otherwise."""
    try:
        # socket.create_connection handles name resolution and IPv4/IPv6.
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except Exception:
        return False

def main():
    parser = argparse.ArgumentParser(description="Simple parallel TCP port scanner")
    parser.add_argument("host", help="Target hostname or IP")
    parser.add_argument("ports", nargs='+', help="Ports to scan. Can be numbers, ranges (e.g. 1-1024), and comma-separated lists.")
    parser.add_argument("-t", "--timeout", type=float, default=1.0, help="Connection timeout in seconds (default 1.0)")
    parser.add_argument("-w", "--workers", type=int, default=100, help="Maximum parallel workers (default 100)")
    args = parser.parse_args()

    try:
        ports = parse_ports(args.ports)
    except argparse.ArgumentTypeError as e:
        parser.error(str(e))

    if not ports:
        parser.error("No ports to scan.")

    # Try resolving host early to fail fast if hostname is invalid
    try:
        socket.getaddrinfo(args.host, None)
    except socket.gaierror as e:
        print(f"Could not resolve host '{args.host}': {e}", file=sys.stderr)
        sys.exit(2)

    max_workers = max(1, min(args.workers, len(ports)))
    results = {}

    print(f"Scanning {args.host} ports {ports[0]}-{ports[-1]} ({len(ports)} ports) with timeout {args.timeout}s using {max_workers} workers...")

    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        future_to_port = {ex.submit(check_port, args.host, p, args.timeout): p for p in ports}
        for fut in as_completed(future_to_port):
            p = future_to_port[fut]
            try:
                is_open = fut.result()
            except Exception:
                is_open = False
            results[p] = is_open

    # Print sorted results
    for p in sorted(results):
        status = "open" if results[p] else "closed"
        print(f"{args.host}:{p} {status}")

if __name__ == "__main__":
    main()
