            if not part:
                continue
            if '-' in part:
                try:
                    start_s, end_s = part.split('-', 1)
                    start = int(start_s)
                    end = int(end_s)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port range: '{part}'")
                if start > end:
                    raise argparse.ArgumentTypeError(f"Invalid port range (start > end): '{part}'")
                for p in range(start, end + 1):
                    if 1 <= p <= 65535:
                        ports.add(p)
                    else:
                        raise argparse.ArgumentTypeError(f"Port out of range: {p}")
            else:
                try:
                    p = int(part)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port: '{part}'")
                if 1 <= p <= 65535:
                    ports.add(p)
                else:
                    raise argparse.ArgumentTypeError(f"Port out of range: {p}")
    if not ports:
        raise argparse.ArgumentTypeError("No valid ports provided")
    return sorted(ports)


def check_port(host, port, timeout):
    """
    Return True if port is open (TCP connect succeeded), False otherwise.
    """
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except (socket.timeout, ConnectionRefusedError, OSError):
        return False


def main():
    parser = argparse.ArgumentParser(description="Simple parallel TCP port scanner")
    parser.add_argument("host", help="Target hostname or IP address")
    parser.add_argument(
        "ports",
        nargs="+",
        help="Ports to check. Examples: 22 80 8000-8010 22,80,443",
    )
