        "--workers",
        type=int,
        default=100,
        help="Maximum number of parallel worker threads (default: 100)",
    )
    args = parser.parse_args()

    try:
        ports = parse_ports(args.ports)
    except argparse.ArgumentTypeError as e:
        parser.error(str(e))

