    try:
        # getaddrinfo will raise socket.gaierror on resolution failure
        socket.getaddrinfo(args.host, None)
    except socket.gaierror as e:
        print(f"Error resolving host '{args.host}': {e}", file=sys.stderr)
        sys.exit(2)

