Here's a simple Python 3 command-line tool that scans TCP ports in parallel and reports which are open or closed.

Save as portscan.py and run with Python 3.6+.

```python
#!/usr/bin/env python3
"""
portscan.py - simple parallel TCP port scanner

Usage:
  python portscan.py example.com 22 80 8000-8010 443,8080 --timeout 1.5 --workers 200
"""

import argparse
import socket
from concurrent.futures import ThreadPoolExecutor, as_completed
import sys

def parse_ports(port_args):
    """
    Accepts a list of strings like ["22", "80,443", "8000-8010"] and returns
    a sorted list of unique integer ports (1-65535).
    """
    ports = set()
    for token in port_args:
        # split comma-separated pieces
        for part in token.split(','):
            part = part.strip()
            if not part:
                continue
            if '-' in part:
                # range
                try:
                    start_s, end_s = part.split('-', 1)
                    start = int(start_s)
                    end = int(end_s)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port range: {part}")
                if start > end:
                    start, end = end, start
                for p in range(start, end + 1):
                    if 1 <= p <= 65535:
                        ports.add(p)
            else:
                try:
                    p = int(part)
                except ValueError:
                    raise argparse.ArgumentTypeError(f"Invalid port: {part}")
                if 1 <= p <= 65535:
                    ports.add(p)
                else:
                    raise argparse.ArgumentTypeError(f"Port out of range (1-65535): {p}")
    if not ports:
        raise argparse.ArgumentTypeError("No valid ports provided")
    return sorted(ports)

def check_port(host, port, timeout):
    """Return True if TCP connection to host:port succeeds within timeout."""
    try:
        # socket.create_connection uses getaddrinfo and supports IPv4/IPv6
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except Exception:
        return False

def main():
    parser = argparse.ArgumentParser(description="Simple parallel TCP port scanner")
    parser.add_argument("host", help="Hostname or IP to scan")
    parser.add_argument("ports", nargs="+", help="Ports to scan. Accepts numbers, ranges (e.g. 20-25) and commas (e.g. 80,443)")
    parser.add_argument("--timeout", type=float, default=1.0, help="Connection timeout in seconds (default: 1.0)")
    parser.add_argument("--workers", type=int, default=100, help="Number of parallel workers (default: 100)")
    args = parser.parse_args()

    try:
        ports = parse_ports(args.ports)
    except argparse.ArgumentTypeError as e:
        print("Error parsing ports:", e, file=sys.stderr)
        sys.exit(2)

    # Resolve host first to provide early error if name doesn't resolve
    try:
        socket.getaddrinfo(args.host, None)
    except socket.gaierror as e:
        print(f"Error resolving host {args.host}: {e}", file=sys.stderr)
        sys.exit(3)

    results = {}
    print(f"Scanning {args.host} ports: {', '.join(str(p) for p in ports)} (timeout {args.timeout}s, workers {args.workers})")
    with ThreadPoolExecutor(max_workers=args.workers) as ex:
        future_to_port = {ex.submit(check_port, args.host, port, args.timeout): port for port in ports}
        for fut in as_completed(future_to_port):
            port = future_to_port[fut]
            try:
                open_ = fut.result()
            except Exception as e:
                # shouldn't really happen because check_port catches exceptions
                open_ = False
            results[port] = open_

    # Print sorted results
    for port in sorted(results):
        status = "open" if results[port] else "closed"
        print(f"{port:5} {status}")

if __name__ == "__main__":
    main()
```

Usage notes:
- Run with: python portscan.py <host> <port(s)>
  - Examples:
    - python portscan.py example.com 22 80 443
    - python portscan.py 192.168.1.1 20-25 80,443
- Options:
  - --timeout to set connection timeout (seconds)
  - --workers to control parallelism (higher = faster but more sockets/threads)

Here's a small Python 3 command-line tool that recursively sums sizes of all files in a directory and prints the total in a human-readable form.

Save as e.g. du_size.py and run with Python 3.

```python
#!/usr/bin/env python3
import os
import sys
import argparse

def human_readable(num_bytes):
    # Uses 1024-based units
    units = ['B', 'KiB', 'MiB', 'GiB', 'TiB', 'PiB', 'EiB']
    n = float(num_bytes)
    for unit in units:
        if n < 1024.0 or unit == units[-1]:
            if unit == 'B':
                return f"{int(n)} {unit}"
            return f"{n:.2f} {unit}"
        n /= 1024.0

def total_size(path):
    total = 0
    # If path is a file (or a symlink to a file), just return its size
    if os.path.isfile(path) or (os.path.islink(path) and os.path.exists(path) and os.path.isfile(path)):
        try:
            return os.path.getsize(path)
        except OSError:
            return 0

    # Otherwise walk directory tree (do not follow directory symlinks)
    for dirpath, dirnames, filenames in os.walk(path, followlinks=False):
        for name in filenames:
            full = os.path.join(dirpath, name)
            try:
                # os.path.getsize follows symlinks to files (if valid)
                total += os.path.getsize(full)
            except OSError:
                # skip files we can't access, but warn
                print(f"Warning: cannot access {full}", file=sys.stderr)
    return total

def main():
    parser = argparse.ArgumentParser(
        description="Recursively sum sizes of all files inside a directory and print total size (human-readable)."
    )
    parser.add_argument("path", nargs="?", default=".", help="Directory (or file) path to summarize (default: current directory)")
    args = parser.parse_args()

    path = args.path
    if not os.path.exists(path):
        print(f"Error: path does not exist: {path}", file=sys.stderr)
        sys.exit(2)

    size = total_size(path)
    print(f"{human_readable(size)} ({size} bytes)")

if __name__ == "__main__":
    main()
```

Usage:
- Make executable: chmod +x du_size.py
- Run: ./du_size.py /path/to/dir
- Or: python3 du_size.py /path/to/dir

Notes:
- The script uses 1024-based units (KiB, MiB, ...).
- It does not follow directory symlinks (to avoid cycles), but it will count a symlinked file's target size when possible.
- Files it cannot access are skipped with a warning printed to stderr.

