```js
const express = require('express');
const fs = require('fs');
const path = require('path');

const DATA_FILE = path.join(__dirname, 'counter.json');
let value = 0;

// Load persisted value or initialize file
try {
  const txt = fs.readFileSync(DATA_FILE, 'utf8');
  const parsed = JSON.parse(txt);
  if (typeof parsed.value === 'number') value = parsed.value;
} catch (e) {
  // If file doesn't exist or is invalid, write initial file
  fs.writeFileSync(DATA_FILE, JSON.stringify({ value }), 'utf8');
}

const app = express();
app.use(express.json());

const clients = []; // SSE clients

// Serve single-page app
app.get('/', (req, res) => {
  res.send(`<!doctype html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>Shared Counter</title>
  <style>
    body { font-family: Arial, sans-serif; display:flex; align-items:center; justify-content:center; height:100vh; margin:0; }
    .box { text-align:center; }
    .count { font-size:64px; margin:20px 0; }
    button { font-size:24px; width:80px; height:50px; margin:0 10px; }
  </style>
</head>
<body>
  <div class="box">
    <div class="count" id="count">0</div>
    <div>
      <button id="dec">−</button>
      <button id="inc">+</button>
    </div>
  </div>

  <script>
    const countEl = document.getElementById('count');
    const incBtn = document.getElementById('inc');
    const decBtn = document.getElementById('dec');

    function updateDisplay(n) { countEl.textContent = n; }

    // Fetch initial value (SSE will also send it on connect, this is fallback)
    fetch('/value').then(r => r.json()).then(j => updateDisplay(j.value)).catch(() => {});

    // Subscribe to server-sent events for live updates
    const es = new EventSource('/events');
    es.onmessage = (e) => {
      try {
        const data = JSON.parse(e.data);
        if (typeof data.value === 'number') updateDisplay(data.value);
      } catch (err) { console.error('Bad SSE data', err); }
    };
    es.onerror = (err) => {
      console.error('EventSource failed', err);
    };

    function sendDelta(delta) {
      fetch('/change', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ delta })
      }).then(r => r.json()).then(j => {
        if (typeof j.value === 'number') updateDisplay(j.value);
      }).catch(err => console.error(err));
    }

    incBtn.addEventListener('click', () => sendDelta(1));
    decBtn.addEventListener('click', () => sendDelta(-1));
  </script>
</body>
</html>`);
});

// Endpoint to get current value
app.get('/value', (req, res) => {
  res.json({ value });
});

// Endpoint to change value by delta (integer)
app.post('/change', (req, res) => {
  const delta = Number(req.body && req.body.delta);
  if (!Number.isInteger(delta)) {
    return res.status(400).json({ error: 'delta must be an integer' });
  }

  // Update in-memory value and persist synchronously to avoid races
  value += delta;
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify({ value }), 'utf8');
  } catch (err) {
    console.error('Failed to write file', err);
    return res.status(500).json({ error: 'failed to persist value' });
  }

  // Broadcast to SSE clients
  const payload = `data: ${JSON.stringify({ value })}\n\n`;
  clients.forEach((client) => {
    client.write(payload);
  });

  res.json({ value });
});

// Server-Sent Events endpoint
app.get('/events', (req, res) => {
  res.set({
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    Connection: 'keep-alive'
  });
  res.flushHeaders();

  // Send the current value immediately
  res.write(`data: ${JSON.stringify({ value })}\n\n`);

  clients.push(res);

  req.on('close', () => {
    const idx = clients.indexOf(res);
    if (idx !== -1) clients.splice(idx, 1);
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(\`Server listening on http://localhost:\${PORT}\`);
});
```

