const express = require('express');
const http = require('http');
const WebSocket = require('ws');
const fs = require('fs');
const path = require('path');

const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'count.json');

function loadCount() {
  try {
    if (fs.existsSync(DATA_FILE)) {
      const raw = fs.readFileSync(DATA_FILE, 'utf8');
      const obj = JSON.parse(raw);
      if (typeof obj.count === 'number') return obj.count;
    }
  } catch (e) {
    console.error('Failed to load count:', e);
  }
  return 0;
}

function saveCount(n) {
  // synchronous write for simplicity/atomicity
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify({ count: n }), 'utf8');
  } catch (e) {
    console.error('Failed to save count:', e);
  }
}

let count = loadCount();
saveCount(count); // ensure file exists

const app = express();
app.use(express.static(path.join(__dirname, 'public')));

const server = http.createServer(app);
const wss = new WebSocket.Server({ server, path: '/ws' });

function broadcastCount() {
  const msg = JSON.stringify({ type: 'count', count });
  wss.clients.forEach((client) => {
    if (client.readyState === WebSocket.OPEN) client.send(msg);
  });
}

wss.on('connection', (ws) => {
  // send current count on connect
  ws.send(JSON.stringify({ type: 'count', count }));

  ws.on('message', (data) => {
    try {
      const msg = JSON.parse(data.toString());
      if (msg && msg.action === 'inc') {
        count++;
        saveCount(count);
        broadcastCount();
      } else if (msg && msg.action === 'dec') {
        count--;
        saveCount(count);
        broadcastCount();
      }
    } catch (e) {
      console.error('Invalid WS message', e);
    }
  });
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});
```

