        statusEl.textContent = 'Disconnected — retrying...';
        setTimeout(() => {
          reconnectTimer = Math.min(reconnectTimer * 1.5, 10000);
          connect();
        }, reconnectTimer);
      });

      ws.addEventListener('error', () => {
        ws.close();
      });
