const express = require('express');
const fs = require('fs').promises;
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;
const DATA_FILE = path.join(__dirname, 'count.json');

app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

let clients = [];

// Ensure data file exists
async function ensureDataFile() {
  try {
    await fs.access(DATA_FILE);
  } catch (err) {
    await fs.writeFile(DATA_FILE, JSON.stringify({ count: 0 }), 'utf8');
  }
}

async function readCount() {
  try {
    const raw = await fs.readFile(DATA_FILE, 'utf8');
    const obj = JSON.parse(raw);
    return typeof obj.count === 'number' ? obj.count : 0;
  } catch (err) {
    return 0;
  }
}

async function writeCount(n) {
  await fs.writeFile(DATA_FILE, JSON.stringify({ count: n }), 'utf8');
  broadcast(n);
}

// Broadcast to SSE clients
function broadcast(n) {
  const data = `data: ${n}\n\n`;
  clients.forEach((res) => {
    try {
      res.write(data);
    } catch (err) {
      // ignore; will be cleaned on close
    }
  });
}

// Simple async queue to serialize updates and avoid races
let updatePromise = Promise.resolve();
function updateCount(delta) {
  updatePromise = updatePromise.then(async () => {
    const cur = await readCount();
    const next = cur + delta;
    await writeCount(next);
    return next;
  }).catch((err) => {
    console.error('Update error', err);
  });
  return updatePromise;
}

// API endpoints
app.get('/count', async (req, res) => {
  const c = await readCount();
  res.json({ count: c });
});

app.post('/inc', async (req, res) => {
  const newCount = await updateCount(+1);
  res.json({ count: newCount });
});

app.post('/dec', async (req, res) => {
  const newCount = await updateCount(-1);
  res.json({ count: newCount });
});

// SSE endpoint for real-time updates
app.get('/events', async (req, res) => {
  res.set({
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    Connection: 'keep-alive',
  });
  res.flushHeaders();

  // Send current count immediately
  const current = await readCount();
  res.write(`data: ${current}\n\n`);

  // Add to clients
  clients.push(res);

  // Remove on close
  req.on('close', () => {
    clients = clients.filter((r) => r !== res);
  });
});

(async () => {
  await ensureDataFile();
  app.listen(PORT, () => {
    console.log(`Server listening on http://localhost:${PORT}`);
  });
})();
