Here's a single-file Node.js web app (server + client) that shows a shared, persistent counter; clicking + or − updates the counter on the server and broadcasts the new value to all connected clients in real time (via Server-Sent Events). Save as server.js and follow the run instructions below.

```js
// server.js
//
// Requires Node.js and the "express" package.
// Run: npm init -y && npm install express
// Start: node server.js
//
// Then open http://localhost:3000 in multiple browser windows.

const express = require('express');
const fs = require('fs');
const path = require('path');

const COUNTER_FILE = path.join(__dirname, 'counter.json');
const PORT = process.env.PORT || 3000;

const app = express();
app.use(express.json());

// Load or initialize counter
let counter = 0;
try {
  const data = fs.readFileSync(COUNTER_FILE, 'utf8');
  counter = JSON.parse(data).value ?? 0;
} catch (err) {
  // file missing or invalid -> create it
  counter = 0;
  fs.writeFileSync(COUNTER_FILE, JSON.stringify({ value: counter }), 'utf8');
}

// Simple in-memory list of SSE clients
const clients = new Set();

// Helper: persist counter to file
function saveCounter() {
  fs.writeFileSync(COUNTER_FILE, JSON.stringify({ value: counter }), 'utf8');
}

// Helper: broadcast to SSE clients
function broadcastCounter() {
  const payload = `data: ${JSON.stringify({ value: counter })}\n\n`;
  for (const res of clients) {
    try {
      res.write(payload);
    } catch (err) {
      // ignore write errors; client cleanup happens on close
    }
  }
}

// Serve single-page app
app.get('/', (req, res) => {
  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.send(`<!doctype html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>Shared Counter</title>
    <style>
      body { font-family: Arial, sans-serif; display:flex; align-items:center; justify-content:center; height:100vh; margin:0; }
      .card { text-align:center; padding:20px; border:1px solid #ddd; border-radius:8px; box-shadow:0 2px 6px rgba(0,0,0,0.08); }
      #value { font-size:48px; margin: 10px 0; }
      button { font-size:20px; padding:8px 14px; margin:0 6px; cursor:pointer; }
    </style>
  </head>
  <body>
    <div class="card">
      <div id="value">…</div>
      <div>
        <button id="dec">−</button>
        <button id="inc">+</button>
      </div>
    </div>
    <script>
      const valueEl = document.getElementById('value');
      const incBtn = document.getElementById('inc');
      const decBtn = document.getElementById('dec');

      // Fetch current value once
      async function fetchValue() {
        try {
          const r = await fetch('/value');
          const json = await r.json();
          updateDisplay(json.value);
        } catch (err) {
          console.error('Failed to fetch value', err);
          valueEl.textContent = 'Error';
        }
      }

      function updateDisplay(v) {
        valueEl.textContent = v;
      }

      // Send update to server
      async function sendDelta(delta) {
        try {
          // send request; server will broadcast new value via SSE
          await fetch('/update', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ delta })
          });
        } catch (err) {
          console.error('Failed to send update', err);
        }
      }

      incBtn.addEventListener('click', () => sendDelta(1));
      decBtn.addEventListener('click', () => sendDelta(-1));

      // SSE to receive live updates
      const ev = new EventSource('/stream');
      ev.onmessage = (e) => {
        try {
          const json = JSON.parse(e.data);
          updateDisplay(json.value);
        } catch (err) {
          console.error('Invalid SSE data', e.data, err);
        }
      };
      ev.onerror = (err) => {
        // show fallback if needed
        console.error('SSE error', err);
      };

      // initial fetch
      fetchValue();
    </script>
  </body>
</html>`);
});

// REST endpoint to get current value
app.get('/value', (req, res) => {
  res.json({ value: counter });
});

// POST to update by delta: { delta: 1 } or -1 etc.
app.post('/update', (req, res) => {
  const delta = Number(req.body.delta);
  if (!Number.isFinite(delta)) {
    return res.status(400).json({ error: 'Invalid delta' });
  }

  // Update in-memory and persist synchronously (simple and safe in single-process app)
  counter += delta;
  saveCounter();

  // Broadcast to SSE clients
  broadcastCounter();

  res.json({ value: counter });
});

// SSE stream endpoint
app.get('/stream', (req, res) => {
  // Set headers for SSE
  res.set({
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    Connection: 'keep-alive',
  });
  res.flushHeaders();

  // Send initial value
  res.write(`data: ${JSON.stringify({ value: counter })}\n\n`);

  // Add to clients
  clients.add(res);

  // Remove when client disconnects
  req.on('close', () => {
    clients.delete(res);
  });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running at http://localhost:${PORT}/`);
});
