      socket.on('history', (msgs) => {
        messagesEl.innerHTML = '';
        msgs.forEach(addMessage);
      });

      socket.on('message', (msg) => {
        addMessage(msg);
      });

      form.addEventListener('submit', function(e) {
        e.preventDefault();
        const text = input.value.trim();
        if (!text) return;
        socket.emit('message', text);
        input.value = '';
        input.focus();
      });

      // Send "typing" indicator (optional minimal)
      let typing = false;
      input.addEventListener('input', () => {
        if (!typing) {
          typing = true;
          socket.emit('typing', true);
          setTimeout(() => { typing = false; socket.emit('typing', false); }, 1000);
        }
      });

      // Show basic typing indicator
      const info = document.querySelector('.info');
      socket.on('typing', (who) => {
        if (who) info.textContent = who + ' is typing...';
        else info.textContent = 'One shared room — open this page in multiple windows to chat live.';
      });

      // Announce connect/disconnect (optional)
      socket.on('connect', () => {
        socket.emit('announce', 'joined');
      });
    })();
  </script>
</body>
</html>`);
});

io.on('connection', (socket) => {
  // send history
  socket.emit('history', history);

  // broadcast typing events
  socket.on('typing', (isTyping) => {
    // use socket.id short to indicate who
    const who = isTyping ? socket.id.slice(0,6) : '';
    socket.broadcast.emit('typing', who);
  });

  socket.on('announce', (msg) => {
    // can be used for join/leave if desired
  });

  socket.on('message', (text) => {
    const item = { id: socket.id, t: Date.now(), text: String(text).slice(0,1000) };
    history.push(item);
    if (history.length > MAX_HISTORY) history.shift();
    io.emit('message', item); // broadcast to all (including sender)
  });

  socket.on('disconnect', () => {
    // notify others that this user left (clear typing)
    socket.broadcast.emit('typing', '');
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log('Chat server running on http://localhost:' + PORT);
});
