Here's a minimal real-time single-room chat app using Node.js and WebSockets. Two files: server.js and index.html.

server.js
```js
// server.js
// Run: npm install ws
// Then: node server.js
const http = require('http');
const fs = require('fs');
const path = require('path');
const WebSocket = require('ws');

const indexHtml = fs.readFileSync(path.join(__dirname, 'index.html'), 'utf8');

const server = http.createServer((req, res) => {
  if (req.method === 'GET' && (req.url === '/' || req.url === '/index.html')) {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(indexHtml);
    return;
  }
  res.writeHead(404);
  res.end();
});

const wss = new WebSocket.Server({ server });

wss.on('connection', (ws) => {
  // Optionally send current time or welcome
  ws.send(JSON.stringify({ type: 'info', text: 'Welcome to the chat' }));

  ws.on('message', (msg) => {
    // Expect client to send JSON: {type:'message', id, name, text}
    let data;
    try {
      data = JSON.parse(msg);
    } catch (e) {
      return;
    }
    if (data && data.type === 'message' && typeof data.text === 'string') {
      // Add server timestamp and broadcast to all connected clients
      const out = {
        type: 'message',
        id: data.id || null,
        name: data.name || 'Anon',
        text: data.text,
        ts: Date.now()
      };
      const outStr = JSON.stringify(out);
      wss.clients.forEach((client) => {
        if (client.readyState === WebSocket.OPEN) client.send(outStr);
      });
    }
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Server running at http://localhost:${PORT}/`);
});
```

