    input[type="text"]{flex:1;padding:8px;border:1px solid #ccc;border-radius:6px}
    button{padding:8px 12px;border-radius:6px}
    .status{font-size:12px;color:#333;margin-bottom:6px}
    .nameBadge{display:inline-block;padding:4px 6px;border-radius:6px;color:#fff;font-weight:600;font-size:12px}
  </style>
</head>
<body>
  <div class="wrap">
    <div class="status">Status: <span id="status">connecting...</span></div>
    <div id="messages" aria-live="polite"></div>
    <div class="inputRow">
      <input id="text" type="text" placeholder="Type a message and press Enter" autocomplete="off"/>
      <button id="send">Send</button>
    </div>
  </div>

<script>
(function(){
  const messagesEl = document.getElementById('messages');
  const textEl = document.getElementById('text');
  const sendBtn = document.getElementById('send');
  const statusEl = document.getElementById('status');

  // Create persistent random id + name in localStorage
  let myId = localStorage.getItem('chat:id');
  if (!myId) {
    myId = Math.random().toString(36).slice(2,9);
    localStorage.setItem('chat:id', myId);
  }
  let myName = localStorage.getItem('chat:name');
  if (!myName) {
    myName = 'User-' + myId.slice(0,4);
    localStorage.setItem('chat:name', myName);
  }

  // Color generator based on id
  function colorFor(id){
    let h = 0;
    for (let i=0;i<id.length;i++) h = (h*31 + id.charCodeAt(i)) % 360;
    return 'hsl(' + h + 'deg 60% 40%)';
  }

  function appendMessage(obj){
    const wrap = document.createElement('div');
    wrap.className = 'msg';
    const badge = document.createElement('div');
    badge.className = 'nameBadge';
    badge.textContent = obj.name || 'Anon';
    badge.style.background = colorFor(obj.id || 'anon');
    const meta = document.createElement('div');
    meta.className = 'meta';
    const time = new Date(obj.ts || Date.now());
    meta.textContent = time.toLocaleTimeString();
    const bubble = document.createElement('div');
    bubble.className = 'bubble';
    bubble.textContent = obj.text;
    const left = document.createElement('div');
    left.style.display = 'flex';
    left.style.flexDirection = 'column';
    left.appendChild(badge);
    left.appendChild(meta);
    wrap.appendChild(left);
    wrap.appendChild(bubble);
    messagesEl.appendChild(wrap);
    messagesEl.scrollTop = messagesEl.scrollHeight;
  }

  const protocol = (location.protocol === 'https:') ? 'wss:' : 'ws:';
  const wsUrl = protocol + '//' + location.host;
  const ws = new WebSocket(wsUrl);

  ws.addEventListener('open', () => {
    statusEl.textContent = 'connected';
    statusEl.style.color = 'green';
  });
  ws.addEventListener('close', () => {
    statusEl.textContent = 'disconnected';
    statusEl.style.color = 'red';
  });
  ws.addEventListener('error', () => {
    statusEl.textContent = 'error';
    statusEl.style.color = 'orange';
  });

  ws.addEventListener('message', (ev) => {
    let data;
    try { data = JSON.parse(ev.data); } catch(e){ return; }
    if (data.type === 'message') {
      appendMessage(data);
    } else if (data.type === 'info') {
      appendMessage({ name: 'System', id: 'system', text: data.text, ts: data.ts || Date.now() });
    }
  });

  function sendMessage(){
    const text = textEl.value.trim();
    if (!text) return;
    const payload = { type: 'message', id: myId, name: myName, text: text };
    ws.send(JSON.stringify(payload));
    textEl.value = '';
  }

  sendBtn.addEventListener('click', sendMessage);
  textEl.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') sendMessage();
  });
})();
</script>
</body>
</html>
```

Usage:
- Put both files in the same directory.
- Install dependency: npm install ws
- Start server: node server.js
- Open http://localhost:3000/ in multiple browser windows/tabs (or different devices on your network) and chat; messages appear instantly to everyone.

This is intentionally minimal: single shared room, no authentication, messages broadcast to all connected clients. Feel free to ask if you want message history, persistent storage, usernames, rooms, or styling improvements.

