    const sample = `# Live Markdown Preview

Type Markdown on the left and see it rendered on the right — updates as you type.

- Supports GitHub Flavored Markdown
- Sanitized output (DOMPurify) to prevent XSS

## Examples

\`\`\`js
// Code blocks render nicely
console.log('Hello, world!');
\`\`\`

> Blockquotes
`;

    input.value = sample;

    function render() {
      const md = input.value;
      charCount.textContent = md.length + ' chars';
      // convert markdown to HTML
      let html = marked.parse(md);
      // sanitize HTML
      html = DOMPurify.sanitize(html, {ADD_ATTR: ['target']});
      // wrap with markdown-body for the CSS styles
      preview.innerHTML = '<article class="markdown-body">' + html + '</article>';
    }

    // Live update
    input.addEventListener('input', render);

    // Buttons
    clearBtn.addEventListener('click', () => {
      input.value = '';
      input.focus();
      render();
    });

    selectAllBtn.addEventListener('click', () => {
      input.focus();
      input.select();
    });

    copyHtmlBtn.addEventListener('click', async () => {
      const html = preview.innerHTML;
      try {
        await navigator.clipboard.writeText(html);
        copyHtmlBtn.textContent = 'Copied!';
        setTimeout(()=> copyHtmlBtn.textContent = 'Copy HTML', 1200);
      } catch (e) {
        copyHtmlBtn.textContent = 'Copy failed';
        setTimeout(()=> copyHtmlBtn.textContent = 'Copy HTML', 1200);
      }
    });

    downloadBtn.addEventListener('click', () => {
      const html = '<!doctype html><meta charset="utf-8"><title>Export</title>' + preview.innerHTML;
      const blob = new Blob([html], {type: 'text/html'});
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'preview.html';
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    });

    // Initial render
    render();
  </script>
</body>
</html>
