    // Configure marked (Markdown parser)
    marked.setOptions({
      gfm: true,
      breaks: true,
      headerIds: true,
      mangle: false,
      // use highlight.js for code blocks if available
      highlight: function(code, lang) {
        if (window.hljs) {
          try {
            if (lang && hljs.getLanguage(lang)) {
              return hljs.highlight(code, { language: lang }).value;
            } else {
              return hljs.highlightAuto(code).value;
            }
          } catch (e) {
            return code;
          }
        }
        return code;
      }
    });

    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');

    // Sample content
    const defaultMarkdown = `# Welcome

Paste or type Markdown on the left. The preview updates live.

## Features

- Live preview as you type
- Sanitized HTML with DOMPurify (prevents XSS)
- Code block syntax highlighting

\`\`\`js
// Example JavaScript code
function greet(name) {
  console.log(\`Hello, \${name}!\`);
}
greet('world');
\`\`\`

[Visit Marked on GitHub](https://github.com/markedjs/marked)
`;

    editor.value = defaultMarkdown;

    function updatePreview() {
      const md = editor.value;
      // Convert markdown to HTML
      const rawHtml = marked.parse(md);
      // Sanitize output to prevent XSS
      const safe = DOMPurify.sanitize(rawHtml, { USE_PROFILES: { html: true } });
      preview.innerHTML = safe;
      // Highlight code blocks (if hljs loaded)
      if (window.hljs && typeof hljs.highlightAll === 'function') {
        hljs.highlightAll();
      }
    }

    // Update as the user types
    editor.addEventListener('input', updatePreview);

    // Initial render
    updatePreview();

    // Optional: keyboard shortcut Ctrl/Cmd+Enter to focus preview (toggle)
    document.addEventListener('keydown', (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
        preview.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    });
  </script>
</body>
</html>
```

Usage: Save the code to a file like preview.html and open it in your browser. Paste or type Markdown into the left pane — the right pane shows the live rendered HTML (sanitized and with syntax highlighting).

Here's a single-file Flask app that implements a simple URL shortener (stores mappings in SQLite, encodes IDs in base62). Save as app.py, install Flask, and run.

```python
#!/usr/bin/env python3
"""
Simple URL shortener web app using Flask + SQLite.
Save as app.py, install dependencies: pip install Flask
Run: python app.py
"""

from flask import Flask, request, redirect, render_template_string, g, url_for, abort
import sqlite3
from urllib.parse import urlparse
from datetime import datetime

DATABASE = "urls.db"
BASE62_ALPHABET = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"

app = Flask(__name__)


# --- Database helpers ---
def get_db():
    db = getattr(g, "_database", None)
    if db is None:
        db = g._database = sqlite3.connect(DATABASE)
        db.row_factory = sqlite3.Row
    return db


def init_db():
    db = get_db()
    db.execute(
        """
        CREATE TABLE IF NOT EXISTS urls (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            long_url TEXT NOT NULL UNIQUE,
            created_at TEXT NOT NULL,
            hits INTEGER NOT NULL DEFAULT 0
        )
        """
    )
    db.commit()


@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, "_database", None)
    if db is not None:
        db.close()


# --- Base62 encoding/decoding ---
def encode_base62(num: int) -> str:
    if num == 0:
        return BASE62_ALPHABET[0]
    arr = []
    base = len(BASE62_ALPHABET)
    while num:
        num, rem = divmod(num, base)
        arr.append(BASE62_ALPHABET[rem])
    arr.reverse()
    return "".join(arr)


def decode_base62(s: str) -> int:
    base = len(BASE62_ALPHABET)
    num = 0
    for char in s:
        try:
            val = BASE62_ALPHABET.index(char)
        except ValueError:
            raise ValueError("Invalid character for base62")
        num = num * base + val
    return num


# --- URL helpers ---
def normalize_url(url: str) -> str:
    url = url.strip()
    if not url:
        return ""
    parsed = urlparse(url)
    if parsed.scheme == "":
        # default to http if no scheme provided
        url = "http://" + url
    return url


# --- Routes ---
INDEX_HTML = """
<!doctype html>
<title>Simple URL Shortener</title>
<style>
body { font-family: Arial, sans-serif; max-width: 700px; margin: 40px auto; }
input[type=text] { width: 80%; padding: 8px; font-size: 14px; }
input[type=submit] { padding: 8px 12px; font-size: 14px; }
.short { margin-top: 16px; padding: 10px; background: #f3f3f3; }
a.shortlink { font-weight: bold; color: #1a73e8; text-decoration: none; }
small { color: #666; }
</style>
<h1>Simple URL Shortener</h1>
<form method="post" action="{{ url_for('create_short') }}">
  <input type="text" name="long_url" placeholder="Paste a long URL here" required>
  <input type="submit" value="Shorten">
</form>

{% if short_url %}
<div class="short">
  Short link: <a class="shortlink" href="{{ short_url }}" target="_blank">{{ short_url }}</a><br>
  Original: <small>{{ long_url }}</small>
</div>
{% endif %}

{% if error %}
<div style="color: #b00020; margin-top: 12px;">{{ error }}</div>
{% endif %}

<hr>
<p>To use: paste a URL and click Shorten. Visiting the short link will redirect to the original URL.</p>
"""

@app.route("/", methods=["GET"])
def index():
    init_db()
    return render_template_string(INDEX_HTML)


@app.route("/", methods=["POST"])
def create_short():
    init_db()
    long_url = request.form.get("long_url", "")
    long_url = normalize_url(long_url)
    if not long_url:
        return render_template_string(INDEX_HTML, error="Please provide a valid URL.")
    db = get_db()
    created_at = datetime.utcnow().isoformat()
    # Try inserting; if URL already exists, we'll retrieve its id
    cur = db.execute(
        "INSERT OR IGNORE INTO urls (long_url, created_at) VALUES (?, ?)",
        (long_url, created_at),
    )
    db.commit()
    if cur.lastrowid:
        url_id = cur.lastrowid
    else:
        # URL already existed: fetch its id
        row = db.execute("SELECT id FROM urls WHERE long_url = ?", (long_url,)).fetchone()
        url_id = row["id"]
    code = encode_base62(url_id)
    short_url = request.host_url.rstrip("/") + "/" + code
    return render_template_string(INDEX_HTML, short_url=short_url, long_url=long_url)


@app.route("/<code>")
def redirect_short(code):
    init_db()
    try:
        url_id = decode_base62(code)
    except ValueError:
        abort(404)
    db = get_db()
    row = db.execute("SELECT long_url FROM urls WHERE id = ?", (url_id,)).fetchone()
    if not row:
        abort(404)
    long_url = row["long_url"]
    # increment hit count (best-effort)
    db.execute("UPDATE urls SET hits = hits + 1 WHERE id = ?", (url_id,))
    db.commit()
    return redirect(long_url, code=302)


# Optional: simple JSON API endpoint to create short URL (useful for curl)
@app.route("/api/shorten", methods=["POST"])
def api_shorten():
    init_db()
    data = request.get_json() or {}
    long_url = data.get("url") or ""
    long_url = normalize_url(long_url)
    if not long_url:
        return {"error": "Invalid URL"}, 400
    db = get_db()
    created_at = datetime.utcnow().isoformat()
    cur = db.execute(
        "INSERT OR IGNORE INTO urls (long_url, created_at) VALUES (?, ?)",
        (long_url, created_at),
    )
    db.commit()
    if cur.lastrowid:
        url_id = cur.lastrowid
    else:
        row = db.execute("SELECT id FROM urls WHERE long_url = ?", (long_url,)).fetchone()
        url_id = row["id"]
    code = encode_base62(url_id)
    short_url = request.host_url.rstrip("/") + "/" + code
    return {"short_url": short_url, "long_url": long_url}


if __name__ == "__main__":
    # create DB on first run
    with app.app_context():
        init_db()
    app.run(debug=True, host="0.0.0.0", port=5000)
```

Usage note:
- Install Flask: pip install Flask
- Run: python app.py
- Open http://localhost:5000 in your browser, paste a URL and click Shorten. Visiting the returned short link will redirect to the original URL. The data is stored in urls.db in the same directory.
